(3, 'Công việc & Hoạt động hàng ngày', '発見', 'はっけん', 'Phát hiện', '新しい星が発見された。', 'N3', '2026-04-07 02:42:11'),
(4, 'Công việc & Hoạt động hàng ngày', '残業', 'ざんぎょう', 'Làm thêm giờ', '仕事が多くて、毎日残業している。', 'N3', '2026-04-07 02:42:11'),
(5, 'Công việc & Hoạt động hàng ngày', '面接', 'めんせつ', 'Phỏng vấn', '明日はアルバイトの面接がある。', 'N3', '2026-04-07 02:42:11'),
(6, 'Tính chất & Trạng thái', '得意', 'とくい', 'Giỏi, sở trường', '彼はダンスが得意だ。', 'N3', '2026-04-07 02:42:11'),
(7, 'Tính chất & Trạng thái', '正常', 'せいじょう', 'Bình thường', '機械は正常に動いている。', 'N3', '2026-04-07 02:42:11'),
(8, 'Tính chất & Trạng thái', '上品', 'じょうひん', 'Sang trọng, lịch sự', '上品な服を着ている。', 'N3', '2026-04-07 02:42:11'),
(9, 'Tính chất & Trạng thái', 'きつい', 'きつい', 'Vất vả, chặt, nghiêm khắc', 'この仕事はきつい。', 'N3', '2026-04-07 02:42:11'),
(10, 'Tính chất & Trạng thái', '丁寧', 'ていねい', 'Lịch sự, cẩn thận', '丁寧な言葉を使ってください。', 'N3', '2026-04-07 02:42:11'),
(11, 'Tính chất & Trạng thái', '積極적', 'せっきょくてき', 'Tích cực', '授業に積極的に参加する。', 'N3', '2026-04-07 02:42:11'),
(12, 'Cảm xúc & Hành động', '感じ', 'かんじ', 'Cảm giác', 'いい感じがする。', 'N3', '2026-04-07 02:42:11'),
(13, 'Cảm xúc & Hành động', '落ち着く', 'おちつく', 'Bình tĩnh', '落ち着いて行動してください。', 'N3', '2026-04-07 02:42:11'),
(14, 'Giao thông & Di chuyển', '渋滞', 'じゅうたい', 'Tắc đường', '事故で道路が渋滞している。', 'N3', '2026-04-07 02:42:11'),
(15, 'Giao thông & Di chuyển', '到着', 'とうちゃく', 'Đến nơi', '飛行機が定刻に到着した。', 'N3', '2026-04-07 02:42:11'),
(16, 'Giao thông & Di chuyển', '乗車', 'じょうしゃ', 'Lên xe', '駆け込み乗車は危ないです。', 'N3', '2026-04-07 02:42:11'),
(17, 'Sức khỏe & Y tế', '回復', 'かいふく', 'Hồi phục', '父の病気が早く回復してほしい。', 'N3', '2026-04-07 02:42:11'),
(18, 'Sức khỏe & Y tế', '栄養', 'えいよう', 'Dinh dưỡng', 'バランスのいい栄養をとる。', 'N3', '2026-04-07 02:42:11'),
(19, 'Sức khỏe & Y tế', '診察', 'しんさつ', 'Khám bệnh', '病院で先生の診察を受ける。', 'N3', '2026-04-07 02:42:11'),
(20, 'Giáo dục & Học tập', '暗記', 'あんき', 'Học thuộc lòng', '新しい単語を暗記する。', 'N3', '2026-04-07 02:42:11'),
(21, 'Giáo dục & Học tập', '参考', 'さんこう', 'Tham khảo', 'この本を参考にレポートを書く。', 'N3', '2026-04-07 02:42:11'),
(22, 'Giáo dục & Học tập', '欠席', 'けっせき', 'Vắng mặt', '風邪で授業を欠席した。', 'N3', '2026-04-07 02:42:11');
INSERT INTO `grammar_lessons` (`id`, `structure_name`, `meaning`, `usage_rules`, `examples`, `level`, `created_at`) VALUES
(1, '~あげく(に)', 'Use this when you want to say how something turned out after a tough experience that took a lot of time or involved various efforts. It is often used to say that the result is not good.', '[動-た形・名-の]＋あげく(に)', '[\"さっきにお客さん、あれこれ試着した<b>あげくに<\\/b>、何も買わずに帰っちゃって・・・。\",\"長い時間がかかったり、いろいろしたりして大変だった後で、どうなったかという結果を言いたい時に使う。よくない結果になったことを言うことが多い。\",\"In the end; finally; on top of all that; to make matters worse.\",\"<img src=\\\"Fitting-room-etiquette.jpg\\\" \\/>\",\"さんさん迷った<b>あげく<\\/b>、大学院には行かないことにした。\",\"45\"]', '', '2026-04-02 15:33:28'),
(2, '~あまり', 'When you want to say that someone \"did ・・・ an extreme amount, which resulted in ~\". It is often used when the result is not good.', '[動-辞書形・た形 / な形-な / 名-の]＋あまり', '[\"子どもの将来を思う<b>あまり<\\/b>、厳しすぎることを言ってしまった。\",\"「非常に～で（・・・の結果になった）と言いたい時に使う。よくない結果の時に使うことが多い。\",\"Do ~ so much as to ~\",\"<img src=\\\"think-1034159_960_720.jpg\\\" \\/>\",\"弟の病気を心配するあまり母は食欲がなくなり、すっかり痩せてしまった。\",\"128\"]', '', '2026-04-02 15:33:28'),
(3, '~ 以上[いじょう](は)', 'When you want to say, with strong emotion, something like \"it\'s natural because ~ is decided / a fact; something should be done; you intend to do something; when you order someone to do something.\"', '[普通形]＋以上', '[\"日本に住んでいる<b>以上<\\/b>、日本の法律を守らなければならない。\",\"~からには、~上は\",\"often followed by obligations, prohibitions, demands, presumptions, and strong conclusions such as [なければならない \\/　てはいけない　\\/ てください　 \\/ だろう]\",\"「～からには」と同じ意味がある。2\",\"[な形 \\/ 名] use [である]\",\"Since\",\"<img src=\\\"paste-24962349924353.jpg\\\" \\/>\",\"プロジェクトのリーダーを引き受けた以上、全力を尽くします。\",\"18.2\"]', '', '2026-04-02 15:33:28'),
(4, '~ 一方[いっぽう] / ~ 一方[いっぽう]では', 'Use this when you explain that one thing can be in very different situations, as in \"行列ができる店がある一方、まったく客が入らない店もある\".', '[名詞修飾型]＋一方<div>[な形 / 名]＋である＋一方</div>', '[\"仕事を求めて都会に出る若者がいる<b>一方<\\/b>、故郷に戻って就職する若者もいる。\",\"一つのことに関して、大きく違う状況があることを説明する時に使う。\",\"[な形 \\/ 名]場合は [である]も使われる。\",\"While; Meanwhile (shows a comparison between two things)\",\"<img src=\\\"Job-hunt-confidence-blog.jpg\\\" \\/>\",\"私の仕事は夏は非常に忙しい<b>一方<\\/b>、冬は暇になる。\",\"61\"]', '', '2026-04-02 15:33:28'),
(5, '~ 一方[いっぽう]だ', 'Use it when you want to say that \"situation ~ is going to continue\" as in \"景気が悪くなる一方だ\".', '[動-辞書形]＋一方だ', '[\"ここは静かな町だったのに、テレビで紹介されて以来、観光的が増える<b>一方だ。<\\/b>\",\"～ばかり\",\"Uses verbs that show \\/ express a change\",\"「～の状態がどんどん進んでいく」と言いたい時に使う。\",\"(no specific meaning) shows something continuing towards a certain tendency.　ex. more and more; less and less; keep on~; never stop~\",\"<img src=\\\"20180908-035557203.jpg\\\" \\/>\",\"最近、パソコン通信の利用者は増える<b>一方だ。<\\/b>\",\"115\"]', '', '2026-04-02 15:33:28'),
(6, '~うえ(に)', 'In addition to~', '[動・い形・な形・名]の名詞修飾型＋うえ', '[\"今年のインフルエンザは高熱が出る<b>うえ<\\/b>、せきもひどい。\"]', '', '2026-04-02 15:33:28'),
(7, '~上で(は) / ~上での / ~上でも / ~上の', 'Has the same meaning as \"～してから\" but don\'t use it to talk about a familiar topic.', '[動-た形 / 名-の]＋上で<div>[動-た形 / 名-の]＋上(で)の＋[名]</div>', '[\"駅前の再開発については、住民の皆さんの意見をまとめた<b>上で<\\/b>、市に要望書を提出したいと思います。\",\"「～してから」と同じ意味で使う。ただし、日常的な話題には使わない。\",\"After...ing ; Upon…ing\",\"<img src=\\\"paste-22806276341761.jpg\\\" \\/>\",\"みんなの意見を聞いた<b>上で<\\/b>決めました。\",\"117\"]', '', '2026-04-02 15:33:28'),
(9, '~上は', 'When you want to say, with strong emotion, something like \"it\'s natural because ~ is decided / a fact; something should be done; you intend to do something; when you order someone to do something.\"', '[動-辞書形・た形]＋上は', '[\"約束を結ぶ<b>上は<\\/b>、条件を慎重に検討すべきである。\",\"~ 以上、~からには\",\"「～からには」と同じ意味がある。1\",\"Now that~; Since~\",\"<img src=\\\"730aca369b236619be67b7115be5a576e0006663.jpg\\\" \\/>\",\"税金を使って研究を行う上は、社会に役立つ研究をしなければならない。\",\"18\"]', '', '2026-04-02 15:33:28'),
(10, '~(よ)うじゃないか / ~(よ)うではないか', 'Shall we~; Let\'s~', '[動-意向形]＋ではないか', '[\"災害を受けた人々に救援物資を送ろうではないか。\"]', '', '2026-04-02 15:33:28'),
(11, '~うちに / ~ないうちに', 'When you say that something should be done, you want to do something, or when you ask someone to do something, or the like, before a certain change occurs.', '[動-ない形-ない・て形-いる / い形-い / な形-な / 名-の]＋うちに', '[\"日本にいる<b>うちに<\\/b>、一度京都を訪ねたいと思っている。\",\"ある変化が起きる前に、何かをしたほうがいい・したい・してくださいなどと言う時に使う。\",\"While~ &lt; do something before the condition changes &gt;\",\"<img src=\\\"shutterstock_367163339.jpg\\\" \\/>\",\"アイスクリームが溶けないうちに食べよう。\",\"81\"]', '', '2026-04-02 15:33:28'),
(12, '~ 得[え]る;&nbsp;~ 得[う]る', 'When you say \"there is a possibility that I can ~\". This is often used in essays and the like.', '[動-ます形]＋得る', '[\"凶器がどこにあるか、考え<b>得る<\\/b>場所はすべて捜したが全く手がかりがつかめなかった。\",\"「～ができる・可能性がある」と言う時に使う。論文などでよく使う。\",\"Be possible to~\",\"<img src=\\\"315DC85D00000578-3454380-image-a-111_1455883339863.jpg\\\" \\/>\",\"考え得るかぎりの手は尽くしたが、問題の解決には至らなかった\",\"66\"]', '', '2026-04-02 15:33:28'),
(13, '~得ない', 'Use it to say \"I can\'t ~; there\'s no possibility\". This is often used in essays and the like.', '[動-ます形]＋得ない', '[\"普通の人が宇宙へ行ける日が来るなんて、100年前には想像し<b>得なかった<\\/b>ことだ。\",\"「～できない・可能性がない」と言う時に使う。論文などでよく使う。\",\"Be impossible to~\",\"<img src=\\\"nasa-space-station.jpg\\\" \\/>\",\"こんな低い山で遭難することはあり得ないと思う。\",\"66\"]', '', '2026-04-02 15:33:28'),
(14, '~おかげだ / ~おかげで', 'Thanks to~; Owing to~; Because of~　(express thanks to the result of a good outcome)', '[名詞修飾型]＋おかげで', '[\"科学技術が発達した<b>おかげで<\\/b>、我々の生活は便利になった。\",\"「～」が原因でいい結果になって、感謝や「よかった」という気持ちを言う時に使う\",\"おかげさまで: Thanks to you or some higher power\",\"<img src=\\\"paste-70334384439297.jpg\\\" \\/>\",\"<div><div><div>大雨のおかげで釣りに行けなかった。<\\/div><\\/div><div><div>あなたのおかげで私は幸せなのです。<\\/div><div><div>彼が成功したのは幸運のおかげである。<\\/div><\\/div><\\/div><\\/div><div><div>この奨学金のおかげで彼は留学できた。<\\/div><\\/div>\",\"51\"]', '', '2026-04-02 15:33:28'),
(15, '~おそれがある', 'When you say that there is a high lokehood that -based on objective data or the like- the situation will become dangerous or otherwise undesirable. It is often used in news shows, newspapers, reports and the like.', '[動-辞書形・ない形-ない / 名-の]＋おそれがある', '[\"噴火の<b>恐れがあります<\\/b>ので、避難してください。\",\"客観的なデータなどを基にして、危険な状態になる可能性が高いことを伝える時に使う。ニュースや新聞、報告書などに使われることが多い。\",\"Be in danger of~\",\"<img src=\\\"Volcano-eruption-817605.jpg\\\" \\/>\",\"早く手術しないと、手遅れになるおそれがある。\",\"34\"]', '', '2026-04-02 15:33:28'),
(16, '~かぎり(は) / ~かぎりでは / ないかぎり(は)', 'As long as~ ; As far as~　&lt;during a specific time&gt;', '[動-辞書形・い形-い・な形-な・名-の / である]＋かぎり', '[\"日本にいるかぎり、タンさんは私に連絡してくれるはずだ。\"]', '', '2026-04-02 15:33:28'),
(20, '~かけだ / ~かけの / ~かける', 'When you say that you have started something and are not finished with it yet.', '[動-ます形]＋かけだ', '[\"この仕事はやり<b>かけ<\\/b>ですから、そのままにしておいてください。\",\"Unfinished ; Half~ (ex. half eaten, half finished)&nbsp;\",\"何かをし始めて、まだ終わっていない状態だと言う時に使う。\",\"<img src=\\\"3bc5d84174ccaba22a75d7dec7c0c01c_t.jpeg\\\" \\/>\",\"弟の部屋のは作りかけのプラモデルがいくつもある。\",\"85\"]', '', '2026-04-02 15:33:28'),
(21, '~がたい', 'It means \"doing ~ is difficult; probably can\'t do ~\".', '[動-ます形]＋がたい', '[\"この条件では、鈴木商事からの合併の申し出は受け入れ<b>がたい。<\\/b>\",\"「～するのは難しい、なかなか～することができない」という意味で使う。\",\"「信じる・理解する・納得する・認める・得る・許す・忘れる」などの言葉と一緒に使われる。\",\"Can’t do~ ; Difficult to~\",\"<img src=\\\"paste-24464133718017.jpg\\\" \\/>\",\"彼女がそんなことをするとは、信じがたい。\",\"126\"]', '', '2026-04-02 15:33:28'),
(22, '~がちだ / ~がちの', 'When you want to say that someone \"often does / is ~\" as in \"忘れがち・病気がち\". There is also an ideomatic usage to express a state or appereance.', '[動-ます形 / 名]＋がち', '[\"日本人は自分の意思をはっきり言わないので誤解され<b>がち<\\/b>だ。\",\"Used mostly with a negative meaning\",\"「～になることが多い」と言いたいときに使う。状態、様子を表す慣用的な言い方もある。\",\"「休む・思う・考える・心配する・留守」などの言葉と一緒に使われる。\",\"Tend to~\",\"<img src=\\\"misunderstanding-1.jpg\\\" \\/>\",\"雪が降ると、電車が遅れがちだ。\",\"111\"]', '', '2026-04-02 15:33:28'),
(23, '~かと思うと / ~かと思ったら', 'Use this when you emphasize that a situation has suddenly changed. Do not use it to explain about yourself.', '[動-た形]＋かと思うと・かと思ったら', '[\"青空を飛んでいた鳥は突然海に潜った<b>かと思うと<\\/b>、魚を口にくわえて出てきた。\",\"状況が急に変わったことを強調して説明するときに使う。自分のことを説明するときには使わない。\",\"As soon as~\",\"<img src=\\\"8 (1).jpg\\\" \\/>\",\"リ-さんは「さようなら」と言ったかと思うと教室を飛び出していった。\",\"99\"]', '', '2026-04-02 15:33:28'),
(24, '~か~ないかのうちに', 'When you want to say \"during the short time in which the action ~ is not completly finished\".', '[動-辞書形 / た形]＋か＋[動-ない形]＋ないかのうちに', '[\"早食い選手権を見ていたら、選手たちは食べ物を口に入れた<b>か<\\/b>入れ<b>ないかのうちに<\\/b>、次の料理に手を伸ばしていた。\",\"「～の動作が完全に完了しないくらい短い時間の間に」と言いたい時に使う。\",\"同じ動詞を使う。\",\"No sooner than~\",\"<img src=\\\"paste-38633230827521.jpg\\\" \\/>\",\"ヘビ-スモ-カ-の彼は、タバコを一本吸い終わったか終わらないかのうちに、次のタバコに火をつけた。\",\"96\"]', '', '2026-04-02 15:33:28'),
(25, '<div>~かねない</div>', 'When you want to say that \"judging from the current situation, a bad result is expected\". It often includes a judgament based on an objective view.', '[動-ます形]＋かねない', '[\"あんなスピードを出したら、事故を起こし<b>かねない<\\/b>。\",\"「今の状況から判断すると、悪い結果が予想される」と言いたい時に使う。客観的に見るとという判断が入っていることが多い。\",\"Be capable of~ ; Be in danger of~ (Used when there is a chance of something bad happening)\",\"<img src=\\\"ford_2035210c.jpg\\\" \\/>\",\"今のような経営方法では、2、3年のうちに倒産しかねない。\",\"27\"]', '', '2026-04-02 15:33:28'),
(26, '~かねる', 'Be hard to~ ; Be difficult to~', '[動-ます形]＋かねる', '[\"そんな多額な寄付には応じかねます。\"]', '', '2026-04-02 15:33:28'),
(27, '<div>~かのようだ / ~かのような / ~かのように</div>', 'When you say that it seems like something that is not actually true.', '[普通形]＋かのようだ<div>[な形 / 名]＋である＋かのようだ</div>', '[\"激しい雨と風は、まるで台風が来た<b>かのようだ。<\\/b>\",\"実際はそうではないのにそのように感じると言う時に使う。\",\"[な形 \\/ 名] can use [である]\",\"Like~\",\"<img src=\\\"rain-room-at-moma-10-1-680x365.jpg\\\" \\/>\",\"リンさんの部屋はまるで泥棒が入ったかのように散らかっている。\",\"80\"]', '', '2026-04-02 15:33:28'),
(28, '<div>~からして &nbsp;</div>', '1. Even~<div>2.&nbsp;Judging from~</div>', '[名]＋からして', '[\"1.&nbsp;彼は礼儀を知らない。あいさつからして、きちんとしていない。<div>2.&nbsp;窓ガラスが破られていることからして、泥棒はここから入ったに違いない。<\\/div>\"]', '', '2026-04-02 15:33:28'),
(29, '<div>~からすると / ~からすれば</div>', 'For~', '[名]＋からすると', '[\"親からすると、子供はいくつになっても子供で、心配なものだ。\",\"「~からして」のＢの意味。\"]', '', '2026-04-02 15:33:28'),
(30, '~からといって', 'When you say that just because of \"~\", doing \"・・・\" is not good, not doable, will cause problem, or the like. This expression is often used when giving criticism, advice, warning, etc.', '[普通形]＋からといって', '[\"お金がある<b>からといって<\\/b>偉いわけではない。\",\"～だからといって\",\"Often the sentence will be negative.\",\"「～」だけの理由で、「・・・」をするのはよくない、できない、すると困ったことになるなどと言う時に使う。批判、助言、意見などを言う時に使うことが多い。\",\"Just because~&nbsp;\",\"<img src=\\\"sad-rich-man.jpg\\\" \\/>\",\"買い物は計画的に。安いからと言って、買い過ぎないようにしましょう。\",\"92\"]', '', '2026-04-02 15:33:28'),
(31, '~から~にかけて', 'When you say that something is within a broad period of time or area between A and B as in \"今週から来週にかけて雨の日が多い\" and \"渋谷から新宿にかけてたくさんの専門学校がある\".', '[名]＋から＋[名]＋にかけて', '[\"本日、九州<b>から<\\/b>四国地方<b>にかけて<\\/b>、梅雨入りしました。\",\"AからBまでの間という意味で、時間や場所のだいたいの範囲を言う時に使う。\",\"From~to~\",\"<img src=\\\"20110822000301.jpg\\\" \\/>\",\"昨夜から今朝にかけて雨が降りました。\",\"32\"]', '', '2026-04-02 15:33:28'),
(32, '~からには / ~からは&nbsp;', 'When you want to say, with strong emotion, something like \"it\'s natural because ~ is decided / a fact; something should be done; you intend to do something; when you order someone to do something.\"', '[普通形・な形/名+である]＋からには・というからには', '[\"試合に出る<b>からには<\\/b>、勝ちたい。\",\"~ 以上、~上は\",\"followed by obligations, resolutions, presumptions, suggestions, and commands\",\"「～は決めたこと・事実なのだから当然・・・するべきだ・するつもりだ・しろ」などの強い気持ちを言いたい時に使う。\",\"[な形 \\/ 名] use [である]\",\"Now that~ ; Since~\",\"<img src=\\\"INDIAN_WOMEN_2715677f.jpg\\\" \\/>\",\"冬、山に登るからには、日頃からトレーニングを続ける必要がある。\",\"18.1\"]', '', '2026-04-02 15:33:28'),
(33, '~から見て(も) / ~から見ると / ~から見れば', 'When you state an idea based on a position, perspective or criterion of \"~\" as in \"専門家から見ると\", \"価格の面から見ると\" and \"データから見て\".', '[名]＋から見ると・から見れば・から見て<div>[名]＋からいうと・からいえば・からいって</div><div>[名]＋からすると・からすれば・からして</div>', '[\"便利さという点<b>から見ると<\\/b>、やはり田舎より都会のほうが暮らしやすい。\",\"「～からいうと」、「～からすると」\",\"「～」の立場、視点、判断材料から考えたことを言う時に使う。\",\"From the viewpoint of~;&nbsp;Judging from~ ; When it comes to~; As for~\",\"<img src=\\\"10593121.jpg\\\" \\/>\",\"子共の教育という点から見ると、豊かすぎる生活は、必ずしもいいとは言えない。<div>あの車は形からすると１０年ぐらい前のものだと思う。<\\/div><div>中国は人口からいうと世界一だが、人口密度は日本よりずっと低い。<\\/div>\",\"60\"]', '', '2026-04-02 15:33:28'),
(34, '<div>~かわりに</div>', 'When another person will do something, another object will be used, or another action will be taken. This expression is also often used to discuss thing such as terms for an exchange.', '[動-辞書形・た形・ない形-ない / 名-の]＋かわりに', '[\"音楽会に行く<b>かわりに<\\/b>、ＣＤを３枚買うほうがいいと思う。\",\"他の人がする、他の物を使う、他の事をすると言う時に使う。交換条件などを表す時にも使われる。\",\"<img src=\\\"paste-35755602739201.jpg\\\" \\/>\",\"病気の父のかわりに、私が参りました。<div>母の帰りが遅くなる日は、母の代わりに私が夕食を作ろことになっている。<\\/div>\",\"45\"]', '', '2026-04-02 15:33:28'),
(36, '~ 気味[ぎみ]', 'When you say that the current situation seems somewhat \"~\"', '[動-ます形 / 名]＋気味', '[\"仕事が忙しくて、最近少し疲れ<b>気味<\\/b>だ。\",\"今の状態は少し～の感じがすると言いたい時に使う。\",\"Rather~ ; A little~\",\"<img src=\\\"paste-19301583028225.jpg\\\" \\/>\",\"このところ残業続きで、寝不足気味だから、今日は早く帰るよ。\",\"99\"]', '', '2026-04-02 15:33:28'),
(37, '~きり(だ)', 'Only~ ; Just~', '[動-辞書形 / た形・名]＋きり', '[\"彼女は、何を聞いても笑っているきりで、答えない。\"]', '', '2026-04-02 15:33:28'),
(38, '<div>~きり</div>', 'As in \"友人とは2年前に別れたきり、会っていない\", when you want to say \"things have been the same (we haven\'t met) since then (after we parted).', '[動-た形]＋きり', '[\"彼は「ごはん」と言った<b>きり<\\/b>、黙ってしまった。\",\"<div>In spoken language becomes 「~っきり」<\\/div>\",\"「～の後はそのままだ」と言いたい時に使う。\",\"(something continuing the same condition after happening)\",\"<img src=\\\"keep-quiet.jpg\\\" \\/>\",\"寝たきり老人が増えている。\",\"37\"]', '', '2026-04-02 15:33:28'),
(39, '<div>~きる / ~きれない/ ~きれる</div>', 'Used to say that something is all done or to the end. The negative means that the amount of a task is too great to do all of or to complete.', '[動-ます形]＋きる', '[\"木村さんは疲れ<b>きった<\\/b>顔をして帰って来た。\",\"全部～する、最後まで～すると言う時に使われる。反対は多すぎて全部～できない、完全には～できないという意味で使う。\",\"In conbinations with certain words, you can also make standard expressions to say something is very \\\"~\\\".\",\"Do(be) completely~ \\/ Be unable to do till the end \\/ Be able to do till the end\",\"<img src=\\\"paste-26650272071681.jpg\\\" \\/>\",\"50\"]', '', '2026-04-02 15:33:28'),
(40, '~くせに', 'In spite of~ ; Though~', '[動・い形・な形・名]の名詞修飾型＋くせに', '[\"よく知らないくせに、あの人は何でも説明したがる\",\"Not often used in formal situations\"]', '', '2026-04-02 15:33:28'),
(41, '~くらい(だ) / ~ぐらい(だ)', 'When you say that the situation is not normal.', '[動-辞書形・ない形-ない / い形-い / な形-な / 名]＋くらい・ぐらい', '[\"棚から物が落ちる<b>くらい<\\/b>地震があった。\",\"～ほど\",\"状態が普通ではないことを表す時に使う。\",\"To the extent that~ ; As~as~ ; To the point that\",\"<img src=\\\"jishin_shirou_illust09.png\\\" \\/>\",\"痛いくらい強く握手した。\",\"102\"]', '', '2026-04-02 15:33:28'),
(42, '<div>~くらい(だ) / ~ぐらい(だ)</div>', 'At least~', '[動-普通形・名-の]＋くらい', '[\"忙しくても電話をかけるくらいはできたでしょう。\"]', '', '2026-04-02 15:33:28'),
(43, '<div>~げ</div>', 'Like \"～そうだ\", it is used when you state an impression from what you see and feel. It is often used together with words that express emotions.', '[い形-○・な形-○]＋げ', '[\"プロジェクトメンバーは、誇らし<b>げ<\\/b>な表情で成功したことを報告した。\",\"~げ becomes a な形容詞\",\"「～そうだ」と同じように、見て感じた印象を言う時に使われる。気持ちを表す言葉と一緒に使われることが多い。\",\"Seem~\",\"<img src=\\\"paste-43361989820417.jpg\\\" \\/>\",\"彼女は悲しげな様子で話した。\",\"97\"]', '', '2026-04-02 15:33:28'),
(44, '<div>~こそ / ~からこそ</div>', 'emphatic (Place a strong emphasis on the subject)', '[名]＋こそ', '[\"今度こそ試合に勝ちたい。\"]', '', '2026-04-02 15:33:28'),
(45, '<div>~ことか</div>', 'Use this when you say with emotion what you have done or felt up to now. It is often said to oneself together with words such as \"どんなに・どれだけ・どれほど\".', '[動/い形/な形]・の名詞修飾型＋ことか<div>[な形 / 名]＋である＋ことか</div>', '[\"人は私のことを頭がいいと言うけど、この試験に合格するために、どれだけ勉強した<b>ことか<\\/b>。私の努力は誰も知らないでしょうね。\",\"自分がこれまでしてきたことや感じていることについて、気持ちを込めて言う時に使われる。「どんなに・どれだけ・どれほど」などの言葉と一緒に、独り言として言うことが多い。\",\"I wonder ; quite ; surely\",\"<img src=\\\"view_1369409911.jpg\\\" \\/>\",\"息子から半年も連絡がない。一体何をしていることか\",\"42\"]', '', '2026-04-02 15:33:28'),
(46, '<div>~ことから</div>', 'When you want to give the reason for why a thing or land got its name, why a judgament was made, or the factors behind why something came to be true.', '[動/い形/な形]・の名詞修飾型＋ことから<div>[な形 / 名]＋である＋ことから</div>', '[\"このサツマイモは中が赤い<b>ことから<\\/b>、紅イモと呼ばれています。\",\"物や土地はその名前になった理由や、何かを判断した理由やそうなった原因を言いたい時に使う。\",\"[名]uses [である]、[な形]sometimes uses[である]\",\"Because~ (tells why something is)&nbsp;\",\"<img src=\\\"beni-1.jpg\\\" \\/>\",\"道がぬれていることから、昨夜、雨が降ったことがわかった。\",\"62\"]', '', '2026-04-02 15:33:28'),
(47, '<div>~ことだ</div>', 'Expresses the judgament of the speaker, as in \"you should ~; you ought to ~\". It\'s often used to give advice.', '[動-辞書形 / ない形-ない]＋ことだ', '[\"仕事でもなんでも自分一人で悩まないで誰かに相談する<b>ことです<\\/b>よ。\",\"「～すべきだ、～したほうがいい」という話者の判断を表す。アドバイスに使われることが多い。\",\"When you want to tell someone that something has importance\",\"<img src=\\\"nutritionist-500x366-300x220.jpg\\\" \\/>\",\"大学に入りたければ、一所懸命勉強することだ。\",\"87\"]', '', '2026-04-02 15:33:28'),
(48, '<div>~ことだから</div>', '<div>As it is ~ it can be expected that ~</div>', '[名]＋ことだから', '[\"<div>子供のことだから、少しぐらいいたずらをしても仕方がないです。<\\/div>\",\"<div>Used to tell something everyone knows. Following sentence is a presumption.<\\/div>\"]', '', '2026-04-02 15:33:28'),
(49, '<div>~ことなく</div>', 'When something happens or is completed even though some action has not been done, as in \"休むことなく働き続けている\".', '[動-辞書形]＋ことなく', '[\"ロボットは２４時間休む<b>ことなく<\\/b>働いている。\",\"何かをしない状態で後ろの動作が続いたり、完了したりする時に使う。\",\"Without~\",\"<img src=\\\"paste-15530601742337.jpg\\\" \\/>\",\"今回は優勝することができましたが、これで満足することなく、さらに努力を続けます。これからも、応援よろしくお願いします。\",\"20\"]', '', '2026-04-02 15:33:28'),
(50, '<div>~ことに(は)</div>', 'Use this expression when you say something like \"困ったことにお金がなかった\" in reverse order, like \"I didn\'t have money and it was a problem\", and you want to express a feeling or emotion.', '[動-た形・い形-い・な形-な]＋ことに', '[\"ホテルの部屋に入ったら、驚いた<b>ことに<\\/b>、バラの花束とホテルマネージャーからの歓迎メッセージがテーブルの上に置いてあった。\",\"話者の気持ち、感情を強く表したい時に使う。\",\"To my~ (strengthens the speakers feeling ex. To my surprise)\",\"<img src=\\\"2-dozen-roses-brought.jpg\\\" \\/>\",\"驚いたことに、私の祖父と恋人のおじさんは小学校時代の友達だったそうです。\",\"40\"]', '', '2026-04-02 15:33:28'),
(51, '<div>~ことになっている</div>', 'Be supposed to ~ (shows an appointment or rule)', '[動-辞書形；動-ない形-ない；い形-い]＋ことになっている', '[\"今度の日曜日、友達と会うことになっている。\"]', '', '2026-04-02 15:33:28'),
(52, '<div>~ことはない</div>', 'When you want to say \"there\'s no need to do ~; you don\'t have to do ~\". It is often used to give advice.', '[動-辞書形]＋ことはない・こともない', '[\"君が謝る<b>ことはない<\\/b>よ。悪いのは向こうなんだから。\",\"「～する必要はない・～しなくてもいい」と言いたい時に使う。アドバイスに使うことが多い。\",\"No need to ~\",\"<img src=\\\"aid18166-v4-728px-Apologize-Step-19-Version-2.jpg\\\" \\/>\",\"時間は十分あるから、急ぐことはない。\",\"49\"]', '', '2026-04-02 15:33:28'),
(53, '<div>~ 際[さい](は) / ~ 際[さい]に</div>', 'Used in manuals, guides and the like to mean \"if / when ~\". Phrases such as \"してください・必要です・お願いします\" often come afterward.', '[動-辞書形・た形 / 名-の]＋際(に)', '[\"カードを紛失した<b>際は<\\/b>カード会社にすぐ知らさせなければならない。\",\"「～場合」という意味で、説明書や案内などで使われる。後ろに「してください・必要です・お願いします」などの文が来ることが多い。\",\"When~ ; Upon~\",\"<img src=\\\"lost-credit-card-wallet1.jpg\\\" \\/>\",\"入学手続きの際に必要なものは下記の通り。\",\"7\"]', '', '2026-04-02 15:33:28'),
(54, '~ 最中[さいちゅう]だ / ~ 最中[さいちゅう]に', 'When something unexpected happens just as you were doing something else. This expression is often used in situations when you do not want to be bothered.', '[動-ている / 名-の]＋最中に', '[\"考えている<b>最中に<\\/b>、話をかけられて困った。\",\"何かをしている、ちょうどその時に、思っていなかったことが起きた時に使われる。邪魔されたくない状況の時によく使われる。\",\"In the midst of~ ; During ~\",\"<img src=\\\"serious-man-thinking_1149-1328.jpg\\\" \\/>\",\"面接の最中にお腹が鳴ってしまった。\",\"84\"]', '', '2026-04-02 15:33:28'),
(55, '<div>~さえ / (~で)さえ</div>', 'When you want to emphasize something by giving an extreme example. The negative form is often used after this expression.', '[名]＋[助詞]＋さえ<div>[動-て形]＋さえ</div>', '[\"そこは電気<b>さえ<\\/b>ない山奥だ。\",\"when さえ is connected to a noun, the particles　は、 が and を are omitted.\",\"極端な例を出して、強調したい時に使う。\",\"Even~　&lt;one example is an extreme conditon, and everything that follows is a needless to say&gt;\",\"<img src=\\\"Japan-Off-Grid-Cabin01.jpg\\\">\",\"<div>加藤さんは明後日までにレポ－トを書かなければならないのに、まだ資料を集めてさえいない。<\\/div>来週から主張に行くのに、ホテルの予約はもちろん、航空券の予約さえしてない。\",\"101\"]', '', '2026-04-02 15:33:28'),
(56, '<div>~さえ~ば</div>', 'When you want to say \"~ is the only necesary condition\" as in \"給料さえよければどんな仕事でもいい\".', '[名]＋さえ＋[普通形-ば]<div>[動-ます形]＋さえ＋すれば・しなければ</div><div>[い形-く・な形で・名-で]＋さえ＋あれば・なければ</div>', '[\"食べられ<b>さえすれば<\\/b>、味は問わないよ。\",\"「～だけが必要な条件だ」と言いたい時に使う。\",\"If only~\",\"<img src=\\\"paste-19520626360321.jpg\\\" \\/>\",\"インスタントラ-メンはお湯を入れさえすれば食べられる便利な食品だ。体さえ丈夫なら、どんな苦労に耐えられると思う。\",\"43\"]', '', '2026-04-02 15:33:28'),
(57, '<div>~ざるを 得[え]ない</div>', 'When you want to say \"I don\'t like it, but I have to / there\'s nothing else I can do.\"', '[動-ない形]＋ざるを得ない', '[\"みんなで決めた規則だから、守ら<b>ざるを得ない<\\/b>。\",\"状況から、「嫌だが～しなければならない・～するしかない」と言いたい時に使う。\",\"[する] becomes 「せざる得ない」\",\"Can’t help thinking~\",\"<img src=\\\"0206.gif\\\" \\/>\",\"台風接近のため、野外コンサートは中止せざるを得なくなった。\",\"24\"]', '', '2026-04-02 15:33:28'),
(58, '<div>~しかない</div>', 'When you say that given the current situation, only this approach (as expressed by \"~\") is available, or that this is the best. This expression is also often used to say something along the lines of \"it can\'t be helped\".', '[動-辞書形 / 名]＋しかない', '[\"事故で電車が動かないから、歩いて行く<b>しかない。<\\/b>\",\"<div>～ほか（は）ない<\\/div>\",\"今の状況ではこれ以外に方法がない、これが一番いいと言う時に使う。仕方がないという気持ちで使うことも多い。\",\"<!--anki-->Have no other way but~ \\/ Must~\",\"<img src=\\\"160909114434-09-spain-train-crash-exlarge-169.jpg\\\" \\/>\",\"入学試験まであと1週間。とにかく頑張るしかありません。\",\"88\"]', '', '2026-04-02 15:33:28'),
(59, '<div>~ 次第[しだい]</div>', 'When you say \"when something (that I can\'t do yet) happens, I\'ll do・・・right away.\"', '[動-ます形・名]＋次第', '[\"ただ今、全線で運転を見合わせておりますが、情報が入り<b>次第<\\/b>、お伝え致します。\",\"「(今はまだできないが)～たら、すぐ・・・する」と言う時に使う。\",\"As soon as~\",\"<img src=\\\"0e5afb88f406f70920cdedbf4a803782.jpg\\\" \\/>\",\"新しい住所を決まり次第、連絡します。\",\"36\"]', '', '2026-04-02 15:33:28'),
(60, '<div>~次第だ / ~次第で(は)</div>', 'show a reason, details. &nbsp;When you want to show the result of something.', '[動・い形・な形]の名詞修飾型＋次第だ', '[\"このたび日本政府の招きにより、親善大使として日本に来た次第だ。\"]', '', '2026-04-02 15:33:28'),
(62, '~ 上[じょう](は) / ~ 上[じょう]の / ~ 上[じょう]も', 'Use it together with words that show a perspective meaning to mean \"in view of ~\".', '[名]＋上', '[\"お札にはその国の歴史<b>上<\\/b>の人物の顔が描かれていることが多い。\",\"the noun in front of ~上 is usually a Chinese word　Ex. 「教育上」、「外見上」、「経済上」、「政治上」、「学問上」、「表面上」、「職業上」、「外交上」etc…\",\"「~の点から教えて」という意味で、視点を示す言葉と一緒に使う。\",\"From the standpoint of~; (can also be thought of as ~ly. Ex. 歴史上?hisorically 法律上?legally)\",\"<img src=\\\"img_intro02.jpg\\\" \\/>\",\"京都には歴史上有名なお寺が数多くある\",\"70\"]', '', '2026-04-02 15:33:28'),
(63, '~ 末[すえ] (に) / ~末の', 'When you want to say \"after doing ~ for a long time (in the end the result was ・・・)\". You can also use it even if it did not take a long time because it \"felt long\" to the speaker.', '[動-た形 / 名-の]＋末(に)', '[\"家族ともよく話し合った<b>末<\\/b>、今年度限りで引退することに決めました。\",\"「長い間～をして（最後に・・・という結果になった）」と言いたい時に使う。実際に長くなくても、話者にとって「長く感じられた」という場合にも使う。\",\"After~(for a long time)\",\"<img src=\\\"paste-13773960118273.jpg\\\" \\/>\",\"いろいろ考えた末、会社を辞めることにした。\",\"124\"]', '', '2026-04-02 15:33:28'),
(64, '<div>~せいか / ~せいだ / ~せいで</div>', 'Because of~ ; On account of~ (The cause leads to a bad result)', '[名詞修飾型]＋せいだ', '[\"私が失敗したのは、彼の<b>せいだ。<\\/b>\",\"理由がはっきりと分かっている時は「～せいで」、はっきり分からない時は「～せいか」を使う。\",\"悪い結果になった理由を強く言う時に使われる。\",\"<div>気のせい: be one’s imagination<\\/div><div>せいにしている:　blame something or somebody<\\/div>\",\"<img src=\\\"David-De-Gea-1.jpg\\\" \\/>\",\"<div><div>部屋がほこりっぽいのは掃除機のせい？<\\/div><\\/div><div><div>列車が止まったのは嵐のせいだった。<\\/div><\\/div><div><div>風邪をひいたせいで声が出なくなった。<\\/div><\\/div><div><div>彼女は結婚生活がうまくいかないのを私のせいだと言う。<\\/div><\\/div>\",\"97\"]', '', '2026-04-02 15:33:28'),
(65, '<div>~だけ / ~だけあって / ~だけに / ~だけの</div>', 'When you say that you sense that something \"feels even more ・・・ because of ~\"', '[動-辞書形・た形・ている形 / い形-い / な形-な / 名-な]＋だけに', '[\"今年は猛暑な<b>だけに<\\/b>、ビールが一層美味しく感じられる。\",\"感覚的に「～だから、さらに・・・と感じる」という時に使われる。\",\"Becoming of~ ; Worthy of~ ; Fitting of~\",\"<img src=\\\"29degrees.jpg\\\" \\/>\",\"この仕事は努力しただけ成果が現れるので、やりがいがある\",\"105\"]', '', '2026-04-02 15:33:28'),
(68, '<div>~たとえ~ても / ~たとえ~でも</div>', 'Meaning \"even if ~ \", when you want to strongly say \"no matter what situation\".', 'たとえ＋[動-ても・い形-くても・な形-でも・名-でも]', '[\"子供がいるので、<b>たとえ<\\/b>給料が高く<b>ても<\\/b>、土日に休めない仕事はしたくない。\",\"「もし～ても」という意味で、「どんな場合でも」と強く言いたい時に使う。\",\"Even if~\",\"<img src=\\\"paste-20276540604417.jpg\\\" \\/>\",\"自分で決めた道だから、失敗しても後悔しない。\",\"125\"]', '', '2026-04-02 15:33:28'),
(69, '<div>~(た)ところ</div>', 'When~ (When something is done, this is the result)', '[動-た形]＋ところ', '[\"新しいワ-プロを使ってみたところ、とても使いやすかった。\"]', '', '2026-04-02 15:33:28'),
(70, '<div>~たとたん(に)</div>', 'When you explain in a situation in which 「．．．」 happened right after &nbsp;「～」&nbsp;', '[動-た形]＋とたん', '[\"犯人は警官の姿を見た<b>とたん<\\/b>、逃げ出した。\",\"「・・・」の部分が話者の意志ですることの場合は使わない。\",\"「～」の後すぐ「・・・」が起こったという状況を説明する時に使う。\",\"<img src=\\\"paste-30017526431745.jpg\\\" \\/>\",\"<div>彼を見たとたん私は吹き出した。<\\/div><div><div>彼が帰宅した途端に雨が降った。<\\/div><\\/div><div><div>僕は見たとたんに彼女だと分かった。<\\/div><\\/div><div><div>腰を下ろしたとたんに、電話が鳴った。<\\/div><\\/div><div><div>彼がそれに手を触れたとたんに爆発した。<\\/div><\\/div>\",\"15\"]', '', '2026-04-02 15:33:28'),
(71, '<div>~たび(に)</div>', 'When you say that a certain thing happens every time a certain action is taken.', '[動-辞書形 / 名-の]＋たび', '[\"その歌を歌う<b>たび<\\/b>、幼い日のことを思い出す。\",\"繰り返し行われることについて、それをする時はいつも、と言う時に使う。\",\"Everytime~\",\"<img src=\\\"aid46137-v4-728px-Remember-Your-Past-Lives-Step-2.jpg\\\" \\/>\",\"父は出張のたびにお土産を買ってきてくれる。\",\"60\"]', '', '2026-04-02 15:33:28'),
(72, '<div>~だらけ</div>', 'Full of~ &lt;negative&gt;', '[名]＋だらけ', '[\"このレポ-トは字が間違い<b>だらけ<\\/b>で読みにくい。\",\"「～いっぱい」；　「～ばっか」\",\"泥やしわ等汚い物がたくさんついている時、間違い等マイナスの評価の物がたくさんある時に使う\",\"<img src=\\\"bpQgCLH.jpg\\\" \\/>\",\"<div><div>彼女の顔はにきびだらけだ。<\\/div><\\/div><div><div>この本は間違いだらけだ。<\\/div><\\/div><div><div>床は血だらけだった。<\\/div><\\/div><div><div>その部屋で古びた錆だらけ鍵を見つけました。<\\/div><\\/div>\",\"104\"]', '', '2026-04-02 15:33:28'),
(73, '<div>~ついでに</div>', 'When you want to take advantage of another action to do something else.', '[動-辞書形・た形 / 名-の]＋ついでに', '[\"銀行へ行く<b>ついでに<\\/b>この手紙を出してくれませんか。\",\"何かをする機会を利用して他の事をすると言う時に使う。\",\"「ついでに」だけでも使われる。\",\"When doing ~ also do ~\",\"<img src=\\\"Santa-Mail.jpg\\\" \\/>\",\"薬局へ薬を買いに行ったついでに、トイレットペーパーも買ってきた。\",\"109\"]', '', '2026-04-02 15:33:28'),
(74, '<div>~っこない</div>', 'When you want to strongly deny something because it is absolutely unthinkable.', '[動-ます形]＋っこない', '[\"宝くじなんて当たり<b>っこない<\\/b>よ。\",\"～わけがない\",\"Use in conversations\",\"そなことは絶対考えられないと、強く否定したい時に使う。\",\"No way that~\",\"<img src=\\\"Winning-the-Lottery.jpg\\\" \\/>\",\"30年後、自分がどこて何をしているかは誰にも分かりっこない。\",\"91\"]', '', '2026-04-02 15:33:28'),
(75, '~つつ', 'Same mining as \"ながら\"', '[動-ます形]＋つつ', '[\"クリスマスを前におもちゃ売り場には、喜ぶ子供の顔を思い浮かべ<b>つつ<\\/b>、プレゼントを選ぶお父さんの姿が増えています。\",\"Not used in conversations.\",\"「～ながら」と同じ意味で使う。\",\"While~\",\"<img src=\\\"7f3841fbe9c77651b699a688af8f5784.jpg\\\" \\/>\",\"財布の中身を考えつつ、買い物をした。\",\"30\"]', '', '2026-04-02 15:33:28'),
(76, '<div>~つつある</div>', 'Use this to explain that something is changing little by little as in \"日本の人口は減りつつある\".', '[動-ます形]＋つつある', '[\"異常気象の影響が世界各地に広がり<b>つつある。<\\/b>\",\"Used mostly in written form\",\"少しずつ変化していると説明する時に使う。\",\"Be (gradually) doing~\",\"<img src=\\\"lightning.jpg\\\" \\/>\",\"景気は徐々に回復しつつある。\",\"71\"]', '', '2026-04-02 15:33:28'),
(77, '<div>~っぽい</div>', '~ish ; ~like ; ~looking', '[い形-○ / 名]＋っぽい', '[\"このテーブルは高いのに安<b>っぽく<\\/b>見える\",\"見た時の印象が、そう見える、そう感じる時に使う\",\"<img src=\\\"veloce100ct_1.jpg\\\" \\/>\",\"<div>ジャスティンは女っぽい。<\\/div><div><div>あの小学生は、大人っぽい。<\\/div><\\/div><div><div>部屋がほこりっぽいのは掃除機のせい？<\\/div><\\/div><div><div>あなたは、今日は本当に怒りっぽいですね。<\\/div><\\/div>\",\"96\"]', '', '2026-04-02 15:33:28'),
(79, '<div>~(て) 以来[いらい]</div>', 'When a condition has continued from \"~\" until now.', '[動-て形 / 名]＋以来', '[\"母が入院して<b>以来<\\/b>、家事はすべて私がしています。\",\"「～」の時から今までずっと同じ状態が続いている時に使う。\",\"Since~(and still going on)\",\"<img src=\\\"housework.jpg\\\" \\/>\",\"3年前の夏休みに帰国して以来、長い間家族に会っていません。\",\"9\"]', '', '2026-04-02 15:33:28'),
(80, '<div>~てからでないと / ~てからでなければ</div>', 'When you say that \"・・・\" cannot be done until \"~\" is done.', '[動-て形]＋からでないと・からでなければ', '[\"お金をいただいて<b>からでないと<\\/b>、商品はを届けできません。\",\"The following sentence will always be negative.\",\"「・・・」は「～」が実現しないとできないと言う時に使う。\",\"Not until~\",\"<img src=\\\"cod.jpg\\\" \\/>\",\"この会社では、３か月の研修を受けてからでなければ正社員になれません。\",\"79\"]', '', '2026-04-02 15:33:28'),
(81, '<div>(~て)たまらない / ~(て)しょうがない</div>', 'When you say that a person\'s mental or physical condition is very \"~\" or that a person is so \"~\" that he or she can not resist doing something.', '[動-て形 / い形-くて / な形-で]＋しょうがない・しかたがない・たまらない', '[\"頭痛がして<b>たまらない<\\/b>ので、近くの病院へ行った。\",\"Subject is always first person\",\"心や体の状態がとても～だ、我慢できないぐらい～だと言う時に使う。\",\"Can’t help~ing ; Can’t stand(bear)~\",\"<img src=\\\"313BF7E000000578-3447870-Those_who_skip_breakfast_makes_people_feel_less_energetic_so_the-a-59_1455541937170.jpg\\\" \\/>\",\"空気が乾燥しているせいか、のどが乾いてしょうがない。\",\"113\"]', '', '2026-04-02 15:33:28'),
(82, '<div>(~て)ならない</div>', 'Is used when you want to say something \"is extremely ~\".<br>', '[動-て形 / い形-くて / な形-で]＋ならない', '[\"私のように年をとってくると、ふるさとの山々が懐かしく思い出されて<b>ならない<\\/b>んですよ。\",\"<div>「綺麗・下手」など評価を表す言葉と一緒には使わなう。<\\/div><div>Don\'t use it with words that assess.<\\/div>More formal than「~てたまらない」。「思える」、「思い出す」etc. can\'t use 「~てたまらない」\",\"「非常に～だ」と言いたいときに使われる。\",\"「残念・不安・心配・つらい・悔しい」など、感情を表す言葉と一緒に使う。<div>Use it together with words that express feelings.<\\/div>\",\"Can’t help~ing\",\"<img src=\\\"paste-12768937771009.jpg\\\" \\/>\",\"交通事故で両親を亡くした子供がかわいそうに思えてならない。\",\"121\"]', '', '2026-04-02 15:33:28'),
(83, '<div>~ということだ、～とのことだ</div>', 'When you tell another person some information you heard.', '[普通形]＋ということだ・とのことだ', '[\"新聞によると、また地下鉄の運賃が値上げされる<b>ということだ<\\/b>。\",\"聞いた情報の内容を他の人に伝える時に使う。\",\"<img src=\\\"o-METROCARD-facebook.jpg\\\" \\/>\",\"<div>つまり常識を疑えということだ。<\\/div><div><div>全ての兆候は彼女が回復しているということだ。<\\/div><\\/div><div><div>天気予報によると、明日は快晴になるということだ。<\\/div><\\/div>\",\"29\"]', '', '2026-04-02 15:33:28'),
(84, '<div>~というと&nbsp;/ ~といえば&nbsp;/ ~といったら</div>', 'When you say something that people often associate with \"~\". The example given is often something famous or typical.', '[名]＋というと・といえば・といったら', '[\"スポーツの祭典<b>というと<\\/b>、まずオリンピックですね\",\"その言葉から多くの人がイメージする物事を言う時に使う。有名なものや代表的なものを言うことが多い。\",\"Speaking of~ ; Talking about~　&lt;use when speaking something typical about the topic&gt;\",\"<img src=\\\"ea2c66983bfeeb390b6c819047a5195405e53328.jpg\\\" \\/>\",\"日本の花というと、桜がすぐ頭に浮かぶ。\",\"54\"]', '', '2026-04-02 15:33:28'),
(85, '<div>~というと / ~といえば</div>', 'Speaking of~ ; Talking about~　&lt;use when remembering something about the subject&gt;', '[普通形]＋といえば', '[\"<div>「昨日、ジョンさんに会いましたよ。」<\\/div><div>「そうですか。ジョンさんといえばＡ会社に就職が決まったそうですね。」<\\/div>\",\"[名]doesn\'t use [だ]\"]', '', '2026-04-02 15:33:28'),
(86, '<div>~というものだ</div>', 'When you want to say tou think that \"this isn\'t what I think, but generally it\'s like this\".', '[普通形]＋というものだ', '[\"貧しくても家族が仲良く暮らせるのが幸せ<b>というものです<\\/b>よ。\",\"話者の考えを、個人的な意見ではなく一般的にそうだと言いたい時に使う。\",\"sometimes [な形；名]don\'t use [だ]\",\"Is known as~ ; It is that~\",\"<img src=\\\"418811132e2875e93c1d693859c360d7.jpg\\\" \\/>\",\"彼の作品がやっと世間から評価された。長年の苦労が認められたというものだ。\",\"52\"]', '', '2026-04-02 15:33:28'),
(87, '<div>~というものではない / ~というものでもない</div>', 'When you want to say that \"people usually think so, but it\'s not necesarilly like that\"', '[普通形]＋というものではない・というものでもない', '[\"性格は絶対に変えられない<b>というものではない<\\/b>。\",\"一般的にそう思われていることも、絶対そうだとは言えないと言いたい時に使う。\",\"sometimes [な形；名]don\'t use [だ]\",\"Not necessarily~ ; It’s not that\",\"<img src=\\\"YesYouCanChangeYourPersonality-800x588.jpg\\\" \\/>\",\"勉強は今日やれば明日やらなくていいというものではない。\",\"25\"]', '', '2026-04-02 15:33:28'),
(88, '<div>~というより</div>', 'As in \"涼しいというより寒い\", use \"AというよりB\" when you want to say \"it\'s more important to say B (it\'s cold) than A (it\'s cool).', '[普通形-○]＋というより', '[\"彼の言い方は勧めている<b>というより<\\/b>、強制しているよ。\",\"「Aの言い方よりBと言ったほうが適切だ」と言いたい時に使う。\",\"[な形・名] do not use [だ]\",\"More than~\",\"<img src=\\\"Government-oppression-sign-Cropped-620x400.png\\\" \\/>\",\"姉は僕より10歳年上で、小さい時からいろいろ世話をしてくれたので、姉というより母親のような存在だ。\",\"28\"]', '', '2026-04-02 15:33:28'),
(89, '<div>~といったら</div>', 'Speaking of~ ; Talking about~(show plus and minus)', '[名]＋といったら', '[\"息子の部屋の汚いことといったら、ひどいものです。\"]', '', '2026-04-02 15:33:28'),
(90, '<div>~といっても</div>', 'As in \"会社といっても妻と二人でやっている小さい会社です\", use this when you want to say \"It\'s not actually like that\" in response to what the listener has imagined (the company has many employees).', '[普通形]＋といっても・といいましても', '[\"1世帯<b>といっても<\\/b>、一人暮らしの人から10人以上の大家族までいろいろある。\",\"相手が想像したことに対して、「実際にはそうではない」と言いたいときに使う。\",\"sometimes[な形；名]don\'t use [だ]\",\"But~ ; Although~ (show what your thinking about is wrong or different)\",\"<img src=\\\"IMG_20181006_011240.jpg\\\" \\/>\",\"庭があるといっても猫の額ほどです。\",\"103\"]', '', '2026-04-02 15:33:28'),
(91, '<div>~とおり(に) / ~どおり(に)</div>', 'To say that something happened exactly as someone said or guessed it would.', '[動-辞書形・た形 / 名-の]＋とおり<div>[名]＋どおり</div>', '[\"説明書に書いてある<b>とおり<\\/b>にやってみてください。\",\"言ったことや予想したことなどと同じだという時に使う。\",\"<img src=\\\"paste-11909944311809.jpg\\\" \\/>\",\"今日の映画は本当に面白かった。友達が言ったとおりだった。<div>初めて見た富士山は私が想像していたとおりにきれいだった。<\\/div><div>料理の本に書いてあるとおりに作ったら、おいしくできた。<\\/div>\",\"25\"]', '', '2026-04-02 15:33:28'),
(92, '<div>~とか</div>', 'This is used in forms such as \"～とか言っていた\" when you state information you have heard. It is often used with the nuance that the information may not be solid. You can also omit words such as \"言っていた\".', '[普通形]＋とか', '[\"息子さんが今度結婚なさる<b>とか<\\/b>。おめでとうございます。\",\"聞いた情報を言う時に使われる。確かな情報ではないがという気持ちで使うことが多い。\",\"hear that~ ; say that~\",\"<img src=\\\"married-588592153df78c2ccdf11fde.jpg\\\" \\/>\",\"新聞によると、国内線の飛行機運賃が上がるとか。\",\"107\"]', '', '2026-04-02 15:33:28'),
(93, '<div>~どころか</div>', 'As in \"雨が降るどころかすごくいい天気になった\", it expresses a feeling that strongly says \"it\'s not A (rainy weather), it\'s the opposite (fine weather)\". In addition, as in \"漢字どころかひらがなも読めない\", it\'s also used when you say \"it\'s not A (not able to read kanji), it\'s something much more, B (not able to even read hiragana)\". A is often something the listener said or something the speaker just thought of.', '[普通形-○]＋どころか', '[\"高校生の時は、海外旅行<b>どころか<\\/b>国内旅行もしたことがありませんでした。\",\"Aではなくて反対のBだと強く言う気持ちを表す。また、Aよりもっと程度がすごいBと言う時に使う。Aには相手の言ったことや自分が初めに思ったことなどが入ることが多い。\",\"[な形・名]don\'t use[だ]；[な形-な]can be used\",\"Far from~\",\"<img src=\\\"paste-21294447853569.jpg\\\" \\/>\",\"彼は貯金するどころか借金だらけだ。\",\"83\"]', '', '2026-04-02 15:33:28'),
(94, '<div>~どころではない / ~どころではなく</div>', 'When you want to explain thet your situation now is \"not a situation wher I can do ~ (so I can\'t do it).\"', '[動-辞書形 / 名]＋どころではない・どころじゃない', '[\"A: 学校が終わったらカラオケ行かない？<div>B: カラオケ<b>どころじゃない<\\/b>よ！レポート、書かなきゃ。明日締め切りなんだ・締め切りなんだ。<\\/div>\",\"今は「～ができる状態ではない(だからできない)」という自分の状況を説明したい時に使う。\",\"Can’t do ~ because~\",\"<img src=\\\"paste-10750303141889.jpg\\\" \\/>\",\"人の仕事を手伝うどころではありません。自分の仕事も間に合わないんです。\",\"38\"]', '', '2026-04-02 15:33:28'),
(95, '<div>~ところに / ~ところへ / ~ところを</div>', 'When you say that someone did \"・・・\" or that \"・・・\" happened right in a certain setting or at a certain time (as expressed by ~)', '[動-辞書形・た形・ている形 / い形-い]＋ところに', '[\"ちょうどキムさんのうわさをしている<b>ところに<\\/b>、本人がやって来た。\",\"「ところ」の後ろにつく助詞は「～ところを見られた」「～ところへ\\/に来た」「～ところで終わった」など、後ろの動詞によって変わる。\",\"ちょうど「～」の場面、「～」の時に、「・・・」をする、「・・・」が起きたと言う時に使う。\",\"[動-ていた形・意向形-とした]＋ところの形も使われる。\",\"At that time ; At that place ; At that scene\",\"<img src=\\\"getty_508970750_2000133420009280144_128946.jpg\\\" \\/>\",\"<div>彼らは彼が盗んでいるところを見つけた。<\\/div><div><div>彼がカンニングをしているところを押さえた。<\\/div><\\/div>\",\"49\"]', '', '2026-04-02 15:33:28'),
(96, '<div>~としたら / ~とすれば</div>', 'Use it meaning \"imagine if ~, ・・・\", when you want to state a personal opinion or prediction.', '[普通形]＋としたら・とすると・とすれば', '[\"もし、生まれ変われる<b>としたら<\\/b>、私は鳥になりたい。\",\"「～だと考えば・・・」という意味で、自分の意見や予想を言いたい時に使う。\",\"If~ (Think from the perspective of~)\",\"<img src=\\\"Screen-Shot-2013-11-05-at-1.31.59-PM.png\\\" \\/>\",\"留学するとしたら、日本に行きたいと思っていました。<div>足の悪い人が地下鉄を利用するとしたら、どんな設備が必要だろうか。<\\/div>\",\"113\"]', '', '2026-04-02 15:33:28'),
(97, '<div>~として(は) / ~としての / としても</div>', 'When you want to state a qualification, use or the like, as in \"留学生として\" and \"旅行用として\".', '[名]＋として', '[\"この病気は難病<b>として<\\/b>認定された。\",\"資格・用途などを言う時に使う。\",\"As~\",\"<img src=\\\"paste-10436770529281.jpg\\\" \\/>\",\"入社後は企業人としての自覚を持って行動してください。\",\"22\"]', '', '2026-04-02 15:33:28'),
(98, '<div>~とともに</div>', 'With~&nbsp;', '[名]＋とともに', '[\"お正月は家族とともに過ごしたい。\"]', '', '2026-04-02 15:33:28'),
(101, '<div>~ないことには</div>', 'Is used when you want to say \"if you don\'t do ~, then you can\'t / you won\'t know ・・・\".', '[動-ない形 / い形-く / な形-で / 名-で]＋ないことには', '[\"もっと広い会場は借り<b>ないことには<\\/b>、観客を収容しきれないだろう。\",\"The following sentence will be negative.\",\"「～なければ（・・・できない・わからない）」と言いたいときに使われる。\",\"If not~\",\"<img src=\\\"homepic.jpg\\\" \\/>\",\"実際に読まないことには、この小説の面白さは分からないだろう。\",\"110\"]', '', '2026-04-02 15:33:28'),
(102, '<div>~ないことはない / ~ないこともない</div>', 'When you cannot say flat out that something \"absolutley is ~\" or are not confident and do not want to say something flat out.', '[動-ない形 / い形-く / な形-で / 名-で]＋ないことはない', '[\"カラオケは行か<b>ないこともない<\\/b>んです、誘われた時にお付き合いで行くぐらいです。\",\"「絶対～だ」とはっきり言えない、自信がなくてはっきり言いたくない時に使う。\",\"Possibility of~ &nbsp;(Neither yes or no)\",\"<img src=\\\"karaoke2-1446926502-600x360.jpg\\\" \\/>\",\"難しいが、やり方次第ではできないことはないだろう。\",\"54\"]', '', '2026-04-02 15:33:28'),
(103, '<div>~ないではいられない / ずにはいられない</div>', 'When you say that you can not stand it and end up doing \"~\" no matter how hard you try not to do.', '[動-ない形]＋ずに・ないで＋はいられない', '[\"彼のもの真似を見るとおかしくて、笑わない<b>ではいられない。<\\/b>\",\"～ないではいられない\",\"Only for first person. &nbsp;For third person, use 「~ようだ」「~らしい」at the end.\",\"我慢ができなくて、どうしても～してしまう状況だと言う時に使う。\",\"[する]becomes[ぜずにはいらない]\",\"Always end up~\",\"<img src=\\\"man-little-boy-shaving-foam-260nw-788255794.jpg\\\" \\/>\",\"一流の水泳選手はみんな、毎日練習せずにはいられないらしい。\",\"86\"]', '', '2026-04-02 15:33:28'),
(104, '<div>~ながら</div>', 'When you want to say \"this is the situation, but...\"', '[動-ます形・ない形-ない / い形-○ / な形-○ / 名]＋ながら<div>[な形-○ / 名]＋であり＋ながら</div>', '[\"一緒に暮らしてい<b>ながら<\\/b>、母の病気に気づかなかった。\",\"「~つつ \\/ ~つつも」のBの意味\",\"「～の状態だが、けれども」と言いたい時に使う。\",\"Though~\",\"<img src=\\\"Illness-Disease.jpg\\\" \\/>\",\"彼とは同じ尞に住んでいながら、ほとんど話をしたことがなかった。\",\"15\"]', '', '2026-04-02 15:33:28'),
(105, '<div>~など / ~なんか / ~なんて</div>', 'Use it when you want to gently suggest another option to the listener, while leaving the decision up to him or her.', '[名]＋なんか', '[\"こちらのセーター<b>なんか<\\/b>いかがでしょう。この色は今年の流行色ですよ。\",\"なんか、なんて are used in spoken language<span class=\\\"Apple-tab-span\\\" style=\\\"white-space:pre\\\"> <\\/span>\",\"他の物でもいいような言い方で相手に判断を任せる形にして、柔らかく言うときに使う。\",\"1. such as; like; and so on　&lt;when you want to give an example, or make a light expression.&gt;<div>2.&nbsp;etc; among other things ; for example&lt;make light of something or say something negative&gt;<\\/div>\",\"<img src=\\\"shopping-addictioni-604cs040813.jpg\\\" \\/>\",\"お見舞いならカ-ネ-ションなんてどうかしら<div>忙しくて、テレビなど見ていられない<\\/div>\",\"66\"]', '', '2026-04-02 15:33:28'),
(106, '<div>~にあたり / ~にあたって</div>', 'It means \"when doing ~\".', '[動-辞書形 / 名]＋にあたって・にあたり', '[\"開会<b>にあたって<\\/b>、一言ご挨拶申し上げます。\",\"「～をするときに」という意味を表す。\",\"When~(show something that should be done in this situation)\",\"<img src=\\\"paste-23038204575745.jpg\\\" \\/>\",\"開会にあたって、ひとことごあいさつ申し上げます。\",\"135\"]', '', '2026-04-02 15:33:28'),
(107, '<div>~において(は) / ~においても / ~における</div>', 'When you want to say a place, time, field / subject, area and so on. Often used in announcements and the like.', '[名]＋において<div>[名]＋における＋[名]</div>', '[\"会議は第一会議室<b>において<\\/b>行われる。\",\"「場所・時代・分野などで」と言いたい時に使う。お知らせやニュースなどで使われることが多い。\",\"In ; At ; On ; same as the particle で\",\"<img src=\\\"1stkaigi1.jpg\\\" \\/>\",\"入学試は、3階のホールにおいて行われます。\",\"6\"]', '', '2026-04-02 15:33:28'),
(108, '<div>~に 応[おう]じ / ~ 応[おう]じた / ~ 応[おう]じて</div>', 'When you want to say that something \"depends on conditions such as a desire, change, location, situation, age, ability or experience.\"', '[名]＋に応じて', '[\"保険金は被害状況<b>に応じて<\\/b>、払われる。\",\"「希望・変化・地域・状況・年齢・能力・経験などの条件に合わせて・・・する」と言いたい時に使う。\",\"In response to~\",\"<img src=\\\"storm-damage-pic-home-page-box-300x201.jpg\\\" \\/>\",\"給料は能力や経験に応じ、決めさせたいただきます。\",\"4\"]', '', '2026-04-02 15:33:28'),
(109, '<div>~にかかわらず / ~に(は)かかわりなく</div>', 'Is used when you want to say \"regardless of conditions such as weather, preference, social position, or whether something is there or not there, done or not done, etc.\"', '[名]＋にかかわらず<div>[動-辞書形＋動-ない形]＋ないにかかわらず</div>', '[\"参加するしない<b>かかわらず<\\/b>、必ず返事をください。\",\"<div>Nouns showing a kind or extent of something, or 2 words in opposition are usually used.&nbsp;Such as 「する・しない」「晴雨」。Adjectives such as 「いい・悪い」「好き・嫌い」「上手・下手」&nbsp;can be combined and used.<\\/div>\",\"「天候・好み・地位や、あるなし・するしないなどの条件に関係なく・・・」と言いたい時に使われる。\",\"Regardless of~\",\"<img src=\\\"08_reply_to_address_in_message.png\\\" \\/>\",\"区民センターの利用料金は変更になりました。和室は人数にかかわらず、2時間1,000円になります。\",\"5\"]', '', '2026-04-02 15:33:28'),
(110, '<div>~に 限[かぎ]って / ~ 限[かぎ]り / ~に 限[かぎ]る</div>', 'It\'s often used to mean \"only / just\" in an announcement and the like.', '[名]＋に限る・に限り・に限って', '[\"参加者は女性<b>に限る<\\/b>。\",\"[名]＋に限って...ない」の形で、予想していなかった悪いことが起きた時や、噂などに対して信じられないと強く否定したい時に使う。\",\"「だけ」という意味で、お知らせなどによく使われる。\",\"Only~\",\"<img src=\\\"178D6928.JPG\\\" \\/>\",\"うちの子に限って、万引きなんてするはずがありません。<div>本日に限り、通常価格１００グラム1,500円の牛肉をl半額でご提供いたしております。<\\/div>\",\"3\"]', '', '2026-04-02 15:33:28'),
(113, '<div>~に限らず</div>', 'When you want to say \"not just ~, but also something else\".', '[名]＋に限らず', '[\"環境対策のためにも、夏<b>に限らず<\\/b>年間を通して節電を心がけるべきだ。\",\"「～だけでなく、他にも」と言いたい時に使う。\",\"Not only~but also~\",\"<img src=\\\"131876-425x282-whyconserveenergy.JPG\\\" \\/>\",\"ディズニ-ランドは子供に限らず、大人にも人気がある。\",\"72\"]', '', '2026-04-02 15:33:28'),
(114, '<div>~にかけては / ~にかけても</div>', 'Is used when you want to say that when it comes to \"the field / subject area of ~\", you have \"the highest level\", are \"confident\" or the like.', '[名]＋にかけては', '[\"日本酒造り<b>にかけては<\\/b>彼の右に出る者はいない。\",\"followed by a positive sentence\",\"「～の分野では」と範囲を限定して、その分野では「最高レベルだ」「自信がある」などと言いたいときに使われる。\",\"If (when) talking about ~ ; As far as~is concerned~\",\"<img src=\\\"making_sake.jpg\\\" \\/>\",\"数学にかけては、彼女はクラスでいつも一番だった。\",\"109\"]', '', '2026-04-02 15:33:28'),
(115, '<div>~にかわって / ~にかわり</div>', '1.&nbsp;In place of~<div>2.&nbsp;( By proxy~ )</div>', '[名]＋にかわって', '[\"1.&nbsp;ここでは、人間にかわってロボットが作業をしている。<div>2.&nbsp;父にかわって、私が結婚式に出席しました。<\\/div>\"]', '', '2026-04-02 15:33:28'),
(116, '<div>~に 関[かん]して(は) / ~にかんしても / ~に 関[かん]する</div>', 'When you introduce a topic or say what someone is investigating. This is often used in surveys, research, notifications and the like.', '[名]＋に関して<div>[名]＋に関する＋[名]</div>', '[\"計画変更<b>に関して<\\/b>、十分検討する必要がある。\",\"「～について」\",\"これはよりもっと硬い言葉\",\"「～について」と同じように、話題にしたり、調べたりする内容を言う時に使う。調査や研究、通知などでよく使う。\",\"About~\",\"<img src=\\\"paste-118545392336897.jpg\\\" \\/>\",\"<div><div>私は音楽に関しては門外漢だ。<\\/div><\\/div><div><div>その件に関して特に疑問はない。<\\/div><\\/div><div><div>それに関しては同意しかねます。<\\/div><\\/div><div><div>地球は赤道に関して対称ではない。<\\/div><\\/div>\",\"68\"]', '', '2026-04-02 15:33:28'),
(117, '<div>~に 比[くら]べ / ~に 比[くら]べて</div>', 'Use it when you want to compare two or more things and say how much they differ. It has the same meaning as \"～より\".', '[名]＋に比べて', '[\"いちごはレモン<b>に比べて<\\/b>、ビタミンCが多いんだって。ほんとかな？\",\"「～より」と同じ意味で、二つ以上の物を比較し、程度の違いを言いたい時に使う。\",\"Compare~ to~\",\"<img src=\\\"paste-13052405612545.jpg\\\" \\/>\",\"兄に比べて、弟はよく勉強する。\",\"50\"]', '', '2026-04-02 15:33:28'),
(118, '<div>~に 加[くわ]え / ~に 加[くわ]えて</div>', 'Means \"not only ~, but also\".', '[名]＋に加えて', '[\"優れたサッカー選手になるには、運動能力<b>に加えて<\\/b>、判断力や協調性が求められる。\",\"「～だけでなく、その上」という意味を表す。\",\"In addition to~\",\"<img src=\\\"paste-24459838750721.jpg\\\" \\/>\",\"電気代に加えて、ガス代まで値上がりした。\",\"136\"]', '', '2026-04-02 15:33:28'),
(119, '<div>~にこたえ / ~にこたえた / ~にこたえて / ~にこたえる</div>', 'Use it when you want to say \"according to another person\'s expectation or request\".', '[名]＋にこたえて<div>[名]＋にこたえた＋[名]</div><div>ご[名]＋におこたえて</div>', '[\"そのアイドルはコンサートの最後にアンコール<b>にこたえて<\\/b>もう1曲歌った。\",\"「相手からの期待や要請の通りに」と言いたいときに使う。\",\"In response to~ ; In reply to~\",\"<img src=\\\"paste-9998683865089.jpg\\\" \\/>\",\"社員の要求にこたえて、労働時間を短縮した。\",\"118\"]', '', '2026-04-02 15:33:28'),
(120, '<div>~に 際[さい]し / ~に 際[さい]して /　~に 際[さい]しての</div>', 'It is used in sentences such as warnings, apologies, explanations and the like.', '[動-辞書形 / 名]＋に際して', '[\"留学<b>に際して<\\/b>、先生や友人から励まし言葉をもらった。\",\"「~にあたって」\",\"注意やおわび、説明などの文に使われる。\",\"When starting~ ; When doing~\",\"<img src=\\\"my_wso_story_img_boys064b.jpg\\\" \\/>\",\"各種書類の提出に際しては、期限を厳守してください。\",\"7\"]', '', '2026-04-02 15:33:28'),
(121, '<div>~に 先立[さきだ]ち / ~に 先立[さきだ]て / ~に 先立[さきだ]つ</div>', 'Is used when you want to say \"something will be done before ~\".', '[名]＋に先立って・に先立ち<div>[名]＋に先立つ＋[名]</div>', '[\"レストランの開店<b>に先立って<\\/b>、試食会が開かれた。\",\"「～の前に、何かが行われる」と言いたいときに使われる。\",\"Before ~ ; Right before~\",\"<img src=\\\"paste-18674517803009.jpg\\\" \\/>\",\"映画の一般公開に先立って、主演女優のサイン会が開かれた。\",\"116\"]', '', '2026-04-02 15:33:28'),
(122, '<div>~にしたがい / ~にしたがって</div>', 'Use it when you want to say \"something else changes along with a change in ~\". You can also use it when you want to say \"in concert with ~\".', '[動-辞書形・名]＋にしたがって・にしたがい', '[\"暑くなる<b>にしたがって<\\/b>、体調を崩す人が増えた。\",\"「~とともに」；「~につれて」\",\"「～の変化に合わせて、他のことも変化する」と言いたい時に使う。「～に合わせて」と言いたい時にも使う。\",\"With~ ; Following~ ; As~ (when one the changes so does the other)\",\"<img src=\\\"humans-clipart-sick-15.jpg\\\" \\/>\",\"高く登るにしたがって、見晴らしがよくなった。\",\"65\"]', '', '2026-04-02 15:33:28'),
(123, '<div>~にしたら / ~にしても / ~にすれば</div>', 'For~ (from the position of)', '[名]＋にしたら', '[\"あの人にしたら、私達の親切はかえって迷惑かもしりません\"]', '', '2026-04-02 15:33:28'),
(124, '<div>~にしては</div>', 'When you want to say that something is \"different from what you would expect from ~\" as in \"小学1年生にしては背は高い\".', '[普通形-○]＋にしては', '[\"今人気のエリナはモデル<b>にしては<\\/b>背が高いほうではない。\",\"「～から予想することとは違う」と言いたい時に使う。\",\"[な形；名]don\'t use [だ]\",\"Although ; Even though\",\"<img src=\\\"BMTFp5jCYAACae0.jpg\\\" \\/>\",\"兄はアメリカに２０年いたにしては英語が下手だ。\",\"41\"]', '', '2026-04-02 15:33:28'),
(125, '~にしても / ~にしろ / ~に(も)せよ', 'Is used when you want to give examples from a category and say that \"not only ~ but all of them\" are something. It is also used with pairs of antonyms such as \"いい・悪い\", \"好き・嫌い\", \"する・しない\", and \"出席する・欠席する\" when you want to say that something could be applicable in either case.&nbsp;', '[普通形-○]＋にしろ・にしても・にせよ＋[普通形-○]＋にしろ・にしても・にせよ', '[\"東京<b>にしろ<\\/b>大阪<b>にしろ<\\/b>大都市には働く場所が多いので人が集まってくる。\",\"\\\"~にしろ\\\" can also be used only once in a sentence when used together with a question word.<div>「～にしろ」が、疑問詞と一緒に、一つだけで使われることもある。<\\/div>\",\"ある範囲内のものから例をあげて、「～だけでなくどれでも」と言いたいときに使われる。「いい・悪い」「好き・嫌い」「する・しない」「出席する・欠席する」など反対の意味の言葉を使って、どちらの場合でもと言いたいときにも使われる。\",\"[~である]can be used.\",\"Whenever~,&nbsp;Even if~\",\"<img src=\\\"238px-Tokyo_Tower_and_around_Skyscrapers.jpg\\\" \\/>\",\"<div>海外旅行中はどこに行くにしろ、パスポートを持って歩かなければならない。<\\/div>ビ-ルにしろ、日本酒にしろ飲んだら運転できない。<div>どんな人間にしろ長所はあるものだ。<\\/div>\",\"106\"]', '', '2026-04-02 15:33:28'),
(126, '<div>~にすぎない</div>', 'Is used when you want to explain that something is \"only ~\" as in \"合格率は８％にすぎない\". It is also often used when you think that something does not have much value.', '[動-辞書形・た形 / 名]＋にすぎない', '[\"この高校は2年前に男女共学になったが、男子学生はまだ10人<b>にすぎない<\\/b>。\",\"「ただ～だけだ」と説明したい時に使われる。あまり価値がないと思っているときにもよく使われる。\",\"Merely~ ; Only~ ; Just~ ; Be (do) nothing but~\",\"<img src=\\\"10678404-large.jpg\\\" \\/>\",\"わたしは警官としてしなければならないことをしたにすぎません。\",\"101\"]', '', '2026-04-02 15:33:28'),
(127, '<div>~に 沿[そ]い / ~に 沿[そ]う / ~に 沿[そ]った /　~に 沿[そ]って</div>', 'Is used to mean \"along\", \"in accordance with\" or \"as\".', '[名]＋に沿って<div>[名]＋に沿う・に沿った＋[名]</div>', '[\"二人は夕暮れの道を川<b>に沿って<\\/b>歩き続けた。\",\"「マニュアル・方針・案内・道順」などの言葉と一緒に使われる。<div>「希望・要望・意向・期待＋に沿うよう」などの言い方もある。<\\/div>\",\"「～の通りに」「～に合わせて」という意味で使われる。\",\"In accordance with~\",\"<img src=\\\"walk-down-malacca-river.jpg\\\" \\/>\",\"決まった方針に沿って、新しい計画を立てましょう。\",\"108\"]', '', '2026-04-02 15:33:28'),
(128, '~に 相違[そうい]ない', 'When you say that you are aboslutely sure or have no doubt about something.', '[普通形-○]＋に相違ない', '[\"そんな非常識な要求は認められないに<b>相違ない。<\\/b>\",\"～に違いない\",\"<div>In certificates the meaning becomes 「間違いない」<\\/div>\",\"「に違いない」と同じ意味がある。\",\"[な形・名] don\'t use [だ]\",\"It must be~\",\"<img src=\\\"paste-19378892439553.jpg\\\" \\/>\",\"今回の企業買収には裏で大物政治家の力が働いていたに相違ないと噂されている。\",\"110\"]', '', '2026-04-02 15:33:28'),
(129, '<div>~に 対[たい]し / ~に 対[たい]して(は) / ~に 対[たい]しても / ~に 対[たい]する</div>', 'When you talk about direct action toward another person or certain attitudes. You can also use it when you respond to or refuse / refute an opinion, problem or request / demand.', '[名]＋に対して<div>[名]＋に対する＋[名]</div>', '[\"お客様<b>に対して<\\/b>失礼なことを言ってはいけません。\",\"人に向かって直接働きかけをしたり、「やさしい」「失礼だ」といった態度を表す時に使う。意見・問題・要求に応えたり反対したりする時にも使う。\",\"<img src=\\\"paste-37151467110401.jpg\\\" \\/>\",\"彼女はだれに対しても親切です。<div>目上の人に対しては敬語を使いましょう。<\\/div><div>私費留学生に対する奨学金などの援助はまだ十分ではないと思う。<\\/div>\",\"22\"]', '', '2026-04-02 15:33:28'),
(130, '~に 違[ちが]いない', 'When you say that you are absolutely sure or have no doubt about something.', '[普通形-○]＋に違いない', '[\"鍵がない。どこかに落とした<b>に違いない。<\\/b>\",\"～相違ない\",\"絶対に、確かに～だと思うと言う時に使う。\",\"[な形・名] don\'t use [だ]\",\"There is no doubt of~\",\"<img src=\\\"hqdefault (2).jpg\\\" \\/>\",\"この絵をかくのに何百時間もかかったに違いないと思う。\",\"110\"]', '', '2026-04-02 15:33:28'),
(131, '<div>~について(は) / ~についての / ~についても / ~につき</div>', 'When you introduce a topic or say what someone is thinking about or investigating.', '[名]＋について ( は / も )<div>[名]＋についての＋[名]</div>', '[\"日本の経済<b>について<\\/b>研究しています。\",\"「～にかんして」\",\"話題にしたり、考えたり、調べたりする内容を言う時に使う。\",\"<img src=\\\"main.jpg\\\" \\/>\",\"<div><div>彼女は鳥についての本を買う。<\\/div><\\/div><div><div>流行についていくことはやめた。<\\/div><\\/div><div><div>私は日本について何も知らない。<\\/div><\\/div><div><div>私の留学について両親と話をした。<\\/div><\\/div>\",\"30\"]', '', '2026-04-02 15:33:28'),
(132, '<div>~につき</div>', 'This is used to state a reason in an announcement and the like.', '[名]＋につき', '[\"雨天<b>につき<\\/b>、試合は延期いたします。\",\"Slightly strong saying\",\"お知らせなどで理由を言う時に使われる。\",\"Because~\",\"<img src=\\\"article-2218748-1588EC9D000005DC-484_634x416.jpg\\\" \\/>\",\"清掃中につき、お足元にご注意ください。\",\"1\"]', '', '2026-04-02 15:33:28');
INSERT INTO `grammar_lessons` (`id`, `structure_name`, `meaning`, `usage_rules`, `examples`, `level`, `created_at`) VALUES
(133, '<div>~につけ / ~につけて(は) / ~についても</div>', 'Use it when you want to say \"(I always think・・・) when I see or hear something\".&nbsp;', '[動-辞書形]＋につけ', '[\"電車の中で走り回る子供たちを見る<b>につけ<\\/b>、家庭でしっかりしつけをしろと言いたくなる。\",\"「暑いにつけ寒いにつけ」のような慣用表現で「どんな時も」という気持ちを表すこともある。<div>As in \\\"暑いにつけ寒いにつけ\\\", you can also use it as an idiomatic expression to express a feeling of \\\"whatever\\\".<\\/div>\",\"「何かを見たり聞いたりするたびに（いつも・・・と思う）と言いたい時に使う。\",\"<div>何かにつけて<\\/div><div>何事につけても<\\/div><div>それにつけても<\\/div>\",\"At the end of the sentence, a verb showing one’s feeling will come　「~と思う」「という気持ちになる」\",\"whenever~\",\"<img src=\\\"children-playing-tag.jpg\\\" \\/>\",\"家族の写真を見るにつけ、会いたくてたまらなくなる。\",\"94\"]', '', '2026-04-02 15:33:28'),
(134, '<div>~につれ / ~につれて</div>', 'When you want to say \"something else changes along with a change in ~\".', '[動-辞書形・名]＋につれて・につれ', '[\"留学生活が長くなる<b>につれて<\\/b>、国のことを思い出すことが少なくなったような気がする。\",\"「~とともに」；「~にしたがって」\",\"「～」と一緒に変化することを表す。\",\"As~ ; With~ (when one the changes so does the other)\",\"<img src=\\\"20170905153911student-studyabroad-2_thumb.jpg\\\" \\/>\",\"品質がよくなるにつれて、値段が高くなる。\",\"65\"]', '', '2026-04-02 15:33:28'),
(135, '<div>~にとって(は) / ~にとっての / ~にとっても</div>', 'Whe you say how something is seen of percieved from the point of view of \"~\". This is followed by \"・・・\", using words that assess, such as 難しい、大切だ', '[名]＋にとって', '[\"この写真は私<b>にとって<\\/b>、何よりも大切なものです。\",\"You can not use words that express your attitude about a certain thing such as 「賛成、反対、好き、嫌い」\",\"「～」の立場から見てどうであるかを言う時に使う。「・・・」には「難しい、大切だ」などの評価を表す言葉が続く。\",\"For~ ; To~ (a judgment or assessment will follow this expression)\",\"<img src=\\\"watch-2.jpg\\\" \\/>\",\"今回の旅行は私にとって忘れない思い出なるだろ。\",\"56\"]', '', '2026-04-02 15:33:28'),
(136, '<div>~にともな伴い / ~に伴う / ~に伴って</div>', '<div>As~ ; With~ (accompanying, following something)</div>', '[動--辞書形；名]＋に伴って', '[\"人口が増えるに伴って、いろいろな問題が起こってきた。\"]', '', '2026-04-02 15:33:28'),
(137, '<div>~に 伴[ともな]い / ~に 伴[ともな]う / ~に 伴[ともな]って</div>', 'As in \"道路工事に伴う通行止め\", use it when the focus of the sentence (road construction) simultaneously produces a concurrent result (a closed road). You can also use it to express a change.', '[名]＋に伴って・に伴い<div>[名]＋に伴う＋[名]</div>', '[\"本州移転<b>に伴って<\\/b>、最新のコンピューターシステムが導入されることになった。\",\"中心になることと同時に、他の事も一緒に起きる時に使う。変化を表す時にも使う。\",\"With~ (happen at the same time)\",\"<img src=\\\"16b7618f03db2d3f60692b4e06722d36.jpg\\\" \\/>\",\"地震に伴って、火災が発生することが多い。\",\"33\"]', '', '2026-04-02 15:33:28'),
(138, '<div>~に 反[はん]し/ ~に 反[はん]した / ~に 反[はん]して / ~に 反[はん]する</div>', 'Use this when you want to say \"the result or situation has become opposite of what was predicted or expected\".', '[名]＋に反して・に反し<div>[名]＋に反する・に反した＋[名]</div>', '[\"今回の経済政策は国民の期待<b>に反して<\\/b>、まったく効果がなかった。\",\"「予想したことや期待したことと反対の結果や状態になった」と言いたくない時にも使う。\",\"Against~ ; Contrary to~\",\"<img src=\\\"BK-453213370X_3L.jpg\\\" \\/>\",\"神に意向に反して、人間は自然を破壊している。\",\"67\"]', '', '2026-04-02 15:33:28'),
(139, '<div>~にほかならない</div>', 'States that something \"is nothing other than ~\". It\'s used when you want to strongly say \"~ is the biggest reason / reason / important / a problem\".', '[名]＋にほかならない', '[\"今回のプロジェクトの成功は、チームワークの勝利<b>にほかなりません<\\/b>。\",\"「～以外の他の物ではない」ことを表す。「一番の理由・大切なこと・問題になることは～だ」と強く言いたいときに使われる。\",\"理由を表す「から・ため」にもつて、原因・理由・根拠を強調する言い方になる。<div>You can also say it with \\\"から・ため\\\", wich emphasizes a cause, reason or basis.<\\/div>\",\"There is no doubt that~\",\"<img src=\\\"paste-20173461389313.jpg\\\" \\/>\",\"この手紙は私の正直な気持ちを申し上げたにほかなりません。\",\"100\"]', '', '2026-04-02 15:33:28'),
(140, '<div>~にもかかわらず</div>', 'Means \"although / despite ~\". Use it when you mean that something is actually different form what one would expect from the situation.', '[動-て形-いる・た形 / い形 / 名]＋にもかかわらず<div>[な形 / 名]＋である＋にもかかわらず</div>', '[\"彼は熱がある<b>にもかかわらず<\\/b>、サッカーの試合に出場した。\",\"「～なのに」という意味で、その状態から予想することと実際が違うという意味で使う。<br>~を気にしないで~\",\"[な形；名]don\'t use [だ]。[~である]can be used.\",\"However~ ; Though~\",\"<img src=\\\"184451368.jpg\\\" \\/>\",\"彼の努力にもかかわらず、業績はよくならなかった。\",\"21\"]', '', '2026-04-02 15:33:28'),
(141, '<div>~に 基[もと]づいて / ~に 基[もと]づいた / ~に 基[もと]づき / ~に 基[もと]づく</div>', 'Use this when you mention something which was used as a basis or reference.', '[名]＋に＋基づいて・基づき<div>[名]＋に＋基づく・基づいた＋[名]</div><div>[名]＋を＋基に・基して</div>', '[\"集めた資料<b>に基づいて<\\/b>、論文を書いた。\",\"「~をもとに」\",\"基準や参考にしたものを言う時に使う。\",\"On the basis of~\",\"<img src=\\\"paste-27925877358593.jpg\\\" \\/>\",\"調査した資料に基づいて、レポ-トを書かなければならない。<div>ファンの人気投票をもとに審査し、今年の歌のベストテンが決まります。<\\/div>\",\"138\"]', '', '2026-04-02 15:33:28'),
(142, '~によって / &nbsp;~による', 'Expresses the means or method by which something is done.', '[名]＋によって<div>[名]＋による＋[名]</div>', '[\"問題は話し合い<b>によって<\\/b>解決した方がいい。\",\"何かを行う時の手段、方法を表す。\",\"<img src=\\\"72ddf405-a46c-4b42-bcb6-b844b3798cb6.jpg\\\" \\/>\",\"大学はアンケートによる満足度調査の結果を発表した。\",\"21\"]', '', '2026-04-02 15:33:28'),
(143, '<div>~によると / ~によれば</div>', 'When you want to say where you got some information from.', '[名]＋によると・によれば', '[\"今朝の新聞<b>によると<\\/b>、来年度、２つの大学が新設されるそうだ。\",\"情報を何で知ったかを言いたい時に使う。\",\"文の終わりは「～そうだ \\/ ～ということだ」などの形になる。\",\"<img src=\\\"paste-30210799960065.jpg\\\" \\/>\",\"最近の調査によれば、病気ではないが不健康な人は増えているそうだ。<div>今朝の天気予報によると、今週はずっと晴れるそうだ。<\\/div><div>観光ガイドブックによれば、この町では毎週日曜日に朝市が開かれるらしい。<\\/div>\",\"28\"]', '', '2026-04-02 15:33:28'),
(144, '<div>~にわたった / ~にわたって / ~にわたり / ~にわたる</div>', 'Use this to mean throughout a long length of time or wide areas as in \"1週間にわたって雨が降り続いた\" and \"高速道路は50キロにわたって渋滞している\".', '[名]＋にわたって・にわたり<div>[名]＋にわたる・にわたった＋[名]</div>', '[\"台風で電線が切れ、この町は全域<b>にわたって<\\/b>停電した。\",\"時間や場所の範囲全部でという意味で使う。\",\"Ranging from~ ; Covering~ ; Lasting~ ; Extending over~\",\"<img src=\\\"1527761151.jpg\\\" \\/>\",\"チンさんは病気のため、２ヶ月にわたって学校を休んだ。\",\"31\"]', '', '2026-04-02 15:33:28'),
(145, '~ぬきで (は) / ~ぬきに(は) / ~ぬきの / (~を)ぬきにして(は) / はぬきにして', 'When you describe a situation in which something usually found in something is not there, or when a person usually found somewhere is not there.', '[名]＋ぬきで', '[\"朝食<b>ぬきで<\\/b>会社へ行くサラリ-マンが多いらしい。\",\"普通はその中にあるものがなかったり、通常そこにいる人がいなかったりする状態を言う時に使う。\",\"Without~&nbsp;\",\"<img src=\\\"breakfast.jpg\\\" \\/>\",\"子供用にわさびぬきでお寿司を作ってもらった。\",\"112\"]', '', '2026-04-02 15:33:28'),
(146, '<div>~ぬく</div>', '\"I\'ll do my best to do ~ to the end, even if it\'s difficult.\". It can also express \"do ~ an extreme amount.\"', '[動-ます形]＋ぬく', '[\"途中、失敗もありましたが、なんとかこの仕事をやり<b>ぬく<\\/b>ことができました。\",\"「苦しくても最後まで頑張って～をする」という意味で使われる。なた、「非常に～する」という意味を表すこともある。\",\"Do (one’s best) till the end\",\"<img src=\\\"21-important-lessons-from-failure.jpg\\\" \\/>\",\"一度やると決めたからには、どんな困難があっても最後までやりぬく覚悟です。\",\"131\"]', '', '2026-04-02 15:33:28'),
(147, '<div>~のみならず</div>', 'Same meaning as [～だけでなく].', '[動/い形/名・の普通形-○]＋のみならず<div>[な形・名]＋である＋のみならず</div>', '[\"現在、日本のコンビニは若者<b>のみならず<\\/b>、あらゆる世代の人々に様々な目的で利用されている。\",\"「～だけでなく」と同じように使う。\",\"[な形；名]don\'t use [だ]. [~である]can be used.<div>「ただ～のみならず」「ひとり～のみならず」can be used.<\\/div>\",\"Not only~ but also ; Besides~ ; Moreover~\",\"<img src=\\\"CStore_Web.jpg\\\" \\/>\",\"このパソコンは性能が優れているのみならず、操作も簡単だ。\",\"63\"]', '', '2026-04-02 15:33:28'),
(148, '<div>~のもとで / ~のもとに</div>', 'When you want to say that something is \"under someone with some great influence\" as in \"教授のもと\", or when you want to say that something is \"under certain conditions or a situation\" as in \"協力のもと\"', '[名]＋のもとで', '[\"鈴木教授のご指導<b>のもとで<\\/b>、卒業論文を完成させた。\",\"「何か大きい影響力のある者の下で」という時や、「その条件や状況の中で」と言いたい時に使う。\",\"Owing to~\",\"<img src=\\\"ts_ronbun-eyecatch.jpg\\\" \\/>\",\"最近は明るい太陽のもとで、元気に遊び子供が少なくなった。\",\"11\"]', '', '2026-04-02 15:33:28'),
(149, '<div>~ばかりか / ~ばかりではなく / ~ばかりでなく</div>', 'Is used to mean \"not just A, but also B\".', '[名詞修飾型]＋ばかりでなく...も', '[\"林さんのお宅でごちそうになった<b>ばかりか<\\/b>、おみやげまでいただいた。\",\"「AだけでなくB(も)」という意味で使う。\",\"「名-の」does not use「の」&nbsp;\",\"Not Only~\",\"<img src=\\\"6510934443_8bd2942b79_b.jpg\\\" \\/>\",\"落語は最近、お年寄りばかりでなく若い女性にも人気が出てきた。\",\"59\"]', '', '2026-04-02 15:33:28'),
(150, '<div>~ばかりに</div>', 'When you want to say (\"It\'s unfortunate that things turned out badly) just because of ~\"', '[名詞修飾型]＋ばかりに<div>[な形 / 名]＋である＋ばかりに</div>', '[\"本当のことを言った<b>ばかりに<\\/b>、彼を怒らせてしまった。\",\"「～だけは原因で(悪い結果になってしまって残念だ)」と言いたい時に使う。\",\"[名-の] uses [名-な]\",\"Because of~ ; On account of~ (shows regret over the cause of some bad result)\",\"<img src=\\\"paste-12073153069057.jpg\\\" \\/>\",\"うそをついたばかりに恋人に嫌われてしまう。\",\"48\"]', '', '2026-04-02 15:33:28'),
(151, '<div>(~を)はじめ / (~を)はじめすると</div>', 'When you want to say \"not just ~, but many others\" by giving a typical example.', '[名]＋をはじめ<div>[名]＋をはじめとして</div><div>[名]＋をはじめとする＋[名]</div>', '[\"<div>上野動物園にはパンダを<b>はじめ<\\/b>、子供達に人気がある動物がたくさんいます。<\\/div>\",\"代表的な例を出して、「～だけでなく他にもたくさん」と言いたい時に使う。\",\"Not only~ but also~ ; ~among other things\",\"<img src=\\\"図1.jpg\\\" \\/>\",\"日本には富士山をはじめ、たくさんの美しい山がある。\",\"10\"]', '', '2026-04-02 15:33:28'),
(152, '<div>~はともかく(として)</div>', 'When you want to say that you are not thinking about \"~\" now, but about other things instead.', '[名]＋はともなく (として)', '[\"この洋服は、デザイン<b>はともなく<\\/b>、色がよくない。\",\"「～かどうか」「疑問詞+か」「動詞+か」と一緒に使うこともある。\",\"「～」については今は考えないで、他の点について言いたい時に使う。\",\"Regardless of~\",\"<img src=\\\"CHINAFASHION032409.jpg\\\" \\/>\",\"今の仕事は、給料はともかく、やりがいがあるいい仕事だと思っています。\",\"26\"]', '', '2026-04-02 15:33:28'),
(153, '<div>~ば~ほど</div>', 'When you say that the more one thing is done, the more something else will change accordingly', '[動-ば]＋[動-辞書形]＋ほど<div>[い形-ければ]＋[い形-い]＋ほど</div><div>[な形-なら・であらば]＋[な形-な・である]＋ほど</div><div>[名-なら・であらば]＋[名-である]＋ほど</div>', '[\"練習<b>すればするほど<\\/b>上手になります。\",\"1つの事柄の程度に合わせて別の事柄も変わると言う時に使う。\",\"The more~the more~(as one goes up, so does the other)\",\"<img src=\\\"440985-300x244.jpg\\\" \\/>\",\"言葉を勉強すればするほどその国への理解も深まると言われている。\",\"57\"]', '', '2026-04-02 15:33:28'),
(154, '<div>~はもちろん / ~はもとより</div>', 'When you want to explain in a speech, presentation or the like that \"~\" is obvious, or that it is not only \"~\" but also something more.', '[名]＋はもちろん<div>[名]＋はもとより</div>', '[\"この温泉は、日本人は<b>もとより<\\/b>、外国人にも大変人気があります。\",\"「~はもとより」is formal language\",\"スピーチ・プレゼンテーションなどで「～はもちろん、～だけでなくそのほかにも」と説明したい時に使う。\",\"Even~ ; Of course~\",\"<img src=\\\"2013012100020_1.jpg\\\" \\/>\",\"私が生まれた村は、電車はもちろん、バスも通っていない。\",\"12\"]', '', '2026-04-02 15:33:28'),
(155, '<div>~ 反面[はんめん] / ~ 半面[はんめん]</div>', 'Use this when you want to explain that there are two aspects or perspectives pertaining to something.', '[動/い形/な形]・の名詞修飾型＋反面・半面<div>[な形 / 名]＋である＋反面・半面</div>', '[\"来日前は留学に期待する<b>反面<\\/b>、不安も大きかった。\",\"[~である]can be used.\",\"あることに関して、二つの反対の面や視点があることを説明する時に使う。\",\"On one side~ ; On the other side~\",\"<img src=\\\"iStock-636831102.jpg\\\" \\/>\",\"この薬はよく効く反面、副作用がある。\",\"69\"]', '', '2026-04-02 15:33:28'),
(156, '<div>~べき / ~べきだ</div>', 'When you say that doing \"~\" is generally the natural thing or correct thing to do.', '[動-辞書形]＋べき', '[\"書く前に注意<b>すべき<\\/b>点を説明します。\",\"一般的に、～するのが当然だ、～するのが正しいと言う時に使う。\",\"「する」becomes 「すべき」\",\"Should~\",\"<img src=\\\"paste-137842680397825.jpg\\\" \\/>\",\"人にお金を借りたらすぐに返すべきだ。\",\"55\"]', '', '2026-04-02 15:33:28'),
(157, '<div>~べきではない</div>', 'When not doing \"~\" is the natural thing to do.', '[動-辞書形]＋べきではない', '[\"先生のお宅に、こんな夜中に電話する<b>べきではない<\\/b>\",\"If it\'s about other person\'s conduct, it has a stron meaning that says \\\"You must not do shuch a thing\\\"\",\"～しないのが当然だと言う時に使う。\",\"「する」becomes 「するべきではない」\",\"Shouldn’t~\",\"<img src=\\\"paste-138843407777793.jpg\\\" \\/>\",\"慣れない人は雪道で車の運転をするべきではないと思う。\",\"55\"]', '', '2026-04-02 15:33:28'),
(158, '<div>(~より)ほか(は)ない / ほかしかたがない</div>', 'When you say that given the current situation, only this approach (as expressed by \"~\") is available, or that this is the best. This expression is also often used to say something along the lines of \"it can\'t be helped\".', '[動-辞書形]＋ほかない', '[\"だれにも頼めないから、自分でやる<b>ほかはない。<\\/b>\",\"～しかない\",\"「～しかない」と同じように使う。\",\"Only~ ; just~ (there is no other way)\",\"<img src=\\\"new-10-things-to-do-by-yourself-2.jpeg\\\" \\/>\",\"天候不順で、山頂まで行くのはあきらめるほかない。\",\"88\"]', '', '2026-04-02 15:33:28'),
(159, '<div>~ほど / ~ほどだ / ~ほどの</div>', 'To describe the unusual condition or degree of 「・・・」 by using 「～」&nbsp;as an example.', '[動-辞書形・ます形-たい・ない形-ない / い形-い / な形-な / 名]＋ほど', '[\"会場にあふれる<b>ほど<\\/b>、ギターを持った若者が集まっていた。\",\"「・・・」の状態・程度が普通ではないことを、「～」の例を使って表す時に使う\",\"<img src=\\\"600guitarists.jpg\\\" \\/>\",\"<div>それほど簡単ではない。<\\/div><div><div>時間ほど大切な物はない。<\\/div><\\/div><div><div>私は昔ほど健康ではない。<\\/div><\\/div>\",\"7\"]', '', '2026-04-02 15:33:28'),
(160, '~ほど...はない', 'When you want to emphasize that \"~\" is the most \"・・・\".', '[動-辞書形-こと / 名]＋ほど…ない', '[\"仲のいい友達と旅行する<b>ほど<\\/b>楽しいこと<b>はない。<\\/b>\",\"~くらい\",\"「～」が一番・・・だと強調したいときに使う。\",\"Nothing is more~ than~\",\"<img src=\\\"220h44bedc860b4d20966bc364724ff14024.jpg\\\" \\/>\",\"夏は毎年暑いけど、今年ほど暑い夏はないんじゃないかなあ。\",\"111\"]', '', '2026-04-02 15:33:28'),
(161, '<div>~ほど</div>', '(as one thing changes, so does the other)', '[動-辞書形；い形-い；な形-な；名]＋ほど', '[\"相撲では、太っているほど有利だ。\"]', '', '2026-04-02 15:33:28'),
(162, '<div>~まい / ~まいか</div>', 'When you want to say that judging from a situation or the like, \"there\'s very little possibility of ~\".', '[動-辞書形]＋まい', '[\"世界経済は状況から見て、すぐに好転することはある<b>まい<\\/b>。我が社も早急に対策を考えなければならない。\",\"「絶対～するのはやめよう」という強く意志を表すこともある。<div>You can also use it to express a strong determination to \\\"absolutley stop doing ~\\\".<\\/div>\",\"状況などから判断して、「～の可能性は非常に少ないだろう」と言いたい時に使われる。\",\"Use 「~まいと思っているらしい \\/ ~まいと思っているようだ」when subject is Third Person.\",\"Probably not~;&nbsp;Will not~\",\"<img src=\\\"bad-economy.jpg\\\" \\/>\",\"あの小さな地震が続いている。大きい地震が起こるのではあるまいか。<div>こんなまずいレストランへは二度と来るまい。<\\/div>\",\"93\"]', '', '2026-04-02 15:33:28'),
(163, '<div>~む向きだ / ~向きに / ~向きの</div>', 'Suitable for~', '[名]＋向きだ', '[\"このスキ-場は初心向きです。\"]', '', '2026-04-02 15:33:28'),
(164, '<div>~ 向[む]けだ / ~ 向[む]けに / ~ 向[む]けの</div>', 'When you express that something is for a specific group or person.', '[名]＋向け', '[\"ここにある軽量のクリスマスカードは、みんな海外<b>向けだ<\\/b>。\",\"ある特定の人やグループのためのものだということを表す時に使う。\",\"Bound for~ ; Made for~\",\"<img src=\\\"mvn51103-1.jpg\\\" \\/>\",\"これは子供向けの映画だが、大人にも人気がある。\",\"82\"]', '', '2026-04-02 15:33:28'),
(165, '<div>~もかまわず</div>', 'Use it when you want to say \"do ・・・ while ignoring that this is something one would normally be concerned about\". It is often used to citicize.', '[名]＋もかまわず', '[\"住民の迷惑<b>もかまわず<\\/b>、夜中にバイクで走り回るのはやめてほしい。\",\"「普通は気にしたほうがいいことを、無視して・・・する」と言いたい時に使う。批判的に使うことが多い。\",\"ところかまわず: &nbsp;indiscriminately; no matter where\",\"Regardless of~\",\"<img src=\\\"paste-27453430956033.jpg\\\" \\/>\",\"人の迷惑もかまわらず、電車の中で携帯電話で話している人がいる。\",\"127\"]', '', '2026-04-02 15:33:28'),
(166, '<div>~も~なら~も / ~も~ば~も</div>', 'This is used with positive words to say there are many good points about something, or with negative words to say there are many bad points about something. It can also express variety as in \"家で食べる日もあれば外で食べる日もある\".', '[名]＋も＋[動-ば・い形-ければ・な形-なら]＋[名]＋も', '[\"今度できたスーパーは品数<b>も<\\/b>多<b>ければ<\\/b>値段<b>も<\\/b>安いので、大人気だ。\",\"プラスイメージの言葉を重ねて「よい点が多くある」と言う時と、マイナスイメージの言葉を重ねて、「悪い点が多くある」と言うときに使われる。「いろいろある」という意味を表すこともある。\",\"Neither~or~ ; Both~and~\",\"<img src=\\\"paste-37911676321793.jpg\\\" \\/>\",\"父はお酒も飲めばタバコも吸うので、健康が心配だ。\",\"130\"]', '', '2026-04-02 15:33:28'),
(167, '<div>~もので</div>', 'When giving a polite explanation to provide your reason for the current situation.', '[名詞修飾型・名-&gt;な]＋もので・ものですから', '[\"「一人で行ける。」「うん、大丈夫、地図を持っている<b>もの<\\/b>。」\",\"Used in conversations by women and children. &nbsp;「~もん」is more informal\",\"自分側の理由があって、今の状況なのだと丁寧に説明する時に使われる。\",\"sometimes conjugated with「です」「ます」\",\"Because~ (give a reason to an explanation).\",\"<img src=\\\"map-reading_2143007b.jpg\\\" \\/>\",\"慣れないものですから、ご迷惑をおかけするかもしれませんが、どうぞよろしくお願いいたします。\",\"65\"]', '', '2026-04-02 15:33:28'),
(168, '<div>~もの(です)か</div>', 'When you want to strongly state, to yourself or someone else, a feeling you have that \"it\'s definetly not ~\". You can also use it to refute what another person has said, as in \"it\'s absolutely not ~; ~ is wrong.\" In colloquial speech use \"～もんか\" or \"～もんですか\".', '[名詞修飾型]＋ものか/もんか・ものですか/もんですか', '[\"こんなサービスの悪い店には二度と来る<b>もんか<\\/b>。\",\"When spoken, or between friends 「~もんか」or「~もんですか」is used\",\"独り言なので、「決して～しない」と自分の気持ちを強く言いたい時に使う。相手の言ったことを、「絶対～ではない・～は違う」と否定する時にも使う。\",\"[名-の] uses [名-な]\",\"By no means~ ; Not~at all\",\"<img src=\\\"restaurant-frustration2-bad-service-390x220.jpg\\\" \\/>\",\"あの人が人の忠告なんか聞くものですか。\",\"51\"]', '', '2026-04-02 15:33:28'),
(169, '<div>~ものがある</div>', 'Use it when you want to say something \"seems ~\". This expression is used when something makes you think in a certain way, but you cannot say exactly what it is.', '[動/い形/な形]・の名詞修飾型＋ものがある', '[\"世界中で大ヒットした歌には、世代を超えて人々の心に響く<b>ものがある。<\\/b>\",\"「～感じがする」と言いたい時に使う。「具体的に何とは言えないが、そう思われる要素がある」と言う時にも使われる。\",\"現在形だけ\",\"Feel like~\",\"<img src=\\\"10d318fc54ea34a091477d5f55693620.png\\\" \\/>\",\"この絵には人を引きつけるものがある。\",\"92\"]', '', '2026-04-02 15:33:28'),
(170, '<div>~ものだ / ~ものではない</div>', 'A. show admiration ; grief ; a heart felt feeling<div>B.&nbsp;express something as common sense</div>', '[動・い形・な形]の名詞修飾型＋ものだ', '[\"A. あんな大事故にあって、よく助かったものだ。<div>B.&nbsp;地震のときは、だれでもあわてるものだ<\\/div>\"]', '', '2026-04-02 15:33:28'),
(173, '<div>~ものだから</div>', 'Because~ (give a reason(excuse)', '[動・い形・な形・名]の名詞修飾型＋ものだから', '[\"事故で電車が遅れたものだから、遅くなったすみません。\",\"[名-の] uses [名-である]\"]', '', '2026-04-02 15:33:28'),
(174, '<div>~ものなら</div>', 'Use this when you very much want something that you actually think is impossible.', '[動-辞書形]＋ものなら・もんなら', '[\"子供のころから星好きだったので、行ける<b>ものなら<\\/b>宇宙旅行に行ってみたいと思っています。\",\"可能の意味を待つ動詞の辞書形も使われる。<div>Dictionary forms of verbs that indicate possibility are also used.<\\/div>\",\"現実には無理だと思っていることを強く希望する時に使う。\",\"<div>会話では「もんなら」になる。<\\/div>It becomes \\\"もんなら\\\" in casual conversation.\",\"If~(wish for something unattainable ; tell someone it is impossible)\",\"<img src=\\\"paste-14663018348545.jpg\\\" \\/>\",\"父の病気が治るものなら、どんな高価な薬でも手に入れたい。\",\"122\"]', '', '2026-04-02 15:33:28'),
(175, '<div>~ものの</div>', 'When you really want to say you feel that \"even tough the fact is ~ (I wanted it and brought it),\" as in \"欲しくて買ったものの\". The particle 「は」 is often used to emphasize the fact.', '[動/い形/な形]・の名詞修飾型＋ものの<div>[な形 / 名]＋で(は)ある＋ものの</div>', '[\"水泳教室に通ってはいる<b>ものの<\\/b>、いまだに25メートルしか泳げない。\",\"「~とはいうものの」is often used. &nbsp;Especially with nouns [名＋とはいうものの]\",\"「～は事実だけれども」という気持ちを強く言いたい時に使う。事実を強調するために、助詞「は」を使うことが多い。\",\"「～ている・～てみる」などは「～て<u>は<\\/u>いる」のように「は」が入ることが多い。\",\"Though~\",\"<img src=\\\"carousel.jpg\\\" \\/>\",\"免許は取ったものの、車が買えない。\",\"39\"]', '', '2026-04-02 15:33:28'),
(176, '<div>~やら~やら</div>', '\"AやらBやら\" has the same meaning as \"AやBなど\" and \"AたりBたり\" by giving examples and expresses a sense of adversity or suprise for various reasons. It is also used to express that you are not quite sure which is the reason.', '[動-辞書形・い形-い・名]＋やら＋[動-辞書形・い形-い・名]＋やら', '[\"部屋代<b>やら<\\/b>、交通費<b>やら<\\/b>、日本はとにかくお金がかかる。\",\"「AやBなど」「AたりBたり」と同じ意味で、例をあげて、いろいろあって大変だったり驚いたりした気持ちを表す。どちらかはっきりわからないことを表す場合もある。\",\"~And~among other things (etc)\",\"<img src=\\\"enhanced-buzz-32397-1370986531-1.jpg\\\" \\/>\",\"帰国前は飛行機の予約をするやらおみやげを買うやらで忙しい。\",\"98\"]', '', '2026-04-02 15:33:28'),
(177, '<div>~ようがない / ~ようもない</div>', 'As in \"私も知らないから教えようがない\", use it when you want to say \"because of (I don\'t know either), I can\'t ~ (tell you).\" When you say it as \"どうしょうもない\", it means there is nothing you can do.', '[動-ます形]＋ようがない', '[\"出張の予定だったが、大雪で飛行機が欠航したしまったので行き<b>ようがない<\\/b>。\",\"「どうしょうもない」という言い方は、できることが何もないという意味。\",\"「理由があって～をすることができない」と言いたい時に使う。\",\"No way to~\",\"<img src=\\\"plane-snow-684987.jpg\\\" \\/>\",\"木村さんは今どこにいるのか分からないので、連絡しようがない。\",\"44\"]', '', '2026-04-02 15:33:28'),
(178, '<div>~ような / ~ように</div>', 'Like~ &lt;show an example&gt;', '[動-辞書形・た形・て形-いる / 名-の]＋ように+[動]・ような+[名]・ようだ', '[\"ここに書いてある<b>ように<\\/b>申込書に記入してください。\",\"「似ている」；「～っぽい」\",\"似ているものを言って、様子や状況を説明するときに使う。\",\"魚のように泳ぎたい。&lt;metaphor&gt;<div>かれは部屋にいないようです。&lt;a guess&gt;<\\/div>\",\"<img src=\\\"sinki_Omote.jpg\\\" \\/>\",\"<div>それは卵のように見える。<\\/div><div><div>彼女は教師のように見える。<\\/div><\\/div><div><div>彼はネズミのように臆病だ。<\\/div><\\/div><div><div>彼はいい奴のように見える。<\\/div><\\/div><div><div>彼の歯は真珠のように白い。<\\/div><\\/div>\",\"42\"]', '', '2026-04-02 15:33:28'),
(179, '<div>&nbsp;~ように</div>', 'So that~ &lt;show a goal(objective)&gt;', '[動-辞書形 / ない形-ない]＋ように', '[\"この本は小学生でも読める<b>ように<\\/b>ルビがつけてあります。\",\"何かをする目的がある時に使う\",\"<div>ここに、タバコを吸わないようにと書いてあります。&lt;indirect command&gt;<\\/div><div>自転車に乗れるようになりました。&lt;show change&gt;<\\/div>\",\"<img src=\\\"250px-Otvorena_knjiga.JPG\\\" \\/>\",\"<div>毎日運動するようにする。<\\/div><div><div>私は笑わないように努めた。<\\/div><\\/div><div><div>落ちないように注意しなさい。<\\/div><\\/div><div><div>私は暫く待つように言われた。<\\/div><\\/div>\"]', '', '2026-04-02 15:33:28'),
(180, '<div>~わけがない / ~わけはない</div>', 'When you want to strongly deny something because it is absolutely unthinkable.', '[名詞修飾型]＋わけがない', '[\"あんな下手な絵が売れる<b>わけがない。<\\/b>\",\"そんなことは絶対考えられないと、強く否定したい時に使う。\",\"Use 「ないわけがない」 when you say with confidence that \\\"~\\\" must be true.\",\"No reason for~\",\"<img src=\\\"I&#39;m%20Not%20Like%20Other%20Girls.jpg\\\" \\/>\",\"87\"]', '', '2026-04-02 15:33:28'),
(181, '<div>~わけだ</div>', 'As in \"開かないわけだ、鍵がかかっているよ\", use this when you come to understand that something is the case (it won\'t open) because of a certain reason (it\'s locked), as if to say \"ah ha\" or \"now I see\". When you don\'t know the reason, use \"というわけか\".', '[名詞修飾型]＋わけだ・というわけだ</div>', '[\"A: このチョコ、1粒1,000円もするんだよ。<div>B: え！本当？じゃあ、おいしい<b>わけ<\\/b>よね。<\\/div>\",\"思っていたことの理由がわかって「やっぱり」「なるほど」と納得した時に使う。\",\"state a reason why something is\",\"<img src=\\\"paste-35158602285057.jpg\\\" \\/>\",\"ジョンさんは、お母さんが日本人ですから、日本語が上手なわけです。\",\"82\"]', '', '2026-04-02 15:33:28'),
(182, '<div>~わけではない / ~わけでもない</div>', 'When you make a denial as in \"that\'s not the situation; it doesn\'t feel like that; not for that reason.\" Use it when you refute another person\'s idea or a typical judgament as in \"病気が治ったわけではない\". You can also use it when you do not want to say that something is 100% for sure, as in \"嫌いなわけではない\".', '[名詞修飾型]＋わけではない・わけじゃない', '[\"生活に困っている<b>わけではない<\\/b>が、貯金する余裕はない。\",\"「～の状況や気持ち・理由ではない」と否定する時に使う。相手の考えや一般的な判断を否定する時に使う。100％そうだと言いたくない時にも使う。\",\"It doesn’t mean that~\",\"<img src=\\\"Reckless-Spending-e1480501169757.jpg\\\" \\/>\",\"退院しても、病気が完全に治ったわけではありませんから、無理をしないでください。\",\"19\"]', '', '2026-04-02 15:33:28'),
(183, '<div>~わけにはいかない<br>~わけにもいかない</div>', 'When you want to say \"thare\'s a reason I can\'t\" as in \"休むわけにはいかない\".', '[動-辞書形]＋わけにはいかない', '[\"A: Bさん、顔色悪いよ。今日は無理しないで早退したら？<div>B: でも、午後から大事な会議があるから帰る<b>わけにはいかなくて<\\/b>・・・<\\/div>\",\"「理由があってできない」と言いたい時に使う。\",\"Mustn’t&nbsp;\",\"<img src=\\\"mlJxdgw.jpg\\\" \\/>\",\"絶対に他の人に言わないと約束したので、話すわけにはいかない。\",\"57\"]', '', '2026-04-02 15:33:28'),
(184, '<div>~わけにはいかない / ~わけにもいかない</div>', 'When you want to say \"I have to\" as in \"働かないわけにはいかない\".', '[動-ない形]＋ないわけにはいかない', '[\"A: 今から飛行機の予定は無理ですよ。<div>B: そこをなんとか。取引先でシステムトラブルがあって、私は行かない<b>わけにはいかない<\\/b>んですよ。<\\/div>\",\"「しなければならない」と言いたい時に使う。\",\"Must~\",\"<img src=\\\"123141-004-9B7F5072.jpg\\\" \\/>\",\"明日試験があるので、勉強しないわけにはいかない。\",\"57\"]', '', '2026-04-02 15:33:28'),
(185, '<div>わり(に)は</div>', 'Although~ ; In spite of~', '[普通形]＋わりに', '[\"私はたくさん食べるわりに太らない。\",\"「~にしては」\"]', '', '2026-04-02 15:33:28'),
(186, '<div>~をきっかけとして / ~をきっかけに(して)</div>', 'To express the factor or reason for why something happened that led to a new beginning or change.', '[名]＋をきっかけに', '[\"留学を<b>きっかけに<\\/b>、自分の国についていろいろ考えるようになった。\",\"何かが始まったり、変わったりしたときに、その原因・理由になった出来事を表す時に使う。\",\"Through~ ; By~ (something happens unexpectedly through a chance encounter)\",\"<img src=\\\"45ecc1eb7862661abf1eecd4b202cc4f_s.jpg\\\" \\/>\",\"日本のドラマをきっかけとして、日本文化に関心を持つようになった。\",\"17\"]', '', '2026-04-02 15:33:28'),
(187, '<div>~を 契機[けいき]として / ~を 契機[けいき]に(して)</div>', 'To express the factor or reason for why something socially or historically important happened that led to a new beginning or change. It\'s often used in sentences with a positive meaning.', '[名]＋を契機に', '[\"オイルショックを<b>契機に<\\/b>新エネルギ-の研究が進められた。\",\"「きっかけ」と同じ意味・用法で社会的、歴史的に大きいことを言いたい時に使う。プラスの意味の文に使うことが多い。\",\"Since~ (Because a thing happened, a big change has occurred)\",\"<img src=\\\"paste-56487409876993.jpg\\\" \\/>\",\"青木氏の社会就任を契機にして、我が社は大きく発展した。\",\"17\"]', '', '2026-04-02 15:33:28'),
(188, '<div>~を 込[こ]めて</div>', 'Use it to mean \"do ・・・with a lot of love, thought or the like.', '[名]＋を込めて', '[\"当店では一つ一つのお菓子を、心<b>を込めて<\\/b>手作りしております。\",\"「愛情、思いなどの気持ちを入れて（・・・する）」という意味で使う。\",\"「心・愛・親しみ・祈り・恨み・怒り」などの言葉と一緒に使われる。\",\"Full of~ ; Loaded with~ &lt;put emotion into&gt;\",\"<img src=\\\"paste-32706175959041.jpg\\\" \\/>\",\"母は私のために心をこめて、せ-タ-を編んでくれた。\",\"129\"]', '', '2026-04-02 15:33:28'),
(189, '<div>~をちゅうしん中心として / ~を中心に(して)</div>', 'Be (at) the center of ~ ; Be the focus of~&nbsp;', '[名]＋を中心に', '[\"駅を中心にたくさんの商店が集まってる。\"]', '', '2026-04-02 15:33:28'),
(190, '<div>~を 通[つう]じて / ~を 通[とお]して</div>', 'Use it on combination with words such as \"一年・四季・一生\" to say that something happened throughout that entire time.', '[時間の言葉]＋を＋通じて・通して', '[\"あの地方は、１年<b>を通じて<\\/b>雨が多い。\",\"その間ずっとと言いたい時、「一年・四季・一生」などの言葉と一緒に使う。\",\"Throughout~\",\"<img src=\\\"mawsynram-india.jpg\\\" \\/>\",\"京都は１年を通じてたくさんの観光客が訪れる。\",\"52\"]', '', '2026-04-02 15:33:28'),
(191, '<div>~を~とした / ~を~として / ~を~とする</div>', 'When you say \"do A as B; A is B\" as in \"地域交流を目的として\" and \"リーダーを中心に\". You can also use \"に\" in place of \"として\".', '[名]＋を＋[名]＋とした+[名]・とする・として/に', '[\"チンさんを先生<b>として<\\/b>、中国語の勉強会を開いた。\",\"Nouns that show aim, postion, role, type,etc. come before 「として」。例えば「目的・中心・対象・手本・前提」\",\"「AをBにする、AがBだ」と言う時に使う。\",\"As~\",\"<img src=\\\"20140801_003.jpg\\\" \\/>\",\"「みどりの会」は環境保護活動を目的とする市民の組織です。\",\"16\"]', '', '2026-04-02 15:33:28'),
(192, '~を 問[と]わず', 'This is used in an announcement, written introduction and the like to say \"anytime, anywhere, anyone\" and such.', '[名]＋を問わず', '[\"留学生ならどなたでも国籍、年齢、性別<b>を問わず<\\/b>申し込めます。\",\"「昼夜・国の内外・男女・～の有無」などの言葉と一緒につかわれる。\",\"お知らせや紹介文などで、「いつでも・どこでも・だれでも」などと説明したい時に使われる。\",\"「問う」という動詞の否定形として、文の最後で使うこともある。\",\"Regardless of~\",\"<img src=\\\"b4d462.jpg\\\" \\/>\",\"<div>この仕事に関心のある方なら、学歴・経験は問いません。<\\/div>このスポーツセンターは、年齢を問わず、どなたでも利用できます。\",\"2\"]', '', '2026-04-02 15:33:28'),
(193, '<div>~をめぐって / ~をめぐる</div>', 'Use it meaning \"about ~\", when you want to say that there is opposition, dispute, conflict, or opinions coming from various directions and positions about \"~\".', '[名]＋をめぐって<div>[名]＋をめぐる＋[名]</div>', '[\"<div>遺産<b>をめぐって<\\/b>、兄弟の争いが起こることを父は心配していた。<\\/div>\",\"「～を話題として」という意味で、「～」について様々な立場、方向から意見を述べたり、争い・紛争・対立などが起きていると言いたいときに使う。\",\"Circulate~ ; around~\",\"<img src=\\\"paste-13816909791233.jpg\\\" \\/>\",\"その法案の賛否をめぐって、活発な議論がかわされた。\",\"133\"]', '', '2026-04-02 15:33:28'),
(194, '～ 始[はじ]める', 'To clearly stathe the beginning of something that takes time.', '[動-ます形]＋始める', '[\"日本語を習い<b>始めた<\\/b>のは半年前です。\",\"時間がかかることが始めるということをはっきり言う時に使う\",\"<img src=\\\"learn-japanese.jpg\\\" \\/>\",\"<div>私達は歩き始めた。<\\/div><div><div>雷が鳴ると、雨が降り始めた。<\\/div><\\/div><div><div>そのりんごは腐り始めている。<\\/div><\\/div><div><div>僕は君を好きになり始めている。<\\/div><\\/div><div><div>彼は講演を始める前に咳払いをした。<\\/div><\\/div>\",\"1.1\"]', '', '2026-04-02 15:33:28'),
(195, '～ 終[お]わる', 'When you clearly state the end of something', '[動-ます形]＋終わる', '[\"その本、読み<b>終わったら<\\/b>貸してもらえませんか。\",\"終わることをはっきり言う時に使う\",\"<img src=\\\"toba2.gif\\\" \\/>\",\"<div>ちょうど昼ご飯を食べ終わった。<\\/div><div><div>彼が話し終わるとみんな黙っていた。<\\/div><\\/div><div><div>吸い終わったらすぐ部屋の中に入るなら問題ないですか？<\\/div><\\/div><div><div>こないだ貸した漫画、弟も読みたがってるから読み終わったら返してね。<\\/div><\\/div>\",\"1.2\"]', '', '2026-04-02 15:33:28'),
(196, '～ように 言[い]う', 'To tell about a command, prohibition, direction or advice given.', '[動-辞書形・ない形-ない]＋ように言う', '[\"先生に宿題を忘れない<b>ように注意された。<\\/b>\",\"「しろ・するな」「してください」「したほうがいい」\",\"「しろ・するな」「してください」「したほうがいい」などの命令・禁止・指示・助言の内容を伝える時に使う\",\"「言う」の代わりに「注意する」「頼む」「伝える」なども使われる\",\"<img src=\\\"paste-77622943940609.jpg\\\" \\/>\",\"<div>私は彼に来るように言った。<\\/div><div><div>私は暫く待つように言われた。<\\/div><\\/div><div><div>寝るように言ったはすだけど。<\\/div><\\/div><div><div>母は私に芝を刈るように言った。<\\/div><\\/div><div><div>両親は私に老人を敬うように言った。<\\/div><\\/div>\",\"2\"]', '', '2026-04-02 15:33:28'),
(197, '～という～', 'To describe something', '[普通形]＋という＋[名]', '[\"彼が有名な音楽家だ<b>という<\\/b>ことはあまり知られていない。\",\"内容を言うときによく使う\",\"<img src=\\\"57558876.jpg\\\" \\/>\",\"<div>罪を犯したという証拠は？<\\/div><div><div>これは何という花ですか？<\\/div><\\/div><div><div>幸福というのは何ですか。<\\/div><\\/div><div><div>両者は何という違いだろう。<\\/div><\\/div><div><div>物には限界というものがある。<\\/div><\\/div>\",\"3\"]', '', '2026-04-02 15:33:28'),
(198, '～だろうと 思[おも]う', 'To tell another person about something you think may be true, but you are not completly sure of.', '[普通形]-○＋だろうと思う', '[\"たぶんこの雨は1時間ぐらいでやむ<b>だろうと思います。<\\/b>\",\"はっきり分からないがたぶんそうだと考えた内容を他の人に伝える時に使う\",\"<img src=\\\"stock-footage-sad-young-girl-looking-out-the-window-on-a-rainy-day.jpg\\\" \\/>\",\"<div>彼は来るだろうと思う。<\\/div><div><div>彼女は難なく試験に通るだろうと思う。<\\/div><\\/div>\",\"4\"]', '', '2026-04-02 15:33:28'),
(199, '～なさそうだ', 'To gess that something is not \"～\" or or think so based on some observation or feeling.', '[い形-く / な形-じゃ / 名-じゃ]＋なさそうだ', '[\"このカレーはあまり辛く<b>なさそう<\\/b>ですね。\",\"「増えそうだ」などの動詞の場合は[動-ます形]＋「そうもない；そうにない；そうにもない」と言う。\",\"何かを見て感じたり、予想したり「～ではない」と思った時に使う\",\"<img src=\\\"Slow-cooked-spicy-chicken-square.jpg\\\" \\/>\",\"こんな難しそうな本、1週間では読めそうもない。<div><div>トムは興味がなさそうだった。<\\/div><\\/div><div><div>今のところ、解決の見込みはなさそうだ。<\\/div><\\/div>\",\"5\"]', '', '2026-04-02 15:33:28'),
(200, '～と', 'When you have noticed something you had not been aware of until that time.', '[動-辞書形]＋と', '[\"気がつく<b>と<\\/b>、外はすっかり暗くなっていた。\",\"「～たら」にも同じ使い方がある。\",\"今まで気づかなかった事に気づいた時に使う。\",\"意外に思ったことに使われることが多く、また「気づいたこと」なので文末は過去形になることが多い。\",\"<img src=\\\"nightdarkness.jpg\\\" \\/>\",\"待ち合わせの場所に着くと、友達はもう来ていた。<div>昔住んでいた所に行ってみると、大きいビルが建っていた。<\\/div><div>国から届いた荷物を開けると。大好きなお菓子が入っていた。<\\/div>\",\"6\"]', '', '2026-04-02 15:33:28'),
(201, '～ていく', 'To describe how the subject of the sentence will travel a long distance or to say that the subject will go to another place after taking certain action. You can also use it when you say that an action will continue into the future.', '[動-て形]＋いく', '[\"冬になると渡り鳥は南のほうへ飛<b>んでいく<\\/b>。\",\"反対に、近づく時は「～てくる」を使う。動作や変化が過去から今まで続いていることを言う時にも使う。\",\"ある動作をしながら遠くへ移動するときや、ある動作をしてから次の場所へ行くことを表すときに使う。将来に向かって続いていくことを言うときにも使う。\",\"<img src=\\\"pexels-photo-203088.jpeg\\\" \\/>\",\"じゃ、ジュース買ってきて。<div>これからも日本語の勉強を続けていくつもりです。<\\/div><div>これから、日本の会社でも外国人社員は増えていくと思います。<\\/div><div>申し込みの時に、身分証明書を持ってきてください。<\\/div>\",\"8\"]', '', '2026-04-02 15:33:28'),
(202, '～ 続[つつ]ける', 'When you say that an action is going on continuosly, or to emphasize the repetition of a habit or custom.', '[動-ます形]＋続ける', '[\"あの人は歯医者に１年以上通い<b>続けている<\\/b>そうです。\",\"動作をずっと続けることや習慣として繰り返すことを強調して言う時に使う。\",\"<img src=\\\"paste-11235634446337.jpg\\\" \\/>\",\"<div>彼は一日中歩き続けた。<\\/div><div><div>永遠に生き続ける者なし。<\\/div><\\/div><div><div>宇宙は無限に膨張し続けるのか？<\\/div><\\/div><div><div>彼女は３時間テレビを見続けている。<\\/div><\\/div><div><div>僕は働き続けるには疲れすぎていた。<\\/div><\\/div>\",\"9\"]', '', '2026-04-02 15:33:28'),
(203, '～なら', 'To set limits and to provide advice or make a suggestion.', '[動-辞書形(-の)・ます形-たい / 欲しい / 名]＋なら', '[\"N3に合格したい<b>なら<\\/b>、このカードをよく勉強したほうがいいよ。\",\"「～なら」の前に「の」（または「ん」）が入ることがありますが、ほとんど同じ意味です。\",\"「～の場合は」と範囲を検定して、アドバイスをしたり申し出をしたりするときに使う。\",\"<img src=\\\"paste-23648089931777.jpg\\\" \\/>\",\"<div>文句あるなら出て行け！<\\/div><div><div>トムが行くなら行く。<\\/div><\\/div><div><div>私ならそれを買います。<\\/div><\\/div>\",\"10\"]', '', '2026-04-02 15:33:28'),
(204, '～って', 'Use instead of &nbsp;「～という」 to give a name', '[名1]＋って＋[名2]', '[\"さっき、上田さん<b>って<\\/b>人が訪ねてきましたよ。お知り合いですか。\",\"名前を表す「～という」の代わりに使う。\",\"<img src=\\\"aid5254611-v4-728px-Stop-Thinking-About-Someone-Step-13.jpg\\\" \\/>\",\"<div>サンタさんって何人なの？<\\/div><div><div>里さんって文学が上手ですか。<\\/div><\\/div><div><div>田中さんって、まだ新婚ほやほやなんだって。<\\/div><\\/div><div><div>ねえ、鈴木さんって、幾つぐらいなんだろう。<\\/div><\\/div><div><div>ノリコさんって、なんていい人なの。<\\/div><\\/div>\",\"11\"]', '', '2026-04-02 15:33:28'),
(205, '～させてもらう&nbsp;/&nbsp;～させてくれる', 'When you obtain permission from another person to do something. You can also use it to express gratitude for receiving permission.', '[動-使役-て形]＋もらう', '[\"この会社は自分の意見を自由に<b>言わせてくれる。<\\/b>\",\"自分がすることのために他の人の許可を取る時に使う。許可してくれたことに感謝する時にも使う。\",\"<img src=\\\"colleagues-girl-discussing-joint-project-express-their-opinions-group-office-workers-partnership-gathered-table-89291053.jpg\\\" \\/>\",\"高校生の時、アルバイトをしたいと父にいったが、させてもらえなかった。<div>上司は何事も経験だと言って、私を海外研修に行かせてくれた。<\\/div><div>ここに荷物を置かせてもらってもいいですか。<\\/div>\",\"12\"]', '', '2026-04-02 15:33:28'),
(206, '～させられる', 'When another person tells you to do someting that you do not want to do, but you have to do it anyway.', '～[動-使役受身]', '[\"子供の時テストの成績が悪いと、父にトイレ掃除を<b>させられた。<\\/b>\",\"自分がしたくないと思っていることを、他人からするように言われて、しなければならない時に使う。\",\"<img src=\\\"woman-cleans-bathroom-toilet-scrub-260nw-426468376.jpg\\\" \\/>\",\"中学生の時、先生にグラウンドを何週を走らされた。<div>学生の時、いつも先輩に飲み物を買いに行かされた。<\\/div>\",\"13\"]', '', '2026-04-02 15:33:28'),
(207, '～がる', 'When a person\'s feelings or the like are expressed by his or her manner or speech.', '[動-たい形-○ / い形-○ / な形]＋がる', '[\"彼は試合に負けて悔し<b>がって<\\/b>いる。\",\"その人の気持ちなどが様子や言葉に表れている時に使う。自分の気持ちを言う時は使わないのが普通。\",\"「～がり」（「暑がり」「寒がり」「怖がり」など）は、よくそのように感じる人という意味の名詞になる。\",\"<img src=\\\"Abu_Dhabi_Tennis_Math.jpg\\\" \\/>\",\"<div>彼は海を怖がる。<\\/div><div><div>彼女は犬を怖がる。<\\/div><\\/div><div><div>彼女は何にでも首を突っ込みたがる。<\\/div><\\/div><div><div>何も恥ずかしがる必要はありません。<\\/div><\\/div><div><div>彼は怒ったときに立ち上がる癖がある。<\\/div><\\/div>\",\"14\"]', '', '2026-04-02 15:33:28'),
(208, '～ 出[だ]す', 'When something happens or starts suddenly', '[動-ます形]＋出す', '[\"さっきまで笑っていた赤ちゃんが急に泣き<b>出した。<\\/b>\",\"何かが急に起きた時や、急に始まったと言う時に使われる。\",\"<img src=\\\"crying-baby-kids-harbor.jpg\\\" \\/>\",\"突然大雨が降り出し、人々はあわてて建物の中に入った。<div>彼は短気で急に怒り出すから、付き合いにくい。<\\/div>\",\"16\"]', '', '2026-04-02 15:33:28'),
(209, '～ようとする', 'When you want to say that you are doing your best to do something or want to start doing so.', '[動-意向形]＋とする', '[\"小さい子供が道を渡ろう<b>として<\\/b>いるよ。一人でどこへ行くのかな。\",\"「～ようとしない」は相手が～しないことを批判する気持ちを表す。\",\"今から～しようと思う、～しようと頑張っていると言いたい時に使う。\",\"<img src=\\\"child-crossing-street.jpg\\\" \\/>\",\"生まれたばかりの馬の赤ちゃんが、一生懸命立とうとしている。<div>昔の友達の名前を思い出そうとしたが、どうしても思い出せない。<\\/div><div>リンさんは試験が近いのに、全然勉強しようとしない。<\\/div>\",\"17\"]', '', '2026-04-02 15:33:28'),
(210, '～ことがある', 'When you say that you sometimes or occasionally do something.', '[動-辞書形・ない形-ない]＋ことがある', '[\"この地方では4月でも雪が降る<b>ことがある<\\/b>。\",\"時々、またはたまに～すると言う時に使う。\",\"<img src=\\\"paste-21646635171841.jpg\\\" \\/>\",\"私の大学は横浜にもキャンパスがあって、時々そちらに行かなければならないことがあるんです。<div>普段はよく寝られるんですが、ストレスがたまって眠れないこともあります。<\\/div><div>あの店の営業時間は5時までですが、昼過ぎに全部売れてしまうこともあります。<\\/div>\",\"18\"]', '', '2026-04-02 15:33:28'),
(211, '～させておく', 'Indicates that someone has been instructed to keep performing some action. It can also say that you are not changing or interrupting someone\'s behavior, but instead, just leaving them as they are.', '[動-使役-て形]＋おく', '[\"夏に車の中で子供を<b>待たせておく<\\/b>のは危険ですよ。\",\"自分より下の人や動物に使うことが多い。\",\"相手に「～」の動作をずっと続けるよう指示することを表す。また、相手の行動を変えさせたりやめさせたりしないで、そのままにしておくことを表すこともある。\",\"<img src=\\\"kid-in-hot-car.jpg\\\" \\/>\",\"家事をしている間、子供をおもちゃで遊ばせておく。<div>息子は何を言っても聞かないので、自分のしたいことを勝手にさせておくことにした。<\\/div>\",\"19\"]', '', '2026-04-02 15:33:28'),
(212, '～られてしまう', 'When you think that an action by another person inconveniences you or is unfortunate.', '[動-受身-て形]＋しまう', '[\"片思いの彼を映画に誘ったが、<b>断られてしまった<\\/b>。\",\"他の人がしたことを迷惑だ、残念だと思う時に使う。\",\"<img src=\\\"paste-32207959752705.jpg\\\" \\/>\",\"後で食べようと思っていたケーキを妹に食べられてしまった。<div>ハイキングをしていたら、蜂に刺されてしまった。<\\/div><div>言葉が足りないと、誤解されてしまうことがある。<\\/div>\",\"20\"]', '', '2026-04-02 15:33:28'),
(213, '～ため (に)、 為[ため]に', 'When you say that 「～」 is the cause or reason.', '[名詞修飾型]＋ため', '[\"雨の<b>ために<\\/b>ハイキングは中止になりました。\",\"文末に「～たい・～つもりだ」などは使わない。\",\"～が原因、理由でと言うと時に使う。\",\"<img src=\\\"Raingear.jpg\\\" \\/>\",\"<div>彼は生活のために働く。<\\/div><div><div>列車は雪のために遅れた。<\\/div><\\/div><div><div>あなたのためにしました。<\\/div><\\/div>\",\"23\"]', '', '2026-04-02 15:33:28'),
(214, '～につき', 'As in the phrase&nbsp;「使用料は1時間につき1000円」, which means there is a charge of 1,000 yen per hour. In this case the rate is expressed as a number 「・・・」（1000円）, which accrues for every unit of 「～」 （1時間）.', '[名]＋につき', '[\"当スポーツクラブ会員以外の方でも、1回<b>につき<\\/b>2,000円で施設をご利用いただけます。\",\"「使用料は1時間につき1000円」のように「～」の数の単位（1時間）で「・・・」の数（1000円）と言う時などに使う。\",\"<img src=\\\"blog20170418.jpg\\\" \\/>\",\"１ページにつき、３枚ずつコピーして下さい。<div>今回のチャリティーコンサートは、ハガキ1枚につき2名様までお申し込みいただけます。<\\/div><div>ランニングマシンは予約制で、ご利用はお一人につき30分までとなっております。<\\/div>\",\"24\"]', '', '2026-04-02 15:33:28'),
(215, '～を 通[とお]して / ～を 通[とお]じて', 'Says that rather than doing something directly, an action was taken by way of another person, means or thing.', '[名]＋を＋通して・通じて', '[\"現在はインターネット<b>を通して<\\/b>、すぐに世界にニュースが広まる。\",\"直接ではなく、人、手段、物事が間に入って何かをすることを表す。\",\"<img src=\\\"news-YourStory.jpg\\\" \\/>\",\"私たちは読書を通して色々な人の考え方を知ることができます。<div>取材は、弁護士を通して申し込んでください。<\\/div><div>私は海外留学の経験を通じて多くのことを学んだ。<\\/div>\",\"26\"]', '', '2026-04-02 15:33:28'),
(216, '~によって / ~によっては / ~により / ~による', 'When you say that something differs depending on the person, place, time, or the like.', '[名]＋によって<div>[名]＋による＋[名]</div>', '[\"習慣は国<b>によって<\\/b>違う。\",\"人や場所、時間などに対応してそれぞれ違うと言う時に使う。\",\"By~ ; Depending on~ (show differences)<div>By~ ; Depending on~ (For a certain condition \\/ occasion)<\\/div>\",\"<img src=\\\"03427BB194ED9559FCF95B6140FE9050141DE4F0C83806CB25pimgpsh_fullsize_distr-750x300.jpg\\\" \\/>\",\"この薬は人<b>によって<\\/b>は副作用が出ることがあります。\",\"83\"]', '', '2026-04-02 15:33:28'),
(217, '～のような / ～のように', 'When you give a typical example.', '[名]＋のように<div>[名]＋のような＋[名]</div><div>[名]＋みたい</div>', '[\"インフルエンザ<b>のような<\\/b>他の人にうつる病気になったら、治るまで学校へ来てはいけないことになっています。\",\"友達の会話では「～みたい」も使う。\",\"代表的な例をあげる時に使う。\",\"<img src=\\\"kazoku-inhuruenza.jpg\\\" \\/>\",\"我々のようなプロのスポーツ選手には食事も練習と同じぐらい大切です。<div>梅雨のように雨の多い季節は洗濯物が乾かなくて困ります。<\\/div><div>体力がないので、テニスのように激しいスポーツはできません。<\\/div>\",\"27\"]', '', '2026-04-02 15:33:28'),
(218, '~ということだ、～とのことだ', 'It means that', '[普通形]＋ということだ / とのことだ', '[\"ご意見がないということは賛成ということですね。\"]', '', '2026-04-02 15:33:28'),
(219, '~っけ', 'When you confirm something you do not fully know about or something you heard but forget about.', '[普通形 / 丁寧形]＋っけ', '[\"クリーニング店、何時までだ<b>っけ<\\/b>。\",\"はっきり分からないことや聞いたのに忘れてしまったことを確認する時にも使う。\",\"過去に知ったことは、現在、未来のことでも過去形を使うことがある。\",\"<img src=\\\"main (1).jpg\\\" \\/>\",\"そのケーキ、どうしたの？今日、誰の誕生日だっけ。<div>今度のテスト、来週の月曜日だったっけ。<\\/div><div>高橋さん、昨日のパーティーにいらっしゃいましたっけ。<\\/div>\",\"33\"]', '', '2026-04-02 15:33:28'),
(220, '~たりして', 'Perhaps or maybe', '[普通形の過去]＋りして', '[\"もしかして寝ていた<b>りして<\\/b>。\",\"「～もしかしたら」という意味を表す。\",\"<img src=\\\"paste-145337398329345.jpg\\\" \\/>\",\"すごく高かったりして<div>芸能人だったりして<\\/div>\",\"34\"]', '', '2026-04-02 15:33:28'),
(221, '~たって', 'It means the same as 「～でも」 (even if~)', '[動-た形・ない形-ない-○ / い形-○-くた・い形-○-くなくた / な形-だ・な形-じゃなくた / 名-だ・名-じゃなくた]＋って', '[\"お金持ち<b>だって<\\/b>、幸せじゃない人もいます。\",\"「～でも」と同じ意味で使う。\",\"<img src=\\\"sad-rich-man.jpg\\\" \\/>\",\"<div><div>病院に行ったって、すぐには治らないよ。<\\/div><div>悲しくたって、寂しくたって絶対泣かない。<\\/div><div>まだ若いので、一晩ぐらい寝なくたって大丈夫です。<\\/div><\\/div>\",\"35\"]', '', '2026-04-02 15:33:28'),
(222, '~に 決[き]まっている', 'When you want to stress that you are absolutely sure of something&nbsp;', '[普通形]-○＋に決まっている', '[\"あのチームは今年も最下位<b>に決まってる<\\/b>よ。\",\"Mostly used in speaking\",\"「絶対～だと思う」と強く言う時に使う。\",\"[な形・名] don\'t use [だ]\",\"<img src=\\\"DSC03711.jpg\\\" \\/>\",\"<div>全然練習していないんだから、今度の試合は負けるにきまっている。<\\/div><div>嘘に決まってるじゃん！<\\/div><div><div>テレビを見ながら宿題なんて、そんなのダメに決まってるでしょ。<\\/div><\\/div><div><div>分かってないなあ。そんなこと言ったら女の子は傷つくに決まってんじゃん。<\\/div><\\/div>\",\"36\"]', '', '2026-04-02 15:33:28'),
(223, '~じゃない', 'When you want to confirm that the listener also knows the same thing or has te same opinion as you. Also used to reproach or to talk about a discovery. Does not contain negative meaning.', '[普通形]＋じゃない', '[\"レストランABK、広くて、交通の便もいい<b>じゃない<\\/b>。\",\"「～じゃん」の形も同じように使われる。\",\"聞き手も知っていると思うことや同じ意見だと思うことを確認する時に使う。避難や発見の意味表すこともある。否定の意味はない。\",\"<img src=\\\"201212310853203a1.jpg\\\" \\/>\",\"駅前に新しいコンビニができたじゃないですか。<div>ためじゃない。<\\/div>\",\"37\"]', '', '2026-04-02 15:33:28'),
(224, '~みたい', 'To state the speaker\'s speculation, as in 「～よう」.', '[普通形]-○＋みたい', '[\"なんか、疲れた<b>みたい<\\/b>だけど、仕事忙しいの？\",\"話し手の推量を表す「～よう」の意味で使う。\",\"[な形・名] don\'t use [だ]\",\"<img src=\\\"6098-1.jpg\\\" \\/>\",\"雪みたい。<div><div>彼の話し方は、女みたいだ。<\\/div><\\/div><div><div>トムは退屈しているみたい。<\\/div><\\/div><div><div>息をしていないみたいだ・・・<\\/div><\\/div>\",\"39\"]', '', '2026-04-02 15:33:28'),
(225, '~ばよかった', 'When you regret a bad result due to you not taking an action, or when another person\'s inaction is unfortunate.', '[普通形-ば]＋よかった', '[\"カメラを持ってくれ<b>ばよかった<\\/b>ね。\",\"自分が～しなかったから悪い結果になったことを後悔したり、他の人がしなかったことを残念に思った時に使う。\",\"<img src=\\\"hqdefault (1).jpg\\\" \\/>\",\"<div>半袖で来ればよかった。<\\/div><div><div>電話すればよかったのに。<\\/div><\\/div><div><div>黙ってればよかったのに。<\\/div><\\/div><div><div>傘持ってくればよかった。<\\/div><\\/div><div><div>トムのアドバイスに従っておけばよかった。<\\/div><\\/div>\",\"40\"]', '', '2026-04-02 15:33:28'),
(226, '~ばかり', 'to express criticism of only doing ~ or of doing it too much because it causes a problem', '[動-て形 / 名]＋ばかり', '[\"最近雨<b>ばかり<\\/b>で、洗濯物が乾かなくて困っています。\",\"～一方\",\"～が多くて困る、～以外のことをしないから困ると批判的に言う時に使う。\",\"[動-て形]＋ばかりいると[動-て形・て形-いる]＋ばかりの形も使われる。\",\"<img src=\\\"paste-25396141621249.jpg\\\" \\/>\",\"ゲームばかりしていると、目が悪くなりますよ。<div>逃げてばかりじゃ勝てないぞ。攻めていけ！<\\/div><div>あの子はいたずら好きで、みんなを困らせてばかりいる。<\\/div>\",\"41\"]', '', '2026-04-02 15:33:28'),
(227, '~をつう通じて / ~をとお通して', '<div>Via~ ; Through~</div>', '[名]＋を通じて', '[\"<div>社長は忙しいから、秘書を通じて頼んだほうがいい。<\\/div>\"]', '', '2026-04-02 15:33:28'),
(229, '1611', '招く', 'まねく', '[\"invite, beckon, engage\",\"verb\",\"I invited my parents for a meal. \\/ I invited my parents to a meal.\",\"招[まね]きます\",\"両親[りょうしん]を 食事[しょくじ]に<b> 招[まね]いた<\\/b>。\",\"okurigana\",\"[sound:1169V.mp3]\",\"[sound:1169S.mp3]\",\"<img src=\\\"1169.jpg\\\" \\/>\",\"招く\",\"2\",\"1kh\",\"怠惰[たいだ]は 失敗[しっぱい]を 招[まね]く。 Idleness leads to failure.<br> 戦争[せんそう]は 必[かなら]ず 不幸[ふこう]を 招[まね]く。 War necessarily causes unhappiness.<br> 黒[くろ] 猫[ねこ]は 悪運[あくうん]を 招[まね]きます。 Black cats are bad luck.<br> 僕[ぼく]の 行動[こうどう]は 非難[ひなん]を 招[まね]いた。 My act incurred a blame.<br> 彼[かれ]らは 自[みずか]ら 困難[こんなん]を 招[まね]いた。 They brought trouble on themselves.<br>パーティーには 誰[だれ]が 招[まね]かれますか。 Who was invited to the party?<br> 彼[かれ]は 私[わたし]を 家[いえ]に 招[まね]いた。 He invited me to his house.<br> 私[わたし]は 友達[ともだち]を 夕食[ゆうしょく]にまねいた。 I invited my friends to dinner.<br> 私[わたし]は 友人[ゆうじん]をみんな 招[まね]いた。 I\'ve invited all my friends.<br> 旧友[きゅうゆう]がレセプションに 招[まね]かれた。 Old friends were invited to the reception.\",\"1611\",\"2933\",\"1612\",\"beckon\",\"3\",\"両親 【りょうしん】  (n) parents; both parents <br>食事 【しょくじ】  (n) (1) meal; (vs) (2) to eat <br>(plain, past)<br>招く 【まねく】  (v5k,vt) to invite\"]', '', '2026-04-02 15:33:28'),
(232, '~つつ / ~つつも', 'As in \"タバコは体に悪いからやめようよと思いつつも、つい吸ってしまう\", it expresses the feeling that \"altougth ~ (I tought I should quit), something undesired actually happened (I smoked)\".', '[動-ます形]＋つつも', '[\"チョコレートを食べたらにきびが増えると知り<b>つつも<\\/b>、つい手が伸びてしまうんです。\",\"Not used in conversations.\",\"「〜だけれども、実際はよくないことをしてしまう」という気持ちを表す。\",\"~Though\",\"<img src=\\\"does-chocolate-give-pimples.jpg\\\" \\/>\",\"悪いと知りつつ、うそをついてしました。\",\"112\"]', '', '2026-04-02 15:33:28'),
(233, '~わけだ', 'Use this when you want to explain a reason or circumstances about something and say that it is a matter of course.', '[名詞修飾型]＋わけだ・というわけだ', '[\"食生活の改善と適度な運動によって免疫力が高まり、病気にかかりにくくなる<b>わけです。<\\/b>\",\"理由や事情を説明して「当然そうなる」と言いたいときに使う。\",\"It means that\",\"<img src=\\\"paste-20263655702529.jpg\\\" \\/>\",\"５パ-セントの値引きというと、１万円の物は9,500円になるわけですね。\",\"134\"]', '', '2026-04-02 15:33:28'),
(467, '~あげく(に)', '<b>In the end; finally; on top of all that; to make matters worse.</b><br><br><b>[JP]:</b> 長い時間がかかったり、いろいろしたりして大変だった後で、どうなったかという結果を言いたい時に使う。よくない結果になったことを言うことが多い。<br><b>[EN]:</b> Use this when you want to say how something turned out after a tough experience that took a lot of time or involved various efforts. It is often used to say that the result is not good.<br><img src=\"Fitting-room-etiquette.jpg\" />', '[動-た形・名-の]＋あげく(に)', '[\"さっきにお客さん、あれこれ試着した<b>あげくに<\\/b>、何も買わずに帰っちゃって・・・。\",\"長い時間がかかったり、いろいろしたりして大変だった後で、どうなったかという結果を言いたい時に使う。よくない結果になったことを言うことが多い。\"]', 'N2', '2026-04-02 16:01:07'),
(468, '~あまり', '<b>Do ~ so much as to ~</b><br><br><b>[JP]:</b> 「非常に～で（・・・の結果になった）と言いたい時に使う。よくない結果の時に使うことが多い。<br><b>[EN]:</b> When you want to say that someone \"did ・・・ an extreme amount, which resulted in ~\". It is often used when the result is not good.<br><img src=\"think-1034159_960_720.jpg\" />', '[動-辞書形・た形 / な形-な / 名-の]＋あまり', '[\"子どもの将来を思う<b>あまり<\\/b>、厳しすぎることを言ってしまった。\",\"「非常に～で（・・・の結果になった）と言いたい時に使う。よくない結果の時に使うことが多い。\"]', 'N2', '2026-04-02 16:01:07'),
(469, '~ 以上[いじょう](は)', '<b>Since</b><br><br><b>[JP]:</b> 「～からには」と同じ意味がある。2<br><b>[EN]:</b> When you want to say, with strong emotion, something like \"it\'s natural because ~ is decided / a fact; something should be done; you intend to do something; when you order someone to do something.\"<br><img src=\"paste-24962349924353.jpg\" />', '[普通形]＋以上', '[\"日本に住んでいる<b>以上<\\/b>、日本の法律を守らなければならない。\",\"~からには、~上は\",\"often followed by obligations, prohibitions, demands, presumptions, and strong conclusions such as [なければならない \\/　てはいけない　\\/ てください　 \\/ だろう]\",\"「～からには」と同じ意味がある。2\",\"[な形 \\/ 名] use [である]\"]', 'N2', '2026-04-02 16:01:07'),
(470, '~ 一方[いっぽう] / ~ 一方[いっぽう]では', '<b>While; Meanwhile (shows a comparison between two things)</b><br><br><b>[JP]:</b> 一つのことに関して、大きく違う状況があることを説明する時に使う。<br><b>[EN]:</b> Use this when you explain that one thing can be in very different situations, as in \"行列ができる店がある一方、まったく客が入らない店もある\".<br><img src=\"Job-hunt-confidence-blog.jpg\" />', '[名詞修飾型]＋一方<div>[な形 / 名]＋である＋一方</div>', '[\"仕事を求めて都会に出る若者がいる<b>一方<\\/b>、故郷に戻って就職する若者もいる。\",\"一つのことに関して、大きく違う状況があることを説明する時に使う。\",\"[な形 \\/ 名]場合は [である]も使われる。\"]', 'N2', '2026-04-02 16:01:07'),
(471, '~ 一方[いっぽう]だ', '<b>(no specific meaning) shows something continuing towards a certain tendency.　ex. more and more; less and less; keep on~; never stop~</b><br><br><b>[JP]:</b> 「～の状態がどんどん進んでいく」と言いたい時に使う。<br><b>[EN]:</b> Use it when you want to say that \"situation ~ is going to continue\" as in \"景気が悪くなる一方だ\".<br><img src=\"20180908-035557203.jpg\" />', '[動-辞書形]＋一方だ', '[\"ここは静かな町だったのに、テレビで紹介されて以来、観光的が増える<b>一方だ。<\\/b>\",\"～ばかり\",\"Uses verbs that show \\/ express a change\",\"「～の状態がどんどん進んでいく」と言いたい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(472, '~上で(は) / ~上での / ~上でも / ~上の', '<b>After...ing ; Upon…ing</b><br><br><b>[JP]:</b> 「～してから」と同じ意味で使う。ただし、日常的な話題には使わない。<br><b>[EN]:</b> Has the same meaning as \"～してから\" but don\'t use it to talk about a familiar topic.<br><img src=\"paste-22806276341761.jpg\" />', '[動-た形 / 名-の]＋上で<div>[動-た形 / 名-の]＋上(で)の＋[名]</div>', '[\"駅前の再開発については、住民の皆さんの意見をまとめた<b>上で<\\/b>、市に要望書を提出したいと思います。\",\"「～してから」と同じ意味で使う。ただし、日常的な話題には使わない。\"]', 'N2', '2026-04-02 16:01:07'),
(473, '~上は', '<b>Now that~; Since~</b><br><br><b>[JP]:</b> 「～からには」と同じ意味がある。1<br><b>[EN]:</b> When you want to say, with strong emotion, something like \"it\'s natural because ~ is decided / a fact; something should be done; you intend to do something; when you order someone to do something.\"<br><img src=\"730aca369b236619be67b7115be5a576e0006663.jpg\" />', '[動-辞書形・た形]＋上は', '[\"約束を結ぶ<b>上は<\\/b>、条件を慎重に検討すべきである。\",\"~ 以上、~からには\",\"「～からには」と同じ意味がある。1\"]', 'N2', '2026-04-02 16:01:07'),
(474, '~うちに / ~ないうちに', '<b>While~ &lt; do something before the condition changes &gt;</b><br><br><b>[JP]:</b> ある変化が起きる前に、何かをしたほうがいい・したい・してくださいなどと言う時に使う。<br><b>[EN]:</b> When you say that something should be done, you want to do something, or when you ask someone to do something, or the like, before a certain change occurs.<br><img src=\"shutterstock_367163339.jpg\" />', '[動-ない形-ない・て形-いる / い形-い / な形-な / 名-の]＋うちに', '[\"日本にいる<b>うちに<\\/b>、一度京都を訪ねたいと思っている。\",\"ある変化が起きる前に、何かをしたほうがいい・したい・してくださいなどと言う時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(475, '~ 得[え]る;&nbsp;~ 得[う]る', '<b>Be possible to~</b><br><br><b>[JP]:</b> 「～ができる・可能性がある」と言う時に使う。論文などでよく使う。<br><b>[EN]:</b> When you say \"there is a possibility that I can ~\". This is often used in essays and the like.<br><img src=\"315DC85D00000578-3454380-image-a-111_1455883339863.jpg\" />', '[動-ます形]＋得る', '[\"凶器がどこにあるか、考え<b>得る<\\/b>場所はすべて捜したが全く手がかりがつかめなかった。\",\"「～ができる・可能性がある」と言う時に使う。論文などでよく使う。\"]', 'N2', '2026-04-02 16:01:07'),
(476, '~得ない', '<b>Be impossible to~</b><br><br><b>[JP]:</b> 「～できない・可能性がない」と言う時に使う。論文などでよく使う。<br><b>[EN]:</b> Use it to say \"I can\'t ~; there\'s no possibility\". This is often used in essays and the like.<br><img src=\"nasa-space-station.jpg\" />', '[動-ます形]＋得ない', '[\"普通の人が宇宙へ行ける日が来るなんて、100年前には想像し<b>得なかった<\\/b>ことだ。\",\"「～できない・可能性がない」と言う時に使う。論文などでよく使う。\"]', 'N2', '2026-04-02 16:01:07'),
(477, '~おかげだ / ~おかげで', '<b></b><br><br><b>[JP]:</b> 「～」が原因でいい結果になって、感謝や「よかった」という気持ちを言う時に使う<br><b>[EN]:</b> Thanks to~; Owing to~; Because of~　(express thanks to the result of a good outcome)<br><img src=\"paste-70334384439297.jpg\" />', '[名詞修飾型]＋おかげで', '[\"科学技術が発達した<b>おかげで<\\/b>、我々の生活は便利になった。\",\"「～」が原因でいい結果になって、感謝や「よかった」という気持ちを言う時に使う\",\"おかげさまで: Thanks to you or some higher power\"]', 'N3', '2026-04-02 16:01:07'),
(478, '~おそれがある', '<b>Be in danger of~</b><br><br><b>[JP]:</b> 客観的なデータなどを基にして、危険な状態になる可能性が高いことを伝える時に使う。ニュースや新聞、報告書などに使われることが多い。<br><b>[EN]:</b> When you say that there is a high lokehood that -based on objective data or the like- the situation will become dangerous or otherwise undesirable. It is often used in news shows, newspapers, reports and the like.<br><img src=\"Volcano-eruption-817605.jpg\" />', '[動-辞書形・ない形-ない / 名-の]＋おそれがある', '[\"噴火の<b>恐れがあります<\\/b>ので、避難してください。\",\"客観的なデータなどを基にして、危険な状態になる可能性が高いことを伝える時に使う。ニュースや新聞、報告書などに使われることが多い。\"]', 'N2', '2026-04-02 16:01:07'),
(479, '~かけだ / ~かけの / ~かける', '<b></b><br><br><b>[JP]:</b> 何かをし始めて、まだ終わっていない状態だと言う時に使う。<br><b>[EN]:</b> When you say that you have started something and are not finished with it yet.<br><img src=\"3bc5d84174ccaba22a75d7dec7c0c01c_t.jpeg\" />', '[動-ます形]＋かけだ', '[\"この仕事はやり<b>かけ<\\/b>ですから、そのままにしておいてください。\",\"Unfinished ; Half~ (ex. half eaten, half finished)&nbsp;\",\"何かをし始めて、まだ終わっていない状態だと言う時に使う。\"]', 'N3', '2026-04-02 16:01:07');
INSERT INTO `grammar_lessons` (`id`, `structure_name`, `meaning`, `usage_rules`, `examples`, `level`, `created_at`) VALUES
(480, '~がたい', '<b>Can’t do~ ; Difficult to~</b><br><br><b>[JP]:</b> 「～するのは難しい、なかなか～することができない」という意味で使う。<br><b>[EN]:</b> It means \"doing ~ is difficult; probably can\'t do ~\".<br><img src=\"paste-24464133718017.jpg\" />', '[動-ます形]＋がたい', '[\"この条件では、鈴木商事からの合併の申し出は受け入れ<b>がたい。<\\/b>\",\"「～するのは難しい、なかなか～することができない」という意味で使う。\",\"「信じる・理解する・納得する・認める・得る・許す・忘れる」などの言葉と一緒に使われる。\"]', 'N2', '2026-04-02 16:01:07'),
(481, '~がちだ / ~がちの', '<b>Tend to~</b><br><br><b>[JP]:</b> 「～になることが多い」と言いたいときに使う。状態、様子を表す慣用的な言い方もある。<br><b>[EN]:</b> When you want to say that someone \"often does / is ~\" as in \"忘れがち・病気がち\". There is also an ideomatic usage to express a state or appereance.<br><img src=\"misunderstanding-1.jpg\" />', '[動-ます形 / 名]＋がち', '[\"日本人は自分の意思をはっきり言わないので誤解され<b>がち<\\/b>だ。\",\"Used mostly with a negative meaning\",\"「～になることが多い」と言いたいときに使う。状態、様子を表す慣用的な言い方もある。\",\"「休む・思う・考える・心配する・留守」などの言葉と一緒に使われる。\"]', 'N2', '2026-04-02 16:01:07'),
(482, '~かと思うと / ~かと思ったら', '<b>As soon as~</b><br><br><b>[JP]:</b> 状況が急に変わったことを強調して説明するときに使う。自分のことを説明するときには使わない。<br><b>[EN]:</b> Use this when you emphasize that a situation has suddenly changed. Do not use it to explain about yourself.<br><img src=\"8 (1).jpg\" />', '[動-た形]＋かと思うと・かと思ったら', '[\"青空を飛んでいた鳥は突然海に潜った<b>かと思うと<\\/b>、魚を口にくわえて出てきた。\",\"状況が急に変わったことを強調して説明するときに使う。自分のことを説明するときには使わない。\"]', 'N2', '2026-04-02 16:01:07'),
(483, '~か~ないかのうちに', '<b>No sooner than~</b><br><br><b>[JP]:</b> 「～の動作が完全に完了しないくらい短い時間の間に」と言いたい時に使う。<br><b>[EN]:</b> When you want to say \"during the short time in which the action ~ is not completly finished\".<br><img src=\"paste-38633230827521.jpg\" />', '[動-辞書形 / た形]＋か＋[動-ない形]＋ないかのうちに', '[\"早食い選手権を見ていたら、選手たちは食べ物を口に入れた<b>か<\\/b>入れ<b>ないかのうちに<\\/b>、次の料理に手を伸ばしていた。\",\"「～の動作が完全に完了しないくらい短い時間の間に」と言いたい時に使う。\",\"同じ動詞を使う。\"]', 'N2', '2026-04-02 16:01:07'),
(484, '<div>~かねない</div>', '<b>Be capable of~ ; Be in danger of~ (Used when there is a chance of something bad happening)</b><br><br><b>[JP]:</b> 「今の状況から判断すると、悪い結果が予想される」と言いたい時に使う。客観的に見るとという判断が入っていることが多い。<br><b>[EN]:</b> When you want to say that \"judging from the current situation, a bad result is expected\". It often includes a judgament based on an objective view.<br><img src=\"ford_2035210c.jpg\" />', '[動-ます形]＋かねない', '[\"あんなスピードを出したら、事故を起こし<b>かねない<\\/b>。\",\"「今の状況から判断すると、悪い結果が予想される」と言いたい時に使う。客観的に見るとという判断が入っていることが多い。\"]', 'N2', '2026-04-02 16:01:07'),
(485, '<div>~かのようだ / ~かのような / ~かのように</div>', '<b>Like~</b><br><br><b>[JP]:</b> 実際はそうではないのにそのように感じると言う時に使う。<br><b>[EN]:</b> When you say that it seems like something that is not actually true.<br><img src=\"rain-room-at-moma-10-1-680x365.jpg\" />', '[普通形]＋かのようだ<div>[な形 / 名]＋である＋かのようだ</div>', '[\"激しい雨と風は、まるで台風が来た<b>かのようだ。<\\/b>\",\"実際はそうではないのにそのように感じると言う時に使う。\",\"[な形 \\/ 名] can use [である]\"]', 'N3', '2026-04-02 16:01:07'),
(486, '~からといって', '<b>Just because~&nbsp;</b><br><br><b>[JP]:</b> 「～」だけの理由で、「・・・」をするのはよくない、できない、すると困ったことになるなどと言う時に使う。批判、助言、意見などを言う時に使うことが多い。<br><b>[EN]:</b> When you say that just because of \"~\", doing \"・・・\" is not good, not doable, will cause problem, or the like. This expression is often used when giving criticism, advice, warning, etc.<br><img src=\"sad-rich-man.jpg\" />', '[普通形]＋からといって', '[\"お金がある<b>からといって<\\/b>偉いわけではない。\",\"～だからといって\",\"Often the sentence will be negative.\",\"「～」だけの理由で、「・・・」をするのはよくない、できない、すると困ったことになるなどと言う時に使う。批判、助言、意見などを言う時に使うことが多い。\"]', 'N3', '2026-04-02 16:01:07'),
(487, '~から~にかけて', '<b>From~to~</b><br><br><b>[JP]:</b> AからBまでの間という意味で、時間や場所のだいたいの範囲を言う時に使う。<br><b>[EN]:</b> When you say that something is within a broad period of time or area between A and B as in \"今週から来週にかけて雨の日が多い\" and \"渋谷から新宿にかけてたくさんの専門学校がある\".<br><img src=\"20110822000301.jpg\" />', '[名]＋から＋[名]＋にかけて', '[\"本日、九州<b>から<\\/b>四国地方<b>にかけて<\\/b>、梅雨入りしました。\",\"AからBまでの間という意味で、時間や場所のだいたいの範囲を言う時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(488, '~からには / ~からは&nbsp;', '<b>Now that~ ; Since~</b><br><br><b>[JP]:</b> 「～は決めたこと・事実なのだから当然・・・するべきだ・するつもりだ・しろ」などの強い気持ちを言いたい時に使う。<br><b>[EN]:</b> When you want to say, with strong emotion, something like \"it\'s natural because ~ is decided / a fact; something should be done; you intend to do something; when you order someone to do something.\"<br><img src=\"INDIAN_WOMEN_2715677f.jpg\" />', '[普通形・な形/名+である]＋からには・というからには', '[\"試合に出る<b>からには<\\/b>、勝ちたい。\",\"~ 以上、~上は\",\"followed by obligations, resolutions, presumptions, suggestions, and commands\",\"「～は決めたこと・事実なのだから当然・・・するべきだ・するつもりだ・しろ」などの強い気持ちを言いたい時に使う。\",\"[な形 \\/ 名] use [である]\"]', 'N2', '2026-04-02 16:01:07'),
(489, '~から見て(も) / ~から見ると / ~から見れば', '<b>From the viewpoint of~;&nbsp;Judging from~ ; When it comes to~; As for~</b><br><br><b>[JP]:</b> 「～」の立場、視点、判断材料から考えたことを言う時に使う。<br><b>[EN]:</b> When you state an idea based on a position, perspective or criterion of \"~\" as in \"専門家から見ると\", \"価格の面から見ると\" and \"データから見て\".<br><img src=\"10593121.jpg\" />', '[名]＋から見ると・から見れば・から見て<div>[名]＋からいうと・からいえば・からいって</div><div>[名]＋からすると・からすれば・からして</div>', '[\"便利さという点<b>から見ると<\\/b>、やはり田舎より都会のほうが暮らしやすい。\",\"「～からいうと」、「～からすると」\",\"「～」の立場、視点、判断材料から考えたことを言う時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(490, '<div>~かわりに</div>', '<b></b><br><br><b>[JP]:</b> 他の人がする、他の物を使う、他の事をすると言う時に使う。交換条件などを表す時にも使われる。<br><b>[EN]:</b> When another person will do something, another object will be used, or another action will be taken. This expression is also often used to discuss thing such as terms for an exchange.<br><img src=\"paste-35755602739201.jpg\" />', '[動-辞書形・た形・ない形-ない / 名-の]＋かわりに', '[\"音楽会に行く<b>かわりに<\\/b>、ＣＤを３枚買うほうがいいと思う。\",\"他の人がする、他の物を使う、他の事をすると言う時に使う。交換条件などを表す時にも使われる。\"]', 'N3', '2026-04-02 16:01:07'),
(491, '~ 気味[ぎみ]', '<b>Rather~ ; A little~</b><br><br><b>[JP]:</b> 今の状態は少し～の感じがすると言いたい時に使う。<br><b>[EN]:</b> When you say that the current situation seems somewhat \"~\"<br><img src=\"paste-19301583028225.jpg\" />', '[動-ます形 / 名]＋気味', '[\"仕事が忙しくて、最近少し疲れ<b>気味<\\/b>だ。\",\"今の状態は少し～の感じがすると言いたい時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(492, '<div>~きり</div>', '<b>(something continuing the same condition after happening)</b><br><br><b>[JP]:</b> 「～の後はそのままだ」と言いたい時に使う。<br><b>[EN]:</b> As in \"友人とは2年前に別れたきり、会っていない\", when you want to say \"things have been the same (we haven\'t met) since then (after we parted).<br><img src=\"keep-quiet.jpg\" />', '[動-た形]＋きり', '[\"彼は「ごはん」と言った<b>きり<\\/b>、黙ってしまった。\",\"<div>In spoken language becomes 「~っきり」<\\/div>\",\"「～の後はそのままだ」と言いたい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(493, '<div>~きる / ~きれない/ ~きれる</div>', '<b>Do(be) completely~ / Be unable to do till the end / Be able to do till the end</b><br><br><b>[JP]:</b> 全部～する、最後まで～すると言う時に使われる。反対は多すぎて全部～できない、完全には～できないという意味で使う。<br><b>[EN]:</b> Used to say that something is all done or to the end. The negative means that the amount of a task is too great to do all of or to complete.<br><img src=\"paste-26650272071681.jpg\" />', '[動-ます形]＋きる', '[\"木村さんは疲れ<b>きった<\\/b>顔をして帰って来た。\",\"全部～する、最後まで～すると言う時に使われる。反対は多すぎて全部～できない、完全には～できないという意味で使う。\",\"In conbinations with certain words, you can also make standard expressions to say something is very \\\"~\\\".\"]', 'N3', '2026-04-02 16:01:07'),
(494, '~くらい(だ) / ~ぐらい(だ)', '<b>To the extent that~ ; As~as~ ; To the point that</b><br><br><b>[JP]:</b> 状態が普通ではないことを表す時に使う。<br><b>[EN]:</b> When you say that the situation is not normal.<br><img src=\"jishin_shirou_illust09.png\" />', '[動-辞書形・ない形-ない / い形-い / な形-な / 名]＋くらい・ぐらい', '[\"棚から物が落ちる<b>くらい<\\/b>地震があった。\",\"～ほど\",\"状態が普通ではないことを表す時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(495, '<div>~げ</div>', '<b>Seem~</b><br><br><b>[JP]:</b> 「～そうだ」と同じように、見て感じた印象を言う時に使われる。気持ちを表す言葉と一緒に使われることが多い。<br><b>[EN]:</b> Like \"～そうだ\", it is used when you state an impression from what you see and feel. It is often used together with words that express emotions.<br><img src=\"paste-43361989820417.jpg\" />', '[い形-○・な形-○]＋げ', '[\"プロジェクトメンバーは、誇らし<b>げ<\\/b>な表情で成功したことを報告した。\",\"~げ becomes a な形容詞\",\"「～そうだ」と同じように、見て感じた印象を言う時に使われる。気持ちを表す言葉と一緒に使われることが多い。\"]', 'N2', '2026-04-02 16:01:07'),
(496, '<div>~ことか</div>', '<b>I wonder ; quite ; surely</b><br><br><b>[JP]:</b> 自分がこれまでしてきたことや感じていることについて、気持ちを込めて言う時に使われる。「どんなに・どれだけ・どれほど」などの言葉と一緒に、独り言として言うことが多い。<br><b>[EN]:</b> Use this when you say with emotion what you have done or felt up to now. It is often said to oneself together with words such as \"どんなに・どれだけ・どれほど\".<br><img src=\"view_1369409911.jpg\" />', '[動/い形/な形]・の名詞修飾型＋ことか<div>[な形 / 名]＋である＋ことか</div>', '[\"人は私のことを頭がいいと言うけど、この試験に合格するために、どれだけ勉強した<b>ことか<\\/b>。私の努力は誰も知らないでしょうね。\",\"自分がこれまでしてきたことや感じていることについて、気持ちを込めて言う時に使われる。「どんなに・どれだけ・どれほど」などの言葉と一緒に、独り言として言うことが多い。\"]', 'N2', '2026-04-02 16:01:07'),
(497, '<div>~ことから</div>', '<b>Because~ (tells why something is)&nbsp;</b><br><br><b>[JP]:</b> 物や土地はその名前になった理由や、何かを判断した理由やそうなった原因を言いたい時に使う。<br><b>[EN]:</b> When you want to give the reason for why a thing or land got its name, why a judgament was made, or the factors behind why something came to be true.<br><img src=\"beni-1.jpg\" />', '[動/い形/な形]・の名詞修飾型＋ことから<div>[な形 / 名]＋である＋ことから</div>', '[\"このサツマイモは中が赤い<b>ことから<\\/b>、紅イモと呼ばれています。\",\"物や土地はその名前になった理由や、何かを判断した理由やそうなった原因を言いたい時に使う。\",\"[名]uses [である]、[な形]sometimes uses[である]\"]', 'N2', '2026-04-02 16:01:07'),
(498, '<div>~ことだ</div>', '<b>When you want to tell someone that something has importance</b><br><br><b>[JP]:</b> 「～すべきだ、～したほうがいい」という話者の判断を表す。アドバイスに使われることが多い。<br><b>[EN]:</b> Expresses the judgament of the speaker, as in \"you should ~; you ought to ~\". It\'s often used to give advice.<br><img src=\"nutritionist-500x366-300x220.jpg\" />', '[動-辞書形 / ない形-ない]＋ことだ', '[\"仕事でもなんでも自分一人で悩まないで誰かに相談する<b>ことです<\\/b>よ。\",\"「～すべきだ、～したほうがいい」という話者の判断を表す。アドバイスに使われることが多い。\"]', 'N2', '2026-04-02 16:01:07'),
(499, '<div>~ことなく</div>', '<b>Without~</b><br><br><b>[JP]:</b> 何かをしない状態で後ろの動作が続いたり、完了したりする時に使う。<br><b>[EN]:</b> When something happens or is completed even though some action has not been done, as in \"休むことなく働き続けている\".<br><img src=\"paste-15530601742337.jpg\" />', '[動-辞書形]＋ことなく', '[\"ロボットは２４時間休む<b>ことなく<\\/b>働いている。\",\"何かをしない状態で後ろの動作が続いたり、完了したりする時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(500, '<div>~ことに(は)</div>', '<b>To my~ (strengthens the speakers feeling ex. To my surprise)</b><br><br><b>[JP]:</b> 話者の気持ち、感情を強く表したい時に使う。<br><b>[EN]:</b> Use this expression when you say something like \"困ったことにお金がなかった\" in reverse order, like \"I didn\'t have money and it was a problem\", and you want to express a feeling or emotion.<br><img src=\"2-dozen-roses-brought.jpg\" />', '[動-た形・い形-い・な形-な]＋ことに', '[\"ホテルの部屋に入ったら、驚いた<b>ことに<\\/b>、バラの花束とホテルマネージャーからの歓迎メッセージがテーブルの上に置いてあった。\",\"話者の気持ち、感情を強く表したい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(501, '<div>~ことはない</div>', '<b>No need to ~</b><br><br><b>[JP]:</b> 「～する必要はない・～しなくてもいい」と言いたい時に使う。アドバイスに使うことが多い。<br><b>[EN]:</b> When you want to say \"there\'s no need to do ~; you don\'t have to do ~\". It is often used to give advice.<br><img src=\"aid18166-v4-728px-Apologize-Step-19-Version-2.jpg\" />', '[動-辞書形]＋ことはない・こともない', '[\"君が謝る<b>ことはない<\\/b>よ。悪いのは向こうなんだから。\",\"「～する必要はない・～しなくてもいい」と言いたい時に使う。アドバイスに使うことが多い。\"]', 'N2', '2026-04-02 16:01:07'),
(502, '<div>~ 際[さい](は) / ~ 際[さい]に</div>', '<b>When~ ; Upon~</b><br><br><b>[JP]:</b> 「～場合」という意味で、説明書や案内などで使われる。後ろに「してください・必要です・お願いします」などの文が来ることが多い。<br><b>[EN]:</b> Used in manuals, guides and the like to mean \"if / when ~\". Phrases such as \"してください・必要です・お願いします\" often come afterward.<br><img src=\"lost-credit-card-wallet1.jpg\" />', '[動-辞書形・た形 / 名-の]＋際(に)', '[\"カードを紛失した<b>際は<\\/b>カード会社にすぐ知らさせなければならない。\",\"「～場合」という意味で、説明書や案内などで使われる。後ろに「してください・必要です・お願いします」などの文が来ることが多い。\"]', 'N2', '2026-04-02 16:01:07'),
(503, '~ 最中[さいちゅう]だ / ~ 最中[さいちゅう]に', '<b>In the midst of~ ; During ~</b><br><br><b>[JP]:</b> 何かをしている、ちょうどその時に、思っていなかったことが起きた時に使われる。邪魔されたくない状況の時によく使われる。<br><b>[EN]:</b> When something unexpected happens just as you were doing something else. This expression is often used in situations when you do not want to be bothered.<br><img src=\"serious-man-thinking_1149-1328.jpg\" />', '[動-ている / 名-の]＋最中に', '[\"考えている<b>最中に<\\/b>、話をかけられて困った。\",\"何かをしている、ちょうどその時に、思っていなかったことが起きた時に使われる。邪魔されたくない状況の時によく使われる。\"]', 'N3', '2026-04-02 16:01:07'),
(504, '<div>~さえ / (~で)さえ</div>', '<b>Even~　&lt;one example is an extreme conditon, and everything that follows is a needless to say&gt;</b><br><br><b>[JP]:</b> 極端な例を出して、強調したい時に使う。<br><b>[EN]:</b> When you want to emphasize something by giving an extreme example. The negative form is often used after this expression.<br><img src=\"Japan-Off-Grid-Cabin01.jpg\">', '[名]＋[助詞]＋さえ<div>[動-て形]＋さえ</div>', '[\"そこは電気<b>さえ<\\/b>ない山奥だ。\",\"when さえ is connected to a noun, the particles　は、 が and を are omitted.\",\"極端な例を出して、強調したい時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(505, '<div>~さえ~ば</div>', '<b>If only~</b><br><br><b>[JP]:</b> 「～だけが必要な条件だ」と言いたい時に使う。<br><b>[EN]:</b> When you want to say \"~ is the only necesary condition\" as in \"給料さえよければどんな仕事でもいい\".<br><img src=\"paste-19520626360321.jpg\" />', '[名]＋さえ＋[普通形-ば]<div>[動-ます形]＋さえ＋すれば・しなければ</div><div>[い形-く・な形で・名-で]＋さえ＋あれば・なければ</div>', '[\"食べられ<b>さえすれば<\\/b>、味は問わないよ。\",\"「～だけが必要な条件だ」と言いたい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(506, '<div>~ざるを 得[え]ない</div>', '<b>Can’t help thinking~</b><br><br><b>[JP]:</b> 状況から、「嫌だが～しなければならない・～するしかない」と言いたい時に使う。<br><b>[EN]:</b> When you want to say \"I don\'t like it, but I have to / there\'s nothing else I can do.\"<br><img src=\"0206.gif\" />', '[動-ない形]＋ざるを得ない', '[\"みんなで決めた規則だから、守ら<b>ざるを得ない<\\/b>。\",\"状況から、「嫌だが～しなければならない・～するしかない」と言いたい時に使う。\",\"[する] becomes 「せざる得ない」\"]', 'N2', '2026-04-02 16:01:07'),
(507, '<div>~しかない</div>', '<b><!--anki-->Have no other way but~ / Must~</b><br><br><b>[JP]:</b> 今の状況ではこれ以外に方法がない、これが一番いいと言う時に使う。仕方がないという気持ちで使うことも多い。<br><b>[EN]:</b> When you say that given the current situation, only this approach (as expressed by \"~\") is available, or that this is the best. This expression is also often used to say something along the lines of \"it can\'t be helped\".<br><img src=\"160909114434-09-spain-train-crash-exlarge-169.jpg\" />', '[動-辞書形 / 名]＋しかない', '[\"事故で電車が動かないから、歩いて行く<b>しかない。<\\/b>\",\"<div>～ほか（は）ない<\\/div>\",\"今の状況ではこれ以外に方法がない、これが一番いいと言う時に使う。仕方がないという気持ちで使うことも多い。\"]', 'N3', '2026-04-02 16:01:07'),
(508, '<div>~ 次第[しだい]</div>', '<b>As soon as~</b><br><br><b>[JP]:</b> 「(今はまだできないが)～たら、すぐ・・・する」と言う時に使う。<br><b>[EN]:</b> When you say \"when something (that I can\'t do yet) happens, I\'ll do・・・right away.\"<br><img src=\"0e5afb88f406f70920cdedbf4a803782.jpg\" />', '[動-ます形・名]＋次第', '[\"ただ今、全線で運転を見合わせておりますが、情報が入り<b>次第<\\/b>、お伝え致します。\",\"「(今はまだできないが)～たら、すぐ・・・する」と言う時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(509, '<div>~次第だ / ~次第で(は)</div>', '<b>Depending on~</b><br><br><b>[JP]:</b> 「～」によって決まることを表す。<br><b>[EN]:</b> As in \"忘年会は予算次第で五つのコースから選べる\", this states that something is decided according to \"~ (the budget)\".<br><img src=\"pix.jpg\" />', '[名]＋次第', '[\"登山ルートは天候<b>次第<\\/b>で変更する場合もありますので、ご了承ください。\",\"「～」によって決まることを表す。\"]', 'N2', '2026-04-02 16:01:07'),
(510, '~ 上[じょう](は) / ~ 上[じょう]の / ~ 上[じょう]も', '<b>From the standpoint of~; (can also be thought of as ~ly. Ex. 歴史上?hisorically 法律上?legally)</b><br><br><b>[JP]:</b> 「~の点から教えて」という意味で、視点を示す言葉と一緒に使う。<br><b>[EN]:</b> Use it together with words that show a perspective meaning to mean \"in view of ~\".<br><img src=\"img_intro02.jpg\" />', '[名]＋上', '[\"お札にはその国の歴史<b>上<\\/b>の人物の顔が描かれていることが多い。\",\"the noun in front of ~上 is usually a Chinese word　Ex. 「教育上」、「外見上」、「経済上」、「政治上」、「学問上」、「表面上」、「職業上」、「外交上」etc…\",\"「~の点から教えて」という意味で、視点を示す言葉と一緒に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(511, '~ 末[すえ] (に) / ~末の', '<b>After~(for a long time)</b><br><br><b>[JP]:</b> 「長い間～をして（最後に・・・という結果になった）」と言いたい時に使う。実際に長くなくても、話者にとって「長く感じられた」という場合にも使う。<br><b>[EN]:</b> When you want to say \"after doing ~ for a long time (in the end the result was ・・・)\". You can also use it even if it did not take a long time because it \"felt long\" to the speaker.<br><img src=\"paste-13773960118273.jpg\" />', '[動-た形 / 名-の]＋末(に)', '[\"家族ともよく話し合った<b>末<\\/b>、今年度限りで引退することに決めました。\",\"「長い間～をして（最後に・・・という結果になった）」と言いたい時に使う。実際に長くなくても、話者にとって「長く感じられた」という場合にも使う。\"]', 'N2', '2026-04-02 16:01:07'),
(512, '<div>~せいか / ~せいだ / ~せいで</div>', '<b></b><br><br><b>[JP]:</b> 悪い結果になった理由を強く言う時に使われる。<br><b>[EN]:</b> Because of~ ; On account of~ (The cause leads to a bad result)<br><img src=\"David-De-Gea-1.jpg\" />', '[名詞修飾型]＋せいだ', '[\"私が失敗したのは、彼の<b>せいだ。<\\/b>\",\"理由がはっきりと分かっている時は「～せいで」、はっきり分からない時は「～せいか」を使う。\",\"悪い結果になった理由を強く言う時に使われる。\",\"<div>気のせい: be one’s imagination<\\/div><div>せいにしている:　blame something or somebody<\\/div>\"]', 'N3', '2026-04-02 16:01:07'),
(513, '<div>~だけ / ~だけあって / ~だけに / ~だけの</div>', '<b>Becoming of~ ; Worthy of~ ; Fitting of~</b><br><br><b>[JP]:</b> 感覚的に「～だから、さらに・・・と感じる」という時に使われる。<br><b>[EN]:</b> When you say that you sense that something \"feels even more ・・・ because of ~\"<br><img src=\"29degrees.jpg\" />', '[動-辞書形・た形・ている形 / い形-い / な形-な / 名-な]＋だけに', '[\"今年は猛暑な<b>だけに<\\/b>、ビールが一層美味しく感じられる。\",\"感覚的に「～だから、さらに・・・と感じる」という時に使われる。\"]', 'N2', '2026-04-02 16:01:07'),
(516, '<div>~たとえ~ても / ~たとえ~でも</div>', '<b>Even if~</b><br><br><b>[JP]:</b> 「もし～ても」という意味で、「どんな場合でも」と強く言いたい時に使う。<br><b>[EN]:</b> Meaning \"even if ~ \", when you want to strongly say \"no matter what situation\".<br><img src=\"paste-20276540604417.jpg\" />', 'たとえ＋[動-ても・い形-くても・な形-でも・名-でも]', '[\"子供がいるので、<b>たとえ<\\/b>給料が高く<b>ても<\\/b>、土日に休めない仕事はしたくない。\",\"「もし～ても」という意味で、「どんな場合でも」と強く言いたい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(517, '<div>~たとたん(に)</div>', '<b></b><br><br><b>[JP]:</b> 「～」の後すぐ「・・・」が起こったという状況を説明する時に使う。<br><b>[EN]:</b> When you explain in a situation in which 「．．．」 happened right after &nbsp;「～」&nbsp;<br><img src=\"paste-30017526431745.jpg\" />', '[動-た形]＋とたん', '[\"犯人は警官の姿を見た<b>とたん<\\/b>、逃げ出した。\",\"「・・・」の部分が話者の意志ですることの場合は使わない。\",\"「～」の後すぐ「・・・」が起こったという状況を説明する時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(518, '<div>~たび(に)</div>', '<b>Everytime~</b><br><br><b>[JP]:</b> 繰り返し行われることについて、それをする時はいつも、と言う時に使う。<br><b>[EN]:</b> When you say that a certain thing happens every time a certain action is taken.<br><img src=\"aid46137-v4-728px-Remember-Your-Past-Lives-Step-2.jpg\" />', '[動-辞書形 / 名-の]＋たび', '[\"その歌を歌う<b>たび<\\/b>、幼い日のことを思い出す。\",\"繰り返し行われることについて、それをする時はいつも、と言う時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(519, '<div>~だらけ</div>', '<b></b><br><br><b>[JP]:</b> 泥やしわ等汚い物がたくさんついている時、間違い等マイナスの評価の物がたくさんある時に使う<br><b>[EN]:</b> Full of~ &lt;negative&gt;<br><img src=\"bpQgCLH.jpg\" />', '[名]＋だらけ', '[\"このレポ-トは字が間違い<b>だらけ<\\/b>で読みにくい。\",\"「～いっぱい」；　「～ばっか」\",\"泥やしわ等汚い物がたくさんついている時、間違い等マイナスの評価の物がたくさんある時に使う\"]', 'N3', '2026-04-02 16:01:07'),
(520, '<div>~ついでに</div>', '<b>When doing ~ also do ~</b><br><br><b>[JP]:</b> 何かをする機会を利用して他の事をすると言う時に使う。<br><b>[EN]:</b> When you want to take advantage of another action to do something else.<br><img src=\"Santa-Mail.jpg\" />', '[動-辞書形・た形 / 名-の]＋ついでに', '[\"銀行へ行く<b>ついでに<\\/b>この手紙を出してくれませんか。\",\"何かをする機会を利用して他の事をすると言う時に使う。\",\"「ついでに」だけでも使われる。\"]', 'N3', '2026-04-02 16:01:07'),
(521, '<div>~っこない</div>', '<b>No way that~</b><br><br><b>[JP]:</b> そなことは絶対考えられないと、強く否定したい時に使う。<br><b>[EN]:</b> When you want to strongly deny something because it is absolutely unthinkable.<br><img src=\"Winning-the-Lottery.jpg\" />', '[動-ます形]＋っこない', '[\"宝くじなんて当たり<b>っこない<\\/b>よ。\",\"～わけがない\",\"Use in conversations\",\"そなことは絶対考えられないと、強く否定したい時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(522, '~つつ', '<b>While~</b><br><br><b>[JP]:</b> 「～ながら」と同じ意味で使う。<br><b>[EN]:</b> Same mining as \"ながら\"<br><img src=\"7f3841fbe9c77651b699a688af8f5784.jpg\" />', '[動-ます形]＋つつ', '[\"クリスマスを前におもちゃ売り場には、喜ぶ子供の顔を思い浮かべ<b>つつ<\\/b>、プレゼントを選ぶお父さんの姿が増えています。\",\"Not used in conversations.\",\"「～ながら」と同じ意味で使う。\"]', 'N2', '2026-04-02 16:01:07'),
(523, '<div>~つつある</div>', '<b>Be (gradually) doing~</b><br><br><b>[JP]:</b> 少しずつ変化していると説明する時に使う。<br><b>[EN]:</b> Use this to explain that something is changing little by little as in \"日本の人口は減りつつある\".<br><img src=\"lightning.jpg\" />', '[動-ます形]＋つつある', '[\"異常気象の影響が世界各地に広がり<b>つつある。<\\/b>\",\"Used mostly in written form\",\"少しずつ変化していると説明する時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(524, '<div>~っぽい</div>', '<b></b><br><br><b>[JP]:</b> 見た時の印象が、そう見える、そう感じる時に使う<br><b>[EN]:</b> ~ish ; ~like ; ~looking<br><img src=\"veloce100ct_1.jpg\" />', '[い形-○ / 名]＋っぽい', '[\"このテーブルは高いのに安<b>っぽく<\\/b>見える\",\"見た時の印象が、そう見える、そう感じる時に使う\"]', 'N3', '2026-04-02 16:01:07'),
(526, '<div>~(て) 以来[いらい]</div>', '<b>Since~(and still going on)</b><br><br><b>[JP]:</b> 「～」の時から今までずっと同じ状態が続いている時に使う。<br><b>[EN]:</b> When a condition has continued from \"~\" until now.<br><img src=\"housework.jpg\" />', '[動-て形 / 名]＋以来', '[\"母が入院して<b>以来<\\/b>、家事はすべて私がしています。\",\"「～」の時から今までずっと同じ状態が続いている時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(527, '<div>~てからでないと / ~てからでなければ</div>', '<b>Not until~</b><br><br><b>[JP]:</b> 「・・・」は「～」が実現しないとできないと言う時に使う。<br><b>[EN]:</b> When you say that \"・・・\" cannot be done until \"~\" is done.<br><img src=\"cod.jpg\" />', '[動-て形]＋からでないと・からでなければ', '[\"お金をいただいて<b>からでないと<\\/b>、商品はを届けできません。\",\"The following sentence will always be negative.\",\"「・・・」は「～」が実現しないとできないと言う時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(528, '<div>(~て)たまらない / ~(て)しょうがない</div>', '<b>Can’t help~ing ; Can’t stand(bear)~</b><br><br><b>[JP]:</b> 心や体の状態がとても～だ、我慢できないぐらい～だと言う時に使う。<br><b>[EN]:</b> When you say that a person\'s mental or physical condition is very \"~\" or that a person is so \"~\" that he or she can not resist doing something.<br><img src=\"313BF7E000000578-3447870-Those_who_skip_breakfast_makes_people_feel_less_energetic_so_the-a-59_1455541937170.jpg\" />', '[動-て形 / い形-くて / な形-で]＋しょうがない・しかたがない・たまらない', '[\"頭痛がして<b>たまらない<\\/b>ので、近くの病院へ行った。\",\"Subject is always first person\",\"心や体の状態がとても～だ、我慢できないぐらい～だと言う時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(529, '<div>(~て)ならない</div>', '<b>Can’t help~ing</b><br><br><b>[JP]:</b> 「非常に～だ」と言いたいときに使われる。<br><b>[EN]:</b> Is used when you want to say something \"is extremely ~\".<br><br><img src=\"paste-12768937771009.jpg\" />', '[動-て形 / い形-くて / な形-で]＋ならない', '[\"私のように年をとってくると、ふるさとの山々が懐かしく思い出されて<b>ならない<\\/b>んですよ。\",\"<div>「綺麗・下手」など評価を表す言葉と一緒には使わなう。<\\/div><div>Don\'t use it with words that assess.<\\/div>More formal than「~てたまらない」。「思える」、「思い出す」etc. can\'t use 「~てたまらない」\",\"「非常に～だ」と言いたいときに使われる。\",\"「残念・不安・心配・つらい・悔しい」など、感情を表す言葉と一緒に使う。<div>Use it together with words that express feelings.<\\/div>\"]', 'N2', '2026-04-02 16:01:07'),
(530, '<div>~ということだ、～とのことだ</div>', '<b></b><br><br><b>[JP]:</b> 聞いた情報の内容を他の人に伝える時に使う。<br><b>[EN]:</b> When you tell another person some information you heard.<br><img src=\"o-METROCARD-facebook.jpg\" />', '[普通形]＋ということだ・とのことだ', '[\"新聞によると、また地下鉄の運賃が値上げされる<b>ということだ<\\/b>。\",\"聞いた情報の内容を他の人に伝える時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(531, '<div>~というと&nbsp;/ ~といえば&nbsp;/ ~といったら</div>', '<b>Speaking of~ ; Talking about~　&lt;use when speaking something typical about the topic&gt;</b><br><br><b>[JP]:</b> その言葉から多くの人がイメージする物事を言う時に使う。有名なものや代表的なものを言うことが多い。<br><b>[EN]:</b> When you say something that people often associate with \"~\". The example given is often something famous or typical.<br><img src=\"ea2c66983bfeeb390b6c819047a5195405e53328.jpg\" />', '[名]＋というと・といえば・といったら', '[\"スポーツの祭典<b>というと<\\/b>、まずオリンピックですね\",\"その言葉から多くの人がイメージする物事を言う時に使う。有名なものや代表的なものを言うことが多い。\"]', 'N3', '2026-04-02 16:01:07'),
(532, '<div>~というものだ</div>', '<b>Is known as~ ; It is that~</b><br><br><b>[JP]:</b> 話者の考えを、個人的な意見ではなく一般的にそうだと言いたい時に使う。<br><b>[EN]:</b> When you want to say tou think that \"this isn\'t what I think, but generally it\'s like this\".<br><img src=\"418811132e2875e93c1d693859c360d7.jpg\" />', '[普通形]＋というものだ', '[\"貧しくても家族が仲良く暮らせるのが幸せ<b>というものです<\\/b>よ。\",\"話者の考えを、個人的な意見ではなく一般的にそうだと言いたい時に使う。\",\"sometimes [な形；名]don\'t use [だ]\"]', 'N2', '2026-04-02 16:01:07'),
(533, '<div>~というものではない / ~というものでもない</div>', '<b>Not necessarily~ ; It’s not that</b><br><br><b>[JP]:</b> 一般的にそう思われていることも、絶対そうだとは言えないと言いたい時に使う。<br><b>[EN]:</b> When you want to say that \"people usually think so, but it\'s not necesarilly like that\"<br><img src=\"YesYouCanChangeYourPersonality-800x588.jpg\" />', '[普通形]＋というものではない・というものでもない', '[\"性格は絶対に変えられない<b>というものではない<\\/b>。\",\"一般的にそう思われていることも、絶対そうだとは言えないと言いたい時に使う。\",\"sometimes [な形；名]don\'t use [だ]\"]', 'N2', '2026-04-02 16:01:07'),
(534, '<div>~というより</div>', '<b>More than~</b><br><br><b>[JP]:</b> 「Aの言い方よりBと言ったほうが適切だ」と言いたい時に使う。<br><b>[EN]:</b> As in \"涼しいというより寒い\", use \"AというよりB\" when you want to say \"it\'s more important to say B (it\'s cold) than A (it\'s cool).<br><img src=\"Government-oppression-sign-Cropped-620x400.png\" />', '[普通形-○]＋というより', '[\"彼の言い方は勧めている<b>というより<\\/b>、強制しているよ。\",\"「Aの言い方よりBと言ったほうが適切だ」と言いたい時に使う。\",\"[な形・名] do not use [だ]\"]', 'N2', '2026-04-02 16:01:07'),
(535, '<div>~といっても</div>', '<b>But~ ; Although~ (show what your thinking about is wrong or different)</b><br><br><b>[JP]:</b> 相手が想像したことに対して、「実際にはそうではない」と言いたいときに使う。<br><b>[EN]:</b> As in \"会社といっても妻と二人でやっている小さい会社です\", use this when you want to say \"It\'s not actually like that\" in response to what the listener has imagined (the company has many employees).<br><img src=\"IMG_20181006_011240.jpg\" />', '[普通形]＋といっても・といいましても', '[\"1世帯<b>といっても<\\/b>、一人暮らしの人から10人以上の大家族までいろいろある。\",\"相手が想像したことに対して、「実際にはそうではない」と言いたいときに使う。\",\"sometimes[な形；名]don\'t use [だ]\"]', 'N2', '2026-04-02 16:01:07'),
(536, '<div>~とおり(に) / ~どおり(に)</div>', '<b></b><br><br><b>[JP]:</b> 言ったことや予想したことなどと同じだという時に使う。<br><b>[EN]:</b> To say that something happened exactly as someone said or guessed it would.<br><img src=\"paste-11909944311809.jpg\" />', '[動-辞書形・た形 / 名-の]＋とおり<div>[名]＋どおり</div>', '[\"説明書に書いてある<b>とおり<\\/b>にやってみてください。\",\"言ったことや予想したことなどと同じだという時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(537, '<div>~とか</div>', '<b>hear that~ ; say that~</b><br><br><b>[JP]:</b> 聞いた情報を言う時に使われる。確かな情報ではないがという気持ちで使うことが多い。<br><b>[EN]:</b> This is used in forms such as \"～とか言っていた\" when you state information you have heard. It is often used with the nuance that the information may not be solid. You can also omit words such as \"言っていた\".<br><img src=\"married-588592153df78c2ccdf11fde.jpg\" />', '[普通形]＋とか', '[\"息子さんが今度結婚なさる<b>とか<\\/b>。おめでとうございます。\",\"聞いた情報を言う時に使われる。確かな情報ではないがという気持ちで使うことが多い。\"]', 'N2', '2026-04-02 16:01:07'),
(538, '<div>~どころか</div>', '<b>Far from~</b><br><br><b>[JP]:</b> Aではなくて反対のBだと強く言う気持ちを表す。また、Aよりもっと程度がすごいBと言う時に使う。Aには相手の言ったことや自分が初めに思ったことなどが入ることが多い。<br><b>[EN]:</b> As in \"雨が降るどころかすごくいい天気になった\", it expresses a feeling that strongly says \"it\'s not A (rainy weather), it\'s the opposite (fine weather)\". In addition, as in \"漢字どころかひらがなも読めない\", it\'s also used when you say \"it\'s not A (not able to read kanji), it\'s something much more, B (not able to even read hiragana)\". A is often something the listener said or something the speaker just thought of.<br><img src=\"paste-21294447853569.jpg\" />', '[普通形-○]＋どころか', '[\"高校生の時は、海外旅行<b>どころか<\\/b>国内旅行もしたことがありませんでした。\",\"Aではなくて反対のBだと強く言う気持ちを表す。また、Aよりもっと程度がすごいBと言う時に使う。Aには相手の言ったことや自分が初めに思ったことなどが入ることが多い。\",\"[な形・名]don\'t use[だ]；[な形-な]can be used\"]', 'N2', '2026-04-02 16:01:07'),
(539, '<div>~どころではない / ~どころではなく</div>', '<b>Can’t do ~ because~</b><br><br><b>[JP]:</b> 今は「～ができる状態ではない(だからできない)」という自分の状況を説明したい時に使う。<br><b>[EN]:</b> When you want to explain thet your situation now is \"not a situation wher I can do ~ (so I can\'t do it).\"<br><img src=\"paste-10750303141889.jpg\" />', '[動-辞書形 / 名]＋どころではない・どころじゃない', '[\"A: 学校が終わったらカラオケ行かない？<div>B: カラオケ<b>どころじゃない<\\/b>よ！レポート、書かなきゃ。明日締め切りなんだ・締め切りなんだ。<\\/div>\",\"今は「～ができる状態ではない(だからできない)」という自分の状況を説明したい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(540, '<div>~ところに / ~ところへ / ~ところを</div>', '<b>At that time ; At that place ; At that scene</b><br><br><b>[JP]:</b> ちょうど「～」の場面、「～」の時に、「・・・」をする、「・・・」が起きたと言う時に使う。<br><b>[EN]:</b> When you say that someone did \"・・・\" or that \"・・・\" happened right in a certain setting or at a certain time (as expressed by ~)<br><img src=\"getty_508970750_2000133420009280144_128946.jpg\" />', '[動-辞書形・た形・ている形 / い形-い]＋ところに', '[\"ちょうどキムさんのうわさをしている<b>ところに<\\/b>、本人がやって来た。\",\"「ところ」の後ろにつく助詞は「～ところを見られた」「～ところへ\\/に来た」「～ところで終わった」など、後ろの動詞によって変わる。\",\"ちょうど「～」の場面、「～」の時に、「・・・」をする、「・・・」が起きたと言う時に使う。\",\"[動-ていた形・意向形-とした]＋ところの形も使われる。\"]', 'N3', '2026-04-02 16:01:07'),
(541, '<div>~としたら / ~とすれば</div>', '<b>If~ (Think from the perspective of~)</b><br><br><b>[JP]:</b> 「～だと考えば・・・」という意味で、自分の意見や予想を言いたい時に使う。<br><b>[EN]:</b> Use it meaning \"imagine if ~, ・・・\", when you want to state a personal opinion or prediction.<br><img src=\"Screen-Shot-2013-11-05-at-1.31.59-PM.png\" />', '[普通形]＋としたら・とすると・とすれば', '[\"もし、生まれ変われる<b>としたら<\\/b>、私は鳥になりたい。\",\"「～だと考えば・・・」という意味で、自分の意見や予想を言いたい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(542, '<div>~として(は) / ~としての / としても</div>', '<b>As~</b><br><br><b>[JP]:</b> 資格・用途などを言う時に使う。<br><b>[EN]:</b> When you want to state a qualification, use or the like, as in \"留学生として\" and \"旅行用として\".<br><img src=\"paste-10436770529281.jpg\" />', '[名]＋として', '[\"この病気は難病<b>として<\\/b>認定された。\",\"資格・用途などを言う時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(543, '<div>~とともに</div>', '<b>As~</b><br><br><b>[JP]:</b> 「～と一緒に・～だけでなく」と言う時に使う。「と一緒に・・・が生じる・起きる」と言う時や、変化を表す時にも使う。<br><b>[EN]:</b> When you say \"together with ~\" or \"not only ~ but also・・・\". You can also use it to say that \"・・・happens together with ~\", or to express a change.<br><img src=\"rsz_gettyimages-182435747.jpg\" />', '[動-辞書形 / 名]＋とともに', '[\"彼は医療ボランティアとして現地の医師<b>とともに<\\/b>日夜病気の治療を行っている。\",\"「～と一緒に・～だけでなく」と言う時に使う。「と一緒に・・・が生じる・起きる」と言う時や、変化を表す時にも使う。\"]', 'N2', '2026-04-02 16:01:07'),
(544, '<div>~ないことには</div>', '<b>If not~</b><br><br><b>[JP]:</b> 「～なければ（・・・できない・わからない）」と言いたいときに使われる。<br><b>[EN]:</b> Is used when you want to say \"if you don\'t do ~, then you can\'t / you won\'t know ・・・\".<br><img src=\"homepic.jpg\" />', '[動-ない形 / い形-く / な形-で / 名-で]＋ないことには', '[\"もっと広い会場は借り<b>ないことには<\\/b>、観客を収容しきれないだろう。\",\"The following sentence will be negative.\",\"「～なければ（・・・できない・わからない）」と言いたいときに使われる。\"]', 'N2', '2026-04-02 16:01:07'),
(545, '<div>~ないことはない / ~ないこともない</div>', '<b>Possibility of~ &nbsp;(Neither yes or no)</b><br><br><b>[JP]:</b> 「絶対～だ」とはっきり言えない、自信がなくてはっきり言いたくない時に使う。<br><b>[EN]:</b> When you cannot say flat out that something \"absolutley is ~\" or are not confident and do not want to say something flat out.<br><img src=\"karaoke2-1446926502-600x360.jpg\" />', '[動-ない形 / い形-く / な形-で / 名-で]＋ないことはない', '[\"カラオケは行か<b>ないこともない<\\/b>んです、誘われた時にお付き合いで行くぐらいです。\",\"「絶対～だ」とはっきり言えない、自信がなくてはっきり言いたくない時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(546, '<div>~ないではいられない / ずにはいられない</div>', '<b>Always end up~</b><br><br><b>[JP]:</b> 我慢ができなくて、どうしても～してしまう状況だと言う時に使う。<br><b>[EN]:</b> When you say that you can not stand it and end up doing \"~\" no matter how hard you try not to do.<br><img src=\"man-little-boy-shaving-foam-260nw-788255794.jpg\" />', '[動-ない形]＋ずに・ないで＋はいられない', '[\"彼のもの真似を見るとおかしくて、笑わない<b>ではいられない。<\\/b>\",\"～ないではいられない\",\"Only for first person. &nbsp;For third person, use 「~ようだ」「~らしい」at the end.\",\"我慢ができなくて、どうしても～してしまう状況だと言う時に使う。\",\"[する]becomes[ぜずにはいらない]\"]', 'N3', '2026-04-02 16:01:07'),
(547, '<div>~ながら</div>', '<b>Though~</b><br><br><b>[JP]:</b> 「～の状態だが、けれども」と言いたい時に使う。<br><b>[EN]:</b> When you want to say \"this is the situation, but...\"<br><img src=\"Illness-Disease.jpg\" />', '[動-ます形・ない形-ない / い形-○ / な形-○ / 名]＋ながら<div>[な形-○ / 名]＋であり＋ながら</div>', '[\"一緒に暮らしてい<b>ながら<\\/b>、母の病気に気づかなかった。\",\"「~つつ \\/ ~つつも」のBの意味\",\"「～の状態だが、けれども」と言いたい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(548, '<div>~など / ~なんか / ~なんて</div>', '<b>1. such as; like; and so on　&lt;when you want to give an example, or make a light expression.&gt;<div>2.&nbsp;etc; among other things ; for example&lt;make light of something or say something negative&gt;</div></b><br><br><b>[JP]:</b> 他の物でもいいような言い方で相手に判断を任せる形にして、柔らかく言うときに使う。<br><b>[EN]:</b> Use it when you want to gently suggest another option to the listener, while leaving the decision up to him or her.<br><img src=\"shopping-addictioni-604cs040813.jpg\" />', '[名]＋なんか', '[\"こちらのセーター<b>なんか<\\/b>いかがでしょう。この色は今年の流行色ですよ。\",\"なんか、なんて are used in spoken language<span class=\\\"Apple-tab-span\\\" style=\\\"white-space:pre\\\"> <\\/span>\",\"他の物でもいいような言い方で相手に判断を任せる形にして、柔らかく言うときに使う。\"]', 'N3', '2026-04-02 16:01:07'),
(549, '<div>~にあたり / ~にあたって</div>', '<b>When~(show something that should be done in this situation)</b><br><br><b>[JP]:</b> 「～をするときに」という意味を表す。<br><b>[EN]:</b> It means \"when doing ~\".<br><img src=\"paste-23038204575745.jpg\" />', '[動-辞書形 / 名]＋にあたって・にあたり', '[\"開会<b>にあたって<\\/b>、一言ご挨拶申し上げます。\",\"「～をするときに」という意味を表す。\"]', 'N2', '2026-04-02 16:01:07'),
(550, '<div>~において(は) / ~においても / ~における</div>', '<b>In ; At ; On ; same as the particle で</b><br><br><b>[JP]:</b> 「場所・時代・分野などで」と言いたい時に使う。お知らせやニュースなどで使われることが多い。<br><b>[EN]:</b> When you want to say a place, time, field / subject, area and so on. Often used in announcements and the like.<br><img src=\"1stkaigi1.jpg\" />', '[名]＋において<div>[名]＋における＋[名]</div>', '[\"会議は第一会議室<b>において<\\/b>行われる。\",\"「場所・時代・分野などで」と言いたい時に使う。お知らせやニュースなどで使われることが多い。\"]', 'N2', '2026-04-02 16:01:07'),
(551, '<div>~に 応[おう]じ / ~ 応[おう]じた / ~ 応[おう]じて</div>', '<b>In response to~</b><br><br><b>[JP]:</b> 「希望・変化・地域・状況・年齢・能力・経験などの条件に合わせて・・・する」と言いたい時に使う。<br><b>[EN]:</b> When you want to say that something \"depends on conditions such as a desire, change, location, situation, age, ability or experience.\"<br><img src=\"storm-damage-pic-home-page-box-300x201.jpg\" />', '[名]＋に応じて', '[\"保険金は被害状況<b>に応じて<\\/b>、払われる。\",\"「希望・変化・地域・状況・年齢・能力・経験などの条件に合わせて・・・する」と言いたい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(552, '<div>~にかかわらず / ~に(は)かかわりなく</div>', '<b>Regardless of~</b><br><br><b>[JP]:</b> 「天候・好み・地位や、あるなし・するしないなどの条件に関係なく・・・」と言いたい時に使われる。<br><b>[EN]:</b> Is used when you want to say \"regardless of conditions such as weather, preference, social position, or whether something is there or not there, done or not done, etc.\"<br><img src=\"08_reply_to_address_in_message.png\" />', '[名]＋にかかわらず<div>[動-辞書形＋動-ない形]＋ないにかかわらず</div>', '[\"参加するしない<b>かかわらず<\\/b>、必ず返事をください。\",\"<div>Nouns showing a kind or extent of something, or 2 words in opposition are usually used.&nbsp;Such as 「する・しない」「晴雨」。Adjectives such as 「いい・悪い」「好き・嫌い」「上手・下手」&nbsp;can be combined and used.<\\/div>\",\"「天候・好み・地位や、あるなし・するしないなどの条件に関係なく・・・」と言いたい時に使われる。\"]', 'N2', '2026-04-02 16:01:07'),
(553, '<div>~に 限[かぎ]って / ~ 限[かぎ]り / ~に 限[かぎ]る</div>', '<b>Only~</b><br><br><b>[JP]:</b> 「だけ」という意味で、お知らせなどによく使われる。<br><b>[EN]:</b> It\'s often used to mean \"only / just\" in an announcement and the like.<br><img src=\"178D6928.JPG\" />', '[名]＋に限る・に限り・に限って', '[\"参加者は女性<b>に限る<\\/b>。\",\"[名]＋に限って...ない」の形で、予想していなかった悪いことが起きた時や、噂などに対して信じられないと強く否定したい時に使う。\",\"「だけ」という意味で、お知らせなどによく使われる。\"]', 'N2', '2026-04-02 16:01:07'),
(556, '<div>~に限らず</div>', '<b>Not only~but also~</b><br><br><b>[JP]:</b> 「～だけでなく、他にも」と言いたい時に使う。<br><b>[EN]:</b> When you want to say \"not just ~, but also something else\".<br><img src=\"131876-425x282-whyconserveenergy.JPG\" />', '[名]＋に限らず', '[\"環境対策のためにも、夏<b>に限らず<\\/b>年間を通して節電を心がけるべきだ。\",\"「～だけでなく、他にも」と言いたい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(557, '<div>~にかけては / ~にかけても</div>', '<b>If (when) talking about ~ ; As far as~is concerned~</b><br><br><b>[JP]:</b> 「～の分野では」と範囲を限定して、その分野では「最高レベルだ」「自信がある」などと言いたいときに使われる。<br><b>[EN]:</b> Is used when you want to say that when it comes to \"the field / subject area of ~\", you have \"the highest level\", are \"confident\" or the like.<br><img src=\"making_sake.jpg\" />', '[名]＋にかけては', '[\"日本酒造り<b>にかけては<\\/b>彼の右に出る者はいない。\",\"followed by a positive sentence\",\"「～の分野では」と範囲を限定して、その分野では「最高レベルだ」「自信がある」などと言いたいときに使われる。\"]', 'N2', '2026-04-02 16:01:07'),
(558, '<div>~に 関[かん]して(は) / ~にかんしても / ~に 関[かん]する</div>', '<b>About~</b><br><br><b>[JP]:</b> 「～について」と同じように、話題にしたり、調べたりする内容を言う時に使う。調査や研究、通知などでよく使う。<br><b>[EN]:</b> When you introduce a topic or say what someone is investigating. This is often used in surveys, research, notifications and the like.<br><img src=\"paste-118545392336897.jpg\" />', '[名]＋に関して<div>[名]＋に関する＋[名]</div>', '[\"計画変更<b>に関して<\\/b>、十分検討する必要がある。\",\"「～について」\",\"これはよりもっと硬い言葉\",\"「～について」と同じように、話題にしたり、調べたりする内容を言う時に使う。調査や研究、通知などでよく使う。\"]', 'N2', '2026-04-02 16:01:07'),
(559, '<div>~に 比[くら]べ / ~に 比[くら]べて</div>', '<b>Compare~ to~</b><br><br><b>[JP]:</b> 「～より」と同じ意味で、二つ以上の物を比較し、程度の違いを言いたい時に使う。<br><b>[EN]:</b> Use it when you want to compare two or more things and say how much they differ. It has the same meaning as \"～より\".<br><img src=\"paste-13052405612545.jpg\" />', '[名]＋に比べて', '[\"いちごはレモン<b>に比べて<\\/b>、ビタミンCが多いんだって。ほんとかな？\",\"「～より」と同じ意味で、二つ以上の物を比較し、程度の違いを言いたい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(560, '<div>~に 加[くわ]え / ~に 加[くわ]えて</div>', '<b>In addition to~</b><br><br><b>[JP]:</b> 「～だけでなく、その上」という意味を表す。<br><b>[EN]:</b> Means \"not only ~, but also\".<br><img src=\"paste-24459838750721.jpg\" />', '[名]＋に加えて', '[\"優れたサッカー選手になるには、運動能力<b>に加えて<\\/b>、判断力や協調性が求められる。\",\"「～だけでなく、その上」という意味を表す。\"]', 'N2', '2026-04-02 16:01:07'),
(561, '<div>~にこたえ / ~にこたえた / ~にこたえて / ~にこたえる</div>', '<b>In response to~ ; In reply to~</b><br><br><b>[JP]:</b> 「相手からの期待や要請の通りに」と言いたいときに使う。<br><b>[EN]:</b> Use it when you want to say \"according to another person\'s expectation or request\".<br><img src=\"paste-9998683865089.jpg\" />', '[名]＋にこたえて<div>[名]＋にこたえた＋[名]</div><div>ご[名]＋におこたえて</div>', '[\"そのアイドルはコンサートの最後にアンコール<b>にこたえて<\\/b>もう1曲歌った。\",\"「相手からの期待や要請の通りに」と言いたいときに使う。\"]', 'N2', '2026-04-02 16:01:07'),
(562, '<div>~に 際[さい]し / ~に 際[さい]して /　~に 際[さい]しての</div>', '<b>When starting~ ; When doing~</b><br><br><b>[JP]:</b> 注意やおわび、説明などの文に使われる。<br><b>[EN]:</b> It is used in sentences such as warnings, apologies, explanations and the like.<br><img src=\"my_wso_story_img_boys064b.jpg\" />', '[動-辞書形 / 名]＋に際して', '[\"留学<b>に際して<\\/b>、先生や友人から励まし言葉をもらった。\",\"「~にあたって」\",\"注意やおわび、説明などの文に使われる。\"]', 'N2', '2026-04-02 16:01:07'),
(563, '<div>~に 先立[さきだ]ち / ~に 先立[さきだ]て / ~に 先立[さきだ]つ</div>', '<b>Before ~ ; Right before~</b><br><br><b>[JP]:</b> 「～の前に、何かが行われる」と言いたいときに使われる。<br><b>[EN]:</b> Is used when you want to say \"something will be done before ~\".<br><img src=\"paste-18674517803009.jpg\" />', '[名]＋に先立って・に先立ち<div>[名]＋に先立つ＋[名]</div>', '[\"レストランの開店<b>に先立って<\\/b>、試食会が開かれた。\",\"「～の前に、何かが行われる」と言いたいときに使われる。\"]', 'N2', '2026-04-02 16:01:07'),
(564, '<div>~にしたがい / ~にしたがって</div>', '<b>With~ ; Following~ ; As~ (when one the changes so does the other)</b><br><br><b>[JP]:</b> 「～の変化に合わせて、他のことも変化する」と言いたい時に使う。「～に合わせて」と言いたい時にも使う。<br><b>[EN]:</b> Use it when you want to say \"something else changes along with a change in ~\". You can also use it when you want to say \"in concert with ~\".<br><img src=\"humans-clipart-sick-15.jpg\" />', '[動-辞書形・名]＋にしたがって・にしたがい', '[\"暑くなる<b>にしたがって<\\/b>、体調を崩す人が増えた。\",\"「~とともに」；「~につれて」\",\"「～の変化に合わせて、他のことも変化する」と言いたい時に使う。「～に合わせて」と言いたい時にも使う。\"]', 'N2', '2026-04-02 16:01:07'),
(565, '<div>~にしては</div>', '<b>Although ; Even though</b><br><br><b>[JP]:</b> 「～から予想することとは違う」と言いたい時に使う。<br><b>[EN]:</b> When you want to say that something is \"different from what you would expect from ~\" as in \"小学1年生にしては背は高い\".<br><img src=\"BMTFp5jCYAACae0.jpg\" />', '[普通形-○]＋にしては', '[\"今人気のエリナはモデル<b>にしては<\\/b>背が高いほうではない。\",\"「～から予想することとは違う」と言いたい時に使う。\",\"[な形；名]don\'t use [だ]\"]', 'N2', '2026-04-02 16:01:07'),
(566, '~にしても / ~にしろ / ~に(も)せよ', '<b>Whenever~,&nbsp;Even if~</b><br><br><b>[JP]:</b> ある範囲内のものから例をあげて、「～だけでなくどれでも」と言いたいときに使われる。「いい・悪い」「好き・嫌い」「する・しない」「出席する・欠席する」など反対の意味の言葉を使って、どちらの場合でもと言いたいときにも使われる。<br><b>[EN]:</b> Is used when you want to give examples from a category and say that \"not only ~ but all of them\" are something. It is also used with pairs of antonyms such as \"いい・悪い\", \"好き・嫌い\", \"する・しない\", and \"出席する・欠席する\" when you want to say that something could be applicable in either case.&nbsp;<br><img src=\"238px-Tokyo_Tower_and_around_Skyscrapers.jpg\" />', '[普通形-○]＋にしろ・にしても・にせよ＋[普通形-○]＋にしろ・にしても・にせよ', '[\"東京<b>にしろ<\\/b>大阪<b>にしろ<\\/b>大都市には働く場所が多いので人が集まってくる。\",\"\\\"~にしろ\\\" can also be used only once in a sentence when used together with a question word.<div>「～にしろ」が、疑問詞と一緒に、一つだけで使われることもある。<\\/div>\",\"ある範囲内のものから例をあげて、「～だけでなくどれでも」と言いたいときに使われる。「いい・悪い」「好き・嫌い」「する・しない」「出席する・欠席する」など反対の意味の言葉を使って、どちらの場合でもと言いたいときにも使われる。\",\"[~である]can be used.\"]', 'N2', '2026-04-02 16:01:07'),
(567, '<div>~にすぎない</div>', '<b>Merely~ ; Only~ ; Just~ ; Be (do) nothing but~</b><br><br><b>[JP]:</b> 「ただ～だけだ」と説明したい時に使われる。あまり価値がないと思っているときにもよく使われる。<br><b>[EN]:</b> Is used when you want to explain that something is \"only ~\" as in \"合格率は８％にすぎない\". It is also often used when you think that something does not have much value.<br><img src=\"10678404-large.jpg\" />', '[動-辞書形・た形 / 名]＋にすぎない', '[\"この高校は2年前に男女共学になったが、男子学生はまだ10人<b>にすぎない<\\/b>。\",\"「ただ～だけだ」と説明したい時に使われる。あまり価値がないと思っているときにもよく使われる。\"]', 'N2', '2026-04-02 16:01:07'),
(568, '<div>~に 沿[そ]い / ~に 沿[そ]う / ~に 沿[そ]った /　~に 沿[そ]って</div>', '<b>In accordance with~</b><br><br><b>[JP]:</b> 「～の通りに」「～に合わせて」という意味で使われる。<br><b>[EN]:</b> Is used to mean \"along\", \"in accordance with\" or \"as\".<br><img src=\"walk-down-malacca-river.jpg\" />', '[名]＋に沿って<div>[名]＋に沿う・に沿った＋[名]</div>', '[\"二人は夕暮れの道を川<b>に沿って<\\/b>歩き続けた。\",\"「マニュアル・方針・案内・道順」などの言葉と一緒に使われる。<div>「希望・要望・意向・期待＋に沿うよう」などの言い方もある。<\\/div>\",\"「～の通りに」「～に合わせて」という意味で使われる。\"]', 'N2', '2026-04-02 16:01:07'),
(569, '~に 相違[そうい]ない', '<b>It must be~</b><br><br><b>[JP]:</b> 「に違いない」と同じ意味がある。<br><b>[EN]:</b> When you say that you are aboslutely sure or have no doubt about something.<br><img src=\"paste-19378892439553.jpg\" />', '[普通形-○]＋に相違ない', '[\"そんな非常識な要求は認められないに<b>相違ない。<\\/b>\",\"～に違いない\",\"<div>In certificates the meaning becomes 「間違いない」<\\/div>\",\"「に違いない」と同じ意味がある。\",\"[な形・名] don\'t use [だ]\"]', 'N3', '2026-04-02 16:01:07'),
(570, '<div>~に 対[たい]し / ~に 対[たい]して(は) / ~に 対[たい]しても / ~に 対[たい]する</div>', '<b></b><br><br><b>[JP]:</b> 人に向かって直接働きかけをしたり、「やさしい」「失礼だ」といった態度を表す時に使う。意見・問題・要求に応えたり反対したりする時にも使う。<br><b>[EN]:</b> When you talk about direct action toward another person or certain attitudes. You can also use it when you respond to or refuse / refute an opinion, problem or request / demand.<br><img src=\"paste-37151467110401.jpg\" />', '[名]＋に対して<div>[名]＋に対する＋[名]</div>', '[\"お客様<b>に対して<\\/b>失礼なことを言ってはいけません。\",\"人に向かって直接働きかけをしたり、「やさしい」「失礼だ」といった態度を表す時に使う。意見・問題・要求に応えたり反対したりする時にも使う。\"]', 'N3', '2026-04-02 16:01:07'),
(571, '~に 違[ちが]いない', '<b>There is no doubt of~</b><br><br><b>[JP]:</b> 絶対に、確かに～だと思うと言う時に使う。<br><b>[EN]:</b> When you say that you are absolutely sure or have no doubt about something.<br><img src=\"hqdefault (2).jpg\" />', '[普通形-○]＋に違いない', '[\"鍵がない。どこかに落とした<b>に違いない。<\\/b>\",\"～相違ない\",\"絶対に、確かに～だと思うと言う時に使う。\",\"[な形・名] don\'t use [だ]\"]', 'N3', '2026-04-02 16:01:07'),
(572, '<div>~について(は) / ~についての / ~についても / ~につき</div>', '<b></b><br><br><b>[JP]:</b> 話題にしたり、考えたり、調べたりする内容を言う時に使う。<br><b>[EN]:</b> When you introduce a topic or say what someone is thinking about or investigating.<br><img src=\"main.jpg\" />', '[名]＋について ( は / も )<div>[名]＋についての＋[名]</div>', '[\"日本の経済<b>について<\\/b>研究しています。\",\"「～にかんして」\",\"話題にしたり、考えたり、調べたりする内容を言う時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(573, '<div>~につき</div>', '<b>Because~</b><br><br><b>[JP]:</b> お知らせなどで理由を言う時に使われる。<br><b>[EN]:</b> This is used to state a reason in an announcement and the like.<br><img src=\"article-2218748-1588EC9D000005DC-484_634x416.jpg\" />', '[名]＋につき', '[\"雨天<b>につき<\\/b>、試合は延期いたします。\",\"Slightly strong saying\",\"お知らせなどで理由を言う時に使われる。\"]', 'N2', '2026-04-02 16:01:07'),
(574, '<div>~につけ / ~につけて(は) / ~についても</div>', '<b>whenever~</b><br><br><b>[JP]:</b> 「何かを見たり聞いたりするたびに（いつも・・・と思う）と言いたい時に使う。<br><b>[EN]:</b> Use it when you want to say \"(I always think・・・) when I see or hear something\".&nbsp;<br><img src=\"children-playing-tag.jpg\" />', '[動-辞書形]＋につけ', '[\"電車の中で走り回る子供たちを見る<b>につけ<\\/b>、家庭でしっかりしつけをしろと言いたくなる。\",\"「暑いにつけ寒いにつけ」のような慣用表現で「どんな時も」という気持ちを表すこともある。<div>As in \\\"暑いにつけ寒いにつけ\\\", you can also use it as an idiomatic expression to express a feeling of \\\"whatever\\\".<\\/div>\",\"「何かを見たり聞いたりするたびに（いつも・・・と思う）と言いたい時に使う。\",\"<div>何かにつけて<\\/div><div>何事につけても<\\/div><div>それにつけても<\\/div>\",\"At the end of the sentence, a verb showing one’s feeling will come　「~と思う」「という気持ちになる」\"]', 'N2', '2026-04-02 16:01:07'),
(575, '<div>~につれ / ~につれて</div>', '<b>As~ ; With~ (when one the changes so does the other)</b><br><br><b>[JP]:</b> 「～」と一緒に変化することを表す。<br><b>[EN]:</b> When you want to say \"something else changes along with a change in ~\".<br><img src=\"20170905153911student-studyabroad-2_thumb.jpg\" />', '[動-辞書形・名]＋につれて・につれ', '[\"留学生活が長くなる<b>につれて<\\/b>、国のことを思い出すことが少なくなったような気がする。\",\"「~とともに」；「~にしたがって」\",\"「～」と一緒に変化することを表す。\"]', 'N2', '2026-04-02 16:01:07'),
(576, '<div>~にとって(は) / ~にとっての / ~にとっても</div>', '<b>For~ ; To~ (a judgment or assessment will follow this expression)</b><br><br><b>[JP]:</b> 「～」の立場から見てどうであるかを言う時に使う。「・・・」には「難しい、大切だ」などの評価を表す言葉が続く。<br><b>[EN]:</b> Whe you say how something is seen of percieved from the point of view of \"~\". This is followed by \"・・・\", using words that assess, such as 難しい、大切だ<br><img src=\"watch-2.jpg\" />', '[名]＋にとって', '[\"この写真は私<b>にとって<\\/b>、何よりも大切なものです。\",\"You can not use words that express your attitude about a certain thing such as 「賛成、反対、好き、嫌い」\",\"「～」の立場から見てどうであるかを言う時に使う。「・・・」には「難しい、大切だ」などの評価を表す言葉が続く。\"]', 'N3', '2026-04-02 16:01:07'),
(577, '<div>~に 伴[ともな]い / ~に 伴[ともな]う / ~に 伴[ともな]って</div>', '<b>With~ (happen at the same time)</b><br><br><b>[JP]:</b> 中心になることと同時に、他の事も一緒に起きる時に使う。変化を表す時にも使う。<br><b>[EN]:</b> As in \"道路工事に伴う通行止め\", use it when the focus of the sentence (road construction) simultaneously produces a concurrent result (a closed road). You can also use it to express a change.<br><img src=\"16b7618f03db2d3f60692b4e06722d36.jpg\" />', '[名]＋に伴って・に伴い<div>[名]＋に伴う＋[名]</div>', '[\"本州移転<b>に伴って<\\/b>、最新のコンピューターシステムが導入されることになった。\",\"中心になることと同時に、他の事も一緒に起きる時に使う。変化を表す時にも使う。\"]', 'N2', '2026-04-02 16:01:07'),
(578, '<div>~に 反[はん]し/ ~に 反[はん]した / ~に 反[はん]して / ~に 反[はん]する</div>', '<b>Against~ ; Contrary to~</b><br><br><b>[JP]:</b> 「予想したことや期待したことと反対の結果や状態になった」と言いたくない時にも使う。<br><b>[EN]:</b> Use this when you want to say \"the result or situation has become opposite of what was predicted or expected\".<br><img src=\"BK-453213370X_3L.jpg\" />', '[名]＋に反して・に反し<div>[名]＋に反する・に反した＋[名]</div>', '[\"今回の経済政策は国民の期待<b>に反して<\\/b>、まったく効果がなかった。\",\"「予想したことや期待したことと反対の結果や状態になった」と言いたくない時にも使う。\"]', 'N2', '2026-04-02 16:01:07'),
(579, '<div>~にほかならない</div>', '<b>There is no doubt that~</b><br><br><b>[JP]:</b> 「～以外の他の物ではない」ことを表す。「一番の理由・大切なこと・問題になることは～だ」と強く言いたいときに使われる。<br><b>[EN]:</b> States that something \"is nothing other than ~\". It\'s used when you want to strongly say \"~ is the biggest reason / reason / important / a problem\".<br><img src=\"paste-20173461389313.jpg\" />', '[名]＋にほかならない', '[\"今回のプロジェクトの成功は、チームワークの勝利<b>にほかなりません<\\/b>。\",\"「～以外の他の物ではない」ことを表す。「一番の理由・大切なこと・問題になることは～だ」と強く言いたいときに使われる。\",\"理由を表す「から・ため」にもつて、原因・理由・根拠を強調する言い方になる。<div>You can also say it with \\\"から・ため\\\", wich emphasizes a cause, reason or basis.<\\/div>\"]', 'N2', '2026-04-02 16:01:07'),
(580, '<div>~にもかかわらず</div>', '<b>However~ ; Though~</b><br><br><b>[JP]:</b> 「～なのに」という意味で、その状態から予想することと実際が違うという意味で使う。<br>~を気にしないで~<br><b>[EN]:</b> Means \"although / despite ~\". Use it when you mean that something is actually different form what one would expect from the situation.<br><img src=\"184451368.jpg\" />', '[動-て形-いる・た形 / い形 / 名]＋にもかかわらず<div>[な形 / 名]＋である＋にもかかわらず</div>', '[\"彼は熱がある<b>にもかかわらず<\\/b>、サッカーの試合に出場した。\",\"「～なのに」という意味で、その状態から予想することと実際が違うという意味で使う。<br>~を気にしないで~\",\"[な形；名]don\'t use [だ]。[~である]can be used.\"]', 'N2', '2026-04-02 16:01:07'),
(581, '<div>~に 基[もと]づいて / ~に 基[もと]づいた / ~に 基[もと]づき / ~に 基[もと]づく</div>', '<b>On the basis of~</b><br><br><b>[JP]:</b> 基準や参考にしたものを言う時に使う。<br><b>[EN]:</b> Use this when you mention something which was used as a basis or reference.<br><img src=\"paste-27925877358593.jpg\" />', '[名]＋に＋基づいて・基づき<div>[名]＋に＋基づく・基づいた＋[名]</div><div>[名]＋を＋基に・基して</div>', '[\"集めた資料<b>に基づいて<\\/b>、論文を書いた。\",\"「~をもとに」\",\"基準や参考にしたものを言う時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(582, '~によって / &nbsp;~による', '<b></b><br><br><b>[JP]:</b> 何かを行う時の手段、方法を表す。<br><b>[EN]:</b> Expresses the means or method by which something is done.<br><img src=\"72ddf405-a46c-4b42-bcb6-b844b3798cb6.jpg\" />', '[名]＋によって<div>[名]＋による＋[名]</div>', '[\"問題は話し合い<b>によって<\\/b>解決した方がいい。\",\"何かを行う時の手段、方法を表す。\"]', 'N3', '2026-04-02 16:01:07'),
(583, '<div>~によると / ~によれば</div>', '<b></b><br><br><b>[JP]:</b> 情報を何で知ったかを言いたい時に使う。<br><b>[EN]:</b> When you want to say where you got some information from.<br><img src=\"paste-30210799960065.jpg\" />', '[名]＋によると・によれば', '[\"今朝の新聞<b>によると<\\/b>、来年度、２つの大学が新設されるそうだ。\",\"情報を何で知ったかを言いたい時に使う。\",\"文の終わりは「～そうだ \\/ ～ということだ」などの形になる。\"]', 'N3', '2026-04-02 16:01:07'),
(584, '<div>~にわたった / ~にわたって / ~にわたり / ~にわたる</div>', '<b>Ranging from~ ; Covering~ ; Lasting~ ; Extending over~</b><br><br><b>[JP]:</b> 時間や場所の範囲全部でという意味で使う。<br><b>[EN]:</b> Use this to mean throughout a long length of time or wide areas as in \"1週間にわたって雨が降り続いた\" and \"高速道路は50キロにわたって渋滞している\".<br><img src=\"1527761151.jpg\" />', '[名]＋にわたって・にわたり<div>[名]＋にわたる・にわたった＋[名]</div>', '[\"台風で電線が切れ、この町は全域<b>にわたって<\\/b>停電した。\",\"時間や場所の範囲全部でという意味で使う。\"]', 'N2', '2026-04-02 16:01:07'),
(585, '~ぬきで (は) / ~ぬきに(は) / ~ぬきの / (~を)ぬきにして(は) / はぬきにして', '<b>Without~&nbsp;</b><br><br><b>[JP]:</b> 普通はその中にあるものがなかったり、通常そこにいる人がいなかったりする状態を言う時に使う。<br><b>[EN]:</b> When you describe a situation in which something usually found in something is not there, or when a person usually found somewhere is not there.<br><img src=\"breakfast.jpg\" />', '[名]＋ぬきで', '[\"朝食<b>ぬきで<\\/b>会社へ行くサラリ-マンが多いらしい。\",\"普通はその中にあるものがなかったり、通常そこにいる人がいなかったりする状態を言う時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(586, '<div>~ぬく</div>', '<b>Do (one’s best) till the end</b><br><br><b>[JP]:</b> 「苦しくても最後まで頑張って～をする」という意味で使われる。なた、「非常に～する」という意味を表すこともある。<br><b>[EN]:</b> \"I\'ll do my best to do ~ to the end, even if it\'s difficult.\". It can also express \"do ~ an extreme amount.\"<br><img src=\"21-important-lessons-from-failure.jpg\" />', '[動-ます形]＋ぬく', '[\"途中、失敗もありましたが、なんとかこの仕事をやり<b>ぬく<\\/b>ことができました。\",\"「苦しくても最後まで頑張って～をする」という意味で使われる。なた、「非常に～する」という意味を表すこともある。\"]', 'N2', '2026-04-02 16:01:07'),
(587, '<div>~のみならず</div>', '<b>Not only~ but also ; Besides~ ; Moreover~</b><br><br><b>[JP]:</b> 「～だけでなく」と同じように使う。<br><b>[EN]:</b> Same meaning as [～だけでなく].<br><img src=\"CStore_Web.jpg\" />', '[動/い形/名・の普通形-○]＋のみならず<div>[な形・名]＋である＋のみならず</div>', '[\"現在、日本のコンビニは若者<b>のみならず<\\/b>、あらゆる世代の人々に様々な目的で利用されている。\",\"「～だけでなく」と同じように使う。\",\"[な形；名]don\'t use [だ]. [~である]can be used.<div>「ただ～のみならず」「ひとり～のみならず」can be used.<\\/div>\"]', 'N2', '2026-04-02 16:01:07');
INSERT INTO `grammar_lessons` (`id`, `structure_name`, `meaning`, `usage_rules`, `examples`, `level`, `created_at`) VALUES
(588, '<div>~のもとで / ~のもとに</div>', '<b>Owing to~</b><br><br><b>[JP]:</b> 「何か大きい影響力のある者の下で」という時や、「その条件や状況の中で」と言いたい時に使う。<br><b>[EN]:</b> When you want to say that something is \"under someone with some great influence\" as in \"教授のもと\", or when you want to say that something is \"under certain conditions or a situation\" as in \"協力のもと\"<br><img src=\"ts_ronbun-eyecatch.jpg\" />', '[名]＋のもとで', '[\"鈴木教授のご指導<b>のもとで<\\/b>、卒業論文を完成させた。\",\"「何か大きい影響力のある者の下で」という時や、「その条件や状況の中で」と言いたい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(589, '<div>~ばかりか / ~ばかりではなく / ~ばかりでなく</div>', '<b>Not Only~</b><br><br><b>[JP]:</b> 「AだけでなくB(も)」という意味で使う。<br><b>[EN]:</b> Is used to mean \"not just A, but also B\".<br><img src=\"6510934443_8bd2942b79_b.jpg\" />', '[名詞修飾型]＋ばかりでなく...も', '[\"林さんのお宅でごちそうになった<b>ばかりか<\\/b>、おみやげまでいただいた。\",\"「AだけでなくB(も)」という意味で使う。\",\"「名-の」does not use「の」&nbsp;\"]', 'N3', '2026-04-02 16:01:07'),
(590, '<div>~ばかりに</div>', '<b>Because of~ ; On account of~ (shows regret over the cause of some bad result)</b><br><br><b>[JP]:</b> 「～だけは原因で(悪い結果になってしまって残念だ)」と言いたい時に使う。<br><b>[EN]:</b> When you want to say (\"It\'s unfortunate that things turned out badly) just because of ~\"<br><img src=\"paste-12073153069057.jpg\" />', '[名詞修飾型]＋ばかりに<div>[な形 / 名]＋である＋ばかりに</div>', '[\"本当のことを言った<b>ばかりに<\\/b>、彼を怒らせてしまった。\",\"「～だけは原因で(悪い結果になってしまって残念だ)」と言いたい時に使う。\",\"[名-の] uses [名-な]\"]', 'N2', '2026-04-02 16:01:07'),
(591, '<div>(~を)はじめ / (~を)はじめすると</div>', '<b>Not only~ but also~ ; ~among other things</b><br><br><b>[JP]:</b> 代表的な例を出して、「～だけでなく他にもたくさん」と言いたい時に使う。<br><b>[EN]:</b> When you want to say \"not just ~, but many others\" by giving a typical example.<br><img src=\"図1.jpg\" />', '[名]＋をはじめ<div>[名]＋をはじめとして</div><div>[名]＋をはじめとする＋[名]</div>', '[\"<div>上野動物園にはパンダを<b>はじめ<\\/b>、子供達に人気がある動物がたくさんいます。<\\/div>\",\"代表的な例を出して、「～だけでなく他にもたくさん」と言いたい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(592, '<div>~はともかく(として)</div>', '<b>Regardless of~</b><br><br><b>[JP]:</b> 「～」については今は考えないで、他の点について言いたい時に使う。<br><b>[EN]:</b> When you want to say that you are not thinking about \"~\" now, but about other things instead.<br><img src=\"CHINAFASHION032409.jpg\" />', '[名]＋はともなく (として)', '[\"この洋服は、デザイン<b>はともなく<\\/b>、色がよくない。\",\"「～かどうか」「疑問詞+か」「動詞+か」と一緒に使うこともある。\",\"「～」については今は考えないで、他の点について言いたい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(593, '<div>~ば~ほど</div>', '<b>The more~the more~(as one goes up, so does the other)</b><br><br><b>[JP]:</b> 1つの事柄の程度に合わせて別の事柄も変わると言う時に使う。<br><b>[EN]:</b> When you say that the more one thing is done, the more something else will change accordingly<br><img src=\"440985-300x244.jpg\" />', '[動-ば]＋[動-辞書形]＋ほど<div>[い形-ければ]＋[い形-い]＋ほど</div><div>[な形-なら・であらば]＋[な形-な・である]＋ほど</div><div>[名-なら・であらば]＋[名-である]＋ほど</div>', '[\"練習<b>すればするほど<\\/b>上手になります。\",\"1つの事柄の程度に合わせて別の事柄も変わると言う時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(594, '<div>~はもちろん / ~はもとより</div>', '<b>Even~ ; Of course~</b><br><br><b>[JP]:</b> スピーチ・プレゼンテーションなどで「～はもちろん、～だけでなくそのほかにも」と説明したい時に使う。<br><b>[EN]:</b> When you want to explain in a speech, presentation or the like that \"~\" is obvious, or that it is not only \"~\" but also something more.<br><img src=\"2013012100020_1.jpg\" />', '[名]＋はもちろん<div>[名]＋はもとより</div>', '[\"この温泉は、日本人は<b>もとより<\\/b>、外国人にも大変人気があります。\",\"「~はもとより」is formal language\",\"スピーチ・プレゼンテーションなどで「～はもちろん、～だけでなくそのほかにも」と説明したい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(595, '<div>~ 反面[はんめん] / ~ 半面[はんめん]</div>', '<b>On one side~ ; On the other side~</b><br><br><b>[JP]:</b> あることに関して、二つの反対の面や視点があることを説明する時に使う。<br><b>[EN]:</b> Use this when you want to explain that there are two aspects or perspectives pertaining to something.<br><img src=\"iStock-636831102.jpg\" />', '[動/い形/な形]・の名詞修飾型＋反面・半面<div>[な形 / 名]＋である＋反面・半面</div>', '[\"来日前は留学に期待する<b>反面<\\/b>、不安も大きかった。\",\"[~である]can be used.\",\"あることに関して、二つの反対の面や視点があることを説明する時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(596, '<div>~べき / ~べきだ</div>', '<b>Should~</b><br><br><b>[JP]:</b> 一般的に、～するのが当然だ、～するのが正しいと言う時に使う。<br><b>[EN]:</b> When you say that doing \"~\" is generally the natural thing or correct thing to do.<br><img src=\"paste-137842680397825.jpg\" />', '[動-辞書形]＋べき', '[\"書く前に注意<b>すべき<\\/b>点を説明します。\",\"一般的に、～するのが当然だ、～するのが正しいと言う時に使う。\",\"「する」becomes 「すべき」\"]', 'N3', '2026-04-02 16:01:07'),
(597, '<div>~べきではない</div>', '<b>Shouldn’t~</b><br><br><b>[JP]:</b> ～しないのが当然だと言う時に使う。<br><b>[EN]:</b> When not doing \"~\" is the natural thing to do.<br><img src=\"paste-138843407777793.jpg\" />', '[動-辞書形]＋べきではない', '[\"先生のお宅に、こんな夜中に電話する<b>べきではない<\\/b>\",\"If it\'s about other person\'s conduct, it has a stron meaning that says \\\"You must not do shuch a thing\\\"\",\"～しないのが当然だと言う時に使う。\",\"「する」becomes 「するべきではない」\"]', 'N3', '2026-04-02 16:01:07'),
(598, '<div>(~より)ほか(は)ない / ほかしかたがない</div>', '<b>Only~ ; just~ (there is no other way)</b><br><br><b>[JP]:</b> 「～しかない」と同じように使う。<br><b>[EN]:</b> When you say that given the current situation, only this approach (as expressed by \"~\") is available, or that this is the best. This expression is also often used to say something along the lines of \"it can\'t be helped\".<br><img src=\"new-10-things-to-do-by-yourself-2.jpeg\" />', '[動-辞書形]＋ほかない', '[\"だれにも頼めないから、自分でやる<b>ほかはない。<\\/b>\",\"～しかない\",\"「～しかない」と同じように使う。\"]', 'N3', '2026-04-02 16:01:07'),
(599, '<div>~ほど / ~ほどだ / ~ほどの</div>', '<b></b><br><br><b>[JP]:</b> 「・・・」の状態・程度が普通ではないことを、「～」の例を使って表す時に使う<br><b>[EN]:</b> To describe the unusual condition or degree of 「・・・」 by using 「～」&nbsp;as an example.<br><img src=\"600guitarists.jpg\" />', '[動-辞書形・ます形-たい・ない形-ない / い形-い / な形-な / 名]＋ほど', '[\"会場にあふれる<b>ほど<\\/b>、ギターを持った若者が集まっていた。\",\"「・・・」の状態・程度が普通ではないことを、「～」の例を使って表す時に使う\"]', 'N3', '2026-04-02 16:01:07'),
(600, '~ほど...はない', '<b>Nothing is more~ than~</b><br><br><b>[JP]:</b> 「～」が一番・・・だと強調したいときに使う。<br><b>[EN]:</b> When you want to emphasize that \"~\" is the most \"・・・\".<br><img src=\"220h44bedc860b4d20966bc364724ff14024.jpg\" />', '[動-辞書形-こと / 名]＋ほど…ない', '[\"仲のいい友達と旅行する<b>ほど<\\/b>楽しいこと<b>はない。<\\/b>\",\"~くらい\",\"「～」が一番・・・だと強調したいときに使う。\"]', 'N3', '2026-04-02 16:01:07'),
(601, '<div>~まい / ~まいか</div>', '<b>Probably not~;&nbsp;Will not~</b><br><br><b>[JP]:</b> 状況などから判断して、「～の可能性は非常に少ないだろう」と言いたい時に使われる。<br><b>[EN]:</b> When you want to say that judging from a situation or the like, \"there\'s very little possibility of ~\".<br><img src=\"bad-economy.jpg\" />', '[動-辞書形]＋まい', '[\"世界経済は状況から見て、すぐに好転することはある<b>まい<\\/b>。我が社も早急に対策を考えなければならない。\",\"「絶対～するのはやめよう」という強く意志を表すこともある。<div>You can also use it to express a strong determination to \\\"absolutley stop doing ~\\\".<\\/div>\",\"状況などから判断して、「～の可能性は非常に少ないだろう」と言いたい時に使われる。\",\"Use 「~まいと思っているらしい \\/ ~まいと思っているようだ」when subject is Third Person.\"]', 'N2', '2026-04-02 16:01:07'),
(602, '<div>~ 向[む]けだ / ~ 向[む]けに / ~ 向[む]けの</div>', '<b>Bound for~ ; Made for~</b><br><br><b>[JP]:</b> ある特定の人やグループのためのものだということを表す時に使う。<br><b>[EN]:</b> When you express that something is for a specific group or person.<br><img src=\"mvn51103-1.jpg\" />', '[名]＋向け', '[\"ここにある軽量のクリスマスカードは、みんな海外<b>向けだ<\\/b>。\",\"ある特定の人やグループのためのものだということを表す時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(603, '<div>~もかまわず</div>', '<b>Regardless of~</b><br><br><b>[JP]:</b> 「普通は気にしたほうがいいことを、無視して・・・する」と言いたい時に使う。批判的に使うことが多い。<br><b>[EN]:</b> Use it when you want to say \"do ・・・ while ignoring that this is something one would normally be concerned about\". It is often used to citicize.<br><img src=\"paste-27453430956033.jpg\" />', '[名]＋もかまわず', '[\"住民の迷惑<b>もかまわず<\\/b>、夜中にバイクで走り回るのはやめてほしい。\",\"「普通は気にしたほうがいいことを、無視して・・・する」と言いたい時に使う。批判的に使うことが多い。\",\"ところかまわず: &nbsp;indiscriminately; no matter where\"]', 'N2', '2026-04-02 16:01:07'),
(604, '<div>~も~なら~も / ~も~ば~も</div>', '<b>Neither~or~ ; Both~and~</b><br><br><b>[JP]:</b> プラスイメージの言葉を重ねて「よい点が多くある」と言う時と、マイナスイメージの言葉を重ねて、「悪い点が多くある」と言うときに使われる。「いろいろある」という意味を表すこともある。<br><b>[EN]:</b> This is used with positive words to say there are many good points about something, or with negative words to say there are many bad points about something. It can also express variety as in \"家で食べる日もあれば外で食べる日もある\".<br><img src=\"paste-37911676321793.jpg\" />', '[名]＋も＋[動-ば・い形-ければ・な形-なら]＋[名]＋も', '[\"今度できたスーパーは品数<b>も<\\/b>多<b>ければ<\\/b>値段<b>も<\\/b>安いので、大人気だ。\",\"プラスイメージの言葉を重ねて「よい点が多くある」と言う時と、マイナスイメージの言葉を重ねて、「悪い点が多くある」と言うときに使われる。「いろいろある」という意味を表すこともある。\"]', 'N2', '2026-04-02 16:01:07'),
(605, '<div>~もので</div>', '<b>Because~ (give a reason to an explanation).</b><br><br><b>[JP]:</b> 自分側の理由があって、今の状況なのだと丁寧に説明する時に使われる。<br><b>[EN]:</b> When giving a polite explanation to provide your reason for the current situation.<br><img src=\"map-reading_2143007b.jpg\" />', '[名詞修飾型・名-&gt;な]＋もので・ものですから', '[\"「一人で行ける。」「うん、大丈夫、地図を持っている<b>もの<\\/b>。」\",\"Used in conversations by women and children. &nbsp;「~もん」is more informal\",\"自分側の理由があって、今の状況なのだと丁寧に説明する時に使われる。\",\"sometimes conjugated with「です」「ます」\"]', 'N3', '2026-04-02 16:01:07'),
(606, '<div>~もの(です)か</div>', '<b>By no means~ ; Not~at all</b><br><br><b>[JP]:</b> 独り言なので、「決して～しない」と自分の気持ちを強く言いたい時に使う。相手の言ったことを、「絶対～ではない・～は違う」と否定する時にも使う。<br><b>[EN]:</b> When you want to strongly state, to yourself or someone else, a feeling you have that \"it\'s definetly not ~\". You can also use it to refute what another person has said, as in \"it\'s absolutely not ~; ~ is wrong.\" In colloquial speech use \"～もんか\" or \"～もんですか\".<br><img src=\"restaurant-frustration2-bad-service-390x220.jpg\" />', '[名詞修飾型]＋ものか/もんか・ものですか/もんですか', '[\"こんなサービスの悪い店には二度と来る<b>もんか<\\/b>。\",\"When spoken, or between friends 「~もんか」or「~もんですか」is used\",\"独り言なので、「決して～しない」と自分の気持ちを強く言いたい時に使う。相手の言ったことを、「絶対～ではない・～は違う」と否定する時にも使う。\",\"[名-の] uses [名-な]\"]', 'N2', '2026-04-02 16:01:07'),
(607, '<div>~ものがある</div>', '<b>Feel like~</b><br><br><b>[JP]:</b> 「～感じがする」と言いたい時に使う。「具体的に何とは言えないが、そう思われる要素がある」と言う時にも使われる。<br><b>[EN]:</b> Use it when you want to say something \"seems ~\". This expression is used when something makes you think in a certain way, but you cannot say exactly what it is.<br><img src=\"10d318fc54ea34a091477d5f55693620.png\" />', '[動/い形/な形]・の名詞修飾型＋ものがある', '[\"世界中で大ヒットした歌には、世代を超えて人々の心に響く<b>ものがある。<\\/b>\",\"「～感じがする」と言いたい時に使う。「具体的に何とは言えないが、そう思われる要素がある」と言う時にも使われる。\",\"現在形だけ\"]', 'N2', '2026-04-02 16:01:07'),
(608, '<div>~ものだ / ~ものではない</div>', '<b>remember a past happening or occurrence</b><br><br><b>[JP]:</b> 過去のことを思い出して懐かしいと思う気持ちを表す。心に強く思ったことを言いたいときにも使う。<br><b>[EN]:</b> It is often used to express nostalgic memories form the past and one\'s feelings. You can also use this when you want to state a strongly held opinion.<br><img src=\"paste-10857677324289.jpg\" />', '[動/い形-い/な形-な]・の普通形＋ものだ', '[\"昔はよく友達と近くの川で泳いだ<b>ものだ。<\\/b>\",\"過去のことを思い出して懐かしいと思う気持ちを表す。心に強く思ったことを言いたいときにも使う。\"]', 'N2', '2026-04-02 16:01:07'),
(609, '<div>~ものなら</div>', '<b>If~(wish for something unattainable ; tell someone it is impossible)</b><br><br><b>[JP]:</b> 現実には無理だと思っていることを強く希望する時に使う。<br><b>[EN]:</b> Use this when you very much want something that you actually think is impossible.<br><img src=\"paste-14663018348545.jpg\" />', '[動-辞書形]＋ものなら・もんなら', '[\"子供のころから星好きだったので、行ける<b>ものなら<\\/b>宇宙旅行に行ってみたいと思っています。\",\"可能の意味を待つ動詞の辞書形も使われる。<div>Dictionary forms of verbs that indicate possibility are also used.<\\/div>\",\"現実には無理だと思っていることを強く希望する時に使う。\",\"<div>会話では「もんなら」になる。<\\/div>It becomes \\\"もんなら\\\" in casual conversation.\"]', 'N2', '2026-04-02 16:01:07'),
(610, '<div>~ものの</div>', '<b>Though~</b><br><br><b>[JP]:</b> 「～は事実だけれども」という気持ちを強く言いたい時に使う。事実を強調するために、助詞「は」を使うことが多い。<br><b>[EN]:</b> When you really want to say you feel that \"even tough the fact is ~ (I wanted it and brought it),\" as in \"欲しくて買ったものの\". The particle 「は」 is often used to emphasize the fact.<br><img src=\"carousel.jpg\" />', '[動/い形/な形]・の名詞修飾型＋ものの<div>[な形 / 名]＋で(は)ある＋ものの</div>', '[\"水泳教室に通ってはいる<b>ものの<\\/b>、いまだに25メートルしか泳げない。\",\"「~とはいうものの」is often used. &nbsp;Especially with nouns [名＋とはいうものの]\",\"「～は事実だけれども」という気持ちを強く言いたい時に使う。事実を強調するために、助詞「は」を使うことが多い。\",\"「～ている・～てみる」などは「～て<u>は<\\/u>いる」のように「は」が入ることが多い。\"]', 'N2', '2026-04-02 16:01:07'),
(611, '<div>~やら~やら</div>', '<b>~And~among other things (etc)</b><br><br><b>[JP]:</b> 「AやBなど」「AたりBたり」と同じ意味で、例をあげて、いろいろあって大変だったり驚いたりした気持ちを表す。どちらかはっきりわからないことを表す場合もある。<br><b>[EN]:</b> \"AやらBやら\" has the same meaning as \"AやBなど\" and \"AたりBたり\" by giving examples and expresses a sense of adversity or suprise for various reasons. It is also used to express that you are not quite sure which is the reason.<br><img src=\"enhanced-buzz-32397-1370986531-1.jpg\" />', '[動-辞書形・い形-い・名]＋やら＋[動-辞書形・い形-い・名]＋やら', '[\"部屋代<b>やら<\\/b>、交通費<b>やら<\\/b>、日本はとにかくお金がかかる。\",\"「AやBなど」「AたりBたり」と同じ意味で、例をあげて、いろいろあって大変だったり驚いたりした気持ちを表す。どちらかはっきりわからないことを表す場合もある。\"]', 'N2', '2026-04-02 16:01:07'),
(612, '<div>~ようがない / ~ようもない</div>', '<b>No way to~</b><br><br><b>[JP]:</b> 「理由があって～をすることができない」と言いたい時に使う。<br><b>[EN]:</b> As in \"私も知らないから教えようがない\", use it when you want to say \"because of (I don\'t know either), I can\'t ~ (tell you).\" When you say it as \"どうしょうもない\", it means there is nothing you can do.<br><img src=\"plane-snow-684987.jpg\" />', '[動-ます形]＋ようがない', '[\"出張の予定だったが、大雪で飛行機が欠航したしまったので行き<b>ようがない<\\/b>。\",\"「どうしょうもない」という言い方は、できることが何もないという意味。\",\"「理由があって～をすることができない」と言いたい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(613, '<div>~ような / ~ように</div>', '<b></b><br><br><b>[JP]:</b> 似ているものを言って、様子や状況を説明するときに使う。<br><b>[EN]:</b> Like~ &lt;show an example&gt;<br><img src=\"sinki_Omote.jpg\" />', '[動-辞書形・た形・て形-いる / 名-の]＋ように+[動]・ような+[名]・ようだ', '[\"ここに書いてある<b>ように<\\/b>申込書に記入してください。\",\"「似ている」；「～っぽい」\",\"似ているものを言って、様子や状況を説明するときに使う。\",\"魚のように泳ぎたい。&lt;metaphor&gt;<div>かれは部屋にいないようです。&lt;a guess&gt;<\\/div>\"]', 'N3', '2026-04-02 16:01:07'),
(614, '<div>&nbsp;~ように</div>', '<b></b><br><br><b>[JP]:</b> 何かをする目的がある時に使う<br><b>[EN]:</b> So that~ &lt;show a goal(objective)&gt;<br><img src=\"250px-Otvorena_knjiga.JPG\" />', '[動-辞書形 / ない形-ない]＋ように', '[\"この本は小学生でも読める<b>ように<\\/b>ルビがつけてあります。\",\"何かをする目的がある時に使う\",\"<div>ここに、タバコを吸わないようにと書いてあります。&lt;indirect command&gt;<\\/div><div>自転車に乗れるようになりました。&lt;show change&gt;<\\/div>\"]', 'N4', '2026-04-02 16:01:07'),
(615, '<div>~わけがない / ~わけはない</div>', '<b>No reason for~</b><br><br><b>[JP]:</b> そんなことは絶対考えられないと、強く否定したい時に使う。<br><b>[EN]:</b> When you want to strongly deny something because it is absolutely unthinkable.<br><img src=\"I&#39;m%20Not%20Like%20Other%20Girls.jpg\" />', '[名詞修飾型]＋わけがない', '[\"あんな下手な絵が売れる<b>わけがない。<\\/b>\",\"そんなことは絶対考えられないと、強く否定したい時に使う。\",\"Use 「ないわけがない」 when you say with confidence that \\\"~\\\" must be true.\"]', 'N3', '2026-04-02 16:01:07'),
(616, '<div>~わけだ</div>', '<b>state a reason why something is</b><br><br><b>[JP]:</b> 思っていたことの理由がわかって「やっぱり」「なるほど」と納得した時に使う。<br><b>[EN]:</b> As in \"開かないわけだ、鍵がかかっているよ\", use this when you come to understand that something is the case (it won\'t open) because of a certain reason (it\'s locked), as if to say \"ah ha\" or \"now I see\". When you don\'t know the reason, use \"というわけか\".<br><img src=\"paste-35158602285057.jpg\" />', '[名詞修飾型]＋わけだ・というわけだ</div>', '[\"A: このチョコ、1粒1,000円もするんだよ。<div>B: え！本当？じゃあ、おいしい<b>わけ<\\/b>よね。<\\/div>\",\"思っていたことの理由がわかって「やっぱり」「なるほど」と納得した時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(617, '<div>~わけではない / ~わけでもない</div>', '<b>It doesn’t mean that~</b><br><br><b>[JP]:</b> 「～の状況や気持ち・理由ではない」と否定する時に使う。相手の考えや一般的な判断を否定する時に使う。100％そうだと言いたくない時にも使う。<br><b>[EN]:</b> When you make a denial as in \"that\'s not the situation; it doesn\'t feel like that; not for that reason.\" Use it when you refute another person\'s idea or a typical judgament as in \"病気が治ったわけではない\". You can also use it when you do not want to say that something is 100% for sure, as in \"嫌いなわけではない\".<br><img src=\"Reckless-Spending-e1480501169757.jpg\" />', '[名詞修飾型]＋わけではない・わけじゃない', '[\"生活に困っている<b>わけではない<\\/b>が、貯金する余裕はない。\",\"「～の状況や気持ち・理由ではない」と否定する時に使う。相手の考えや一般的な判断を否定する時に使う。100％そうだと言いたくない時にも使う。\"]', 'N2', '2026-04-02 16:01:07'),
(618, '<div>~わけにはいかない<br>~わけにもいかない</div>', '<b>Mustn’t&nbsp;</b><br><br><b>[JP]:</b> 「理由があってできない」と言いたい時に使う。<br><b>[EN]:</b> When you want to say \"thare\'s a reason I can\'t\" as in \"休むわけにはいかない\".<br><img src=\"mlJxdgw.jpg\" />', '[動-辞書形]＋わけにはいかない', '[\"A: Bさん、顔色悪いよ。今日は無理しないで早退したら？<div>B: でも、午後から大事な会議があるから帰る<b>わけにはいかなくて<\\/b>・・・<\\/div>\",\"「理由があってできない」と言いたい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(619, '<div>~わけにはいかない / ~わけにもいかない</div>', '<b>Must~</b><br><br><b>[JP]:</b> 「しなければならない」と言いたい時に使う。<br><b>[EN]:</b> When you want to say \"I have to\" as in \"働かないわけにはいかない\".<br><img src=\"123141-004-9B7F5072.jpg\" />', '[動-ない形]＋ないわけにはいかない', '[\"A: 今から飛行機の予定は無理ですよ。<div>B: そこをなんとか。取引先でシステムトラブルがあって、私は行かない<b>わけにはいかない<\\/b>んですよ。<\\/div>\",\"「しなければならない」と言いたい時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(620, '<div>~をきっかけとして / ~をきっかけに(して)</div>', '<b>Through~ ; By~ (something happens unexpectedly through a chance encounter)</b><br><br><b>[JP]:</b> 何かが始まったり、変わったりしたときに、その原因・理由になった出来事を表す時に使う。<br><b>[EN]:</b> To express the factor or reason for why something happened that led to a new beginning or change.<br><img src=\"45ecc1eb7862661abf1eecd4b202cc4f_s.jpg\" />', '[名]＋をきっかけに', '[\"留学を<b>きっかけに<\\/b>、自分の国についていろいろ考えるようになった。\",\"何かが始まったり、変わったりしたときに、その原因・理由になった出来事を表す時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(621, '<div>~を 契機[けいき]として / ~を 契機[けいき]に(して)</div>', '<b>Since~ (Because a thing happened, a big change has occurred)</b><br><br><b>[JP]:</b> 「きっかけ」と同じ意味・用法で社会的、歴史的に大きいことを言いたい時に使う。プラスの意味の文に使うことが多い。<br><b>[EN]:</b> To express the factor or reason for why something socially or historically important happened that led to a new beginning or change. It\'s often used in sentences with a positive meaning.<br><img src=\"paste-56487409876993.jpg\" />', '[名]＋を契機に', '[\"オイルショックを<b>契機に<\\/b>新エネルギ-の研究が進められた。\",\"「きっかけ」と同じ意味・用法で社会的、歴史的に大きいことを言いたい時に使う。プラスの意味の文に使うことが多い。\"]', 'N2', '2026-04-02 16:01:07'),
(622, '<div>~を 込[こ]めて</div>', '<b>Full of~ ; Loaded with~ &lt;put emotion into&gt;</b><br><br><b>[JP]:</b> 「愛情、思いなどの気持ちを入れて（・・・する）」という意味で使う。<br><b>[EN]:</b> Use it to mean \"do ・・・with a lot of love, thought or the like.<br><img src=\"paste-32706175959041.jpg\" />', '[名]＋を込めて', '[\"当店では一つ一つのお菓子を、心<b>を込めて<\\/b>手作りしております。\",\"「愛情、思いなどの気持ちを入れて（・・・する）」という意味で使う。\",\"「心・愛・親しみ・祈り・恨み・怒り」などの言葉と一緒に使われる。\"]', 'N2', '2026-04-02 16:01:07'),
(623, '<div>~を 通[つう]じて / ~を 通[とお]して</div>', '<b>Throughout~</b><br><br><b>[JP]:</b> その間ずっとと言いたい時、「一年・四季・一生」などの言葉と一緒に使う。<br><b>[EN]:</b> Use it on combination with words such as \"一年・四季・一生\" to say that something happened throughout that entire time.<br><img src=\"mawsynram-india.jpg\" />', '[時間の言葉]＋を＋通じて・通して', '[\"あの地方は、１年<b>を通じて<\\/b>雨が多い。\",\"その間ずっとと言いたい時、「一年・四季・一生」などの言葉と一緒に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(624, '<div>~を~とした / ~を~として / ~を~とする</div>', '<b>As~</b><br><br><b>[JP]:</b> 「AをBにする、AがBだ」と言う時に使う。<br><b>[EN]:</b> When you say \"do A as B; A is B\" as in \"地域交流を目的として\" and \"リーダーを中心に\". You can also use \"に\" in place of \"として\".<br><img src=\"20140801_003.jpg\" />', '[名]＋を＋[名]＋とした+[名]・とする・として/に', '[\"チンさんを先生<b>として<\\/b>、中国語の勉強会を開いた。\",\"Nouns that show aim, postion, role, type,etc. come before 「として」。例えば「目的・中心・対象・手本・前提」\",\"「AをBにする、AがBだ」と言う時に使う。\"]', 'N2', '2026-04-02 16:01:07'),
(625, '~を 問[と]わず', '<b>Regardless of~</b><br><br><b>[JP]:</b> お知らせや紹介文などで、「いつでも・どこでも・だれでも」などと説明したい時に使われる。<br><b>[EN]:</b> This is used in an announcement, written introduction and the like to say \"anytime, anywhere, anyone\" and such.<br><img src=\"b4d462.jpg\" />', '[名]＋を問わず', '[\"留学生ならどなたでも国籍、年齢、性別<b>を問わず<\\/b>申し込めます。\",\"「昼夜・国の内外・男女・～の有無」などの言葉と一緒につかわれる。\",\"お知らせや紹介文などで、「いつでも・どこでも・だれでも」などと説明したい時に使われる。\",\"「問う」という動詞の否定形として、文の最後で使うこともある。\"]', 'N2', '2026-04-02 16:01:07'),
(626, '<div>~をめぐって / ~をめぐる</div>', '<b>Circulate~ ; around~</b><br><br><b>[JP]:</b> 「～を話題として」という意味で、「～」について様々な立場、方向から意見を述べたり、争い・紛争・対立などが起きていると言いたいときに使う。<br><b>[EN]:</b> Use it meaning \"about ~\", when you want to say that there is opposition, dispute, conflict, or opinions coming from various directions and positions about \"~\".<br><img src=\"paste-13816909791233.jpg\" />', '[名]＋をめぐって<div>[名]＋をめぐる＋[名]</div>', '[\"<div>遺産<b>をめぐって<\\/b>、兄弟の争いが起こることを父は心配していた。<\\/div>\",\"「～を話題として」という意味で、「～」について様々な立場、方向から意見を述べたり、争い・紛争・対立などが起きていると言いたいときに使う。\"]', 'N2', '2026-04-02 16:01:07'),
(627, '～ 始[はじ]める', '<b></b><br><br><b>[JP]:</b> 時間がかかることが始めるということをはっきり言う時に使う<br><b>[EN]:</b> To clearly stathe the beginning of something that takes time.<br><img src=\"learn-japanese.jpg\" />', '[動-ます形]＋始める', '[\"日本語を習い<b>始めた<\\/b>のは半年前です。\",\"時間がかかることが始めるということをはっきり言う時に使う\"]', 'N3', '2026-04-02 16:01:07'),
(628, '～ 終[お]わる', '<b></b><br><br><b>[JP]:</b> 終わることをはっきり言う時に使う<br><b>[EN]:</b> When you clearly state the end of something<br><img src=\"toba2.gif\" />', '[動-ます形]＋終わる', '[\"その本、読み<b>終わったら<\\/b>貸してもらえませんか。\",\"終わることをはっきり言う時に使う\"]', 'N3', '2026-04-02 16:01:07'),
(629, '～ように 言[い]う', '<b></b><br><br><b>[JP]:</b> 「しろ・するな」「してください」「したほうがいい」などの命令・禁止・指示・助言の内容を伝える時に使う<br><b>[EN]:</b> To tell about a command, prohibition, direction or advice given.<br><img src=\"paste-77622943940609.jpg\" />', '[動-辞書形・ない形-ない]＋ように言う', '[\"先生に宿題を忘れない<b>ように注意された。<\\/b>\",\"「しろ・するな」「してください」「したほうがいい」\",\"「しろ・するな」「してください」「したほうがいい」などの命令・禁止・指示・助言の内容を伝える時に使う\",\"「言う」の代わりに「注意する」「頼む」「伝える」なども使われる\"]', 'N3', '2026-04-02 16:01:07'),
(630, '～という～', '<b></b><br><br><b>[JP]:</b> 内容を言うときによく使う<br><b>[EN]:</b> To describe something<br><img src=\"57558876.jpg\" />', '[普通形]＋という＋[名]', '[\"彼が有名な音楽家だ<b>という<\\/b>ことはあまり知られていない。\",\"内容を言うときによく使う\"]', 'N3', '2026-04-02 16:01:07'),
(631, '～だろうと 思[おも]う', '<b></b><br><br><b>[JP]:</b> はっきり分からないがたぶんそうだと考えた内容を他の人に伝える時に使う<br><b>[EN]:</b> To tell another person about something you think may be true, but you are not completly sure of.<br><img src=\"stock-footage-sad-young-girl-looking-out-the-window-on-a-rainy-day.jpg\" />', '[普通形]-○＋だろうと思う', '[\"たぶんこの雨は1時間ぐらいでやむ<b>だろうと思います。<\\/b>\",\"はっきり分からないがたぶんそうだと考えた内容を他の人に伝える時に使う\"]', 'N3', '2026-04-02 16:01:07'),
(632, '～なさそうだ', '<b></b><br><br><b>[JP]:</b> 何かを見て感じたり、予想したり「～ではない」と思った時に使う<br><b>[EN]:</b> To gess that something is not \"～\" or or think so based on some observation or feeling.<br><img src=\"Slow-cooked-spicy-chicken-square.jpg\" />', '[い形-く / な形-じゃ / 名-じゃ]＋なさそうだ', '[\"このカレーはあまり辛く<b>なさそう<\\/b>ですね。\",\"「増えそうだ」などの動詞の場合は[動-ます形]＋「そうもない；そうにない；そうにもない」と言う。\",\"何かを見て感じたり、予想したり「～ではない」と思った時に使う\"]', 'N3', '2026-04-02 16:01:07'),
(633, '～と', '<b>意外に思ったことに使われることが多く、また「気づいたこと」なので文末は過去形になることが多い。</b><br><br><b>[JP]:</b> 今まで気づかなかった事に気づいた時に使う。<br><b>[EN]:</b> When you have noticed something you had not been aware of until that time.<br><img src=\"nightdarkness.jpg\" />', '[動-辞書形]＋と', '[\"気がつく<b>と<\\/b>、外はすっかり暗くなっていた。\",\"「～たら」にも同じ使い方がある。\",\"今まで気づかなかった事に気づいた時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(634, '～ていく', '<b></b><br><br><b>[JP]:</b> ある動作をしながら遠くへ移動するときや、ある動作をしてから次の場所へ行くことを表すときに使う。将来に向かって続いていくことを言うときにも使う。<br><b>[EN]:</b> To describe how the subject of the sentence will travel a long distance or to say that the subject will go to another place after taking certain action. You can also use it when you say that an action will continue into the future.<br><img src=\"pexels-photo-203088.jpeg\" />', '[動-て形]＋いく', '[\"冬になると渡り鳥は南のほうへ飛<b>んでいく<\\/b>。\",\"反対に、近づく時は「～てくる」を使う。動作や変化が過去から今まで続いていることを言う時にも使う。\",\"ある動作をしながら遠くへ移動するときや、ある動作をしてから次の場所へ行くことを表すときに使う。将来に向かって続いていくことを言うときにも使う。\"]', 'N3', '2026-04-02 16:01:07'),
(635, '～ 続[つつ]ける', '<b></b><br><br><b>[JP]:</b> 動作をずっと続けることや習慣として繰り返すことを強調して言う時に使う。<br><b>[EN]:</b> When you say that an action is going on continuosly, or to emphasize the repetition of a habit or custom.<br><img src=\"paste-11235634446337.jpg\" />', '[動-ます形]＋続ける', '[\"あの人は歯医者に１年以上通い<b>続けている<\\/b>そうです。\",\"動作をずっと続けることや習慣として繰り返すことを強調して言う時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(636, '～なら', '<b></b><br><br><b>[JP]:</b> 「～の場合は」と範囲を検定して、アドバイスをしたり申し出をしたりするときに使う。<br><b>[EN]:</b> To set limits and to provide advice or make a suggestion.<br><img src=\"paste-23648089931777.jpg\" />', '[動-辞書形(-の)・ます形-たい / 欲しい / 名]＋なら', '[\"N3に合格したい<b>なら<\\/b>、このカードをよく勉強したほうがいいよ。\",\"「～なら」の前に「の」（または「ん」）が入ることがありますが、ほとんど同じ意味です。\",\"「～の場合は」と範囲を検定して、アドバイスをしたり申し出をしたりするときに使う。\"]', 'N3', '2026-04-02 16:01:07'),
(637, '～って', '<b></b><br><br><b>[JP]:</b> 名前を表す「～という」の代わりに使う。<br><b>[EN]:</b> Use instead of &nbsp;「～という」 to give a name<br><img src=\"aid5254611-v4-728px-Stop-Thinking-About-Someone-Step-13.jpg\" />', '[名1]＋って＋[名2]', '[\"さっき、上田さん<b>って<\\/b>人が訪ねてきましたよ。お知り合いですか。\",\"名前を表す「～という」の代わりに使う。\"]', 'N3', '2026-04-02 16:01:07'),
(638, '～させてもらう&nbsp;/&nbsp;～させてくれる', '<b></b><br><br><b>[JP]:</b> 自分がすることのために他の人の許可を取る時に使う。許可してくれたことに感謝する時にも使う。<br><b>[EN]:</b> When you obtain permission from another person to do something. You can also use it to express gratitude for receiving permission.<br><img src=\"colleagues-girl-discussing-joint-project-express-their-opinions-group-office-workers-partnership-gathered-table-89291053.jpg\" />', '[動-使役-て形]＋もらう', '[\"この会社は自分の意見を自由に<b>言わせてくれる。<\\/b>\",\"自分がすることのために他の人の許可を取る時に使う。許可してくれたことに感謝する時にも使う。\"]', 'N3', '2026-04-02 16:01:07'),
(639, '～させられる', '<b></b><br><br><b>[JP]:</b> 自分がしたくないと思っていることを、他人からするように言われて、しなければならない時に使う。<br><b>[EN]:</b> When another person tells you to do someting that you do not want to do, but you have to do it anyway.<br><img src=\"woman-cleans-bathroom-toilet-scrub-260nw-426468376.jpg\" />', '～[動-使役受身]', '[\"子供の時テストの成績が悪いと、父にトイレ掃除を<b>させられた。<\\/b>\",\"自分がしたくないと思っていることを、他人からするように言われて、しなければならない時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(640, '～がる', '<b>「～がり」（「暑がり」「寒がり」「怖がり」など）は、よくそのように感じる人という意味の名詞になる。</b><br><br><b>[JP]:</b> その人の気持ちなどが様子や言葉に表れている時に使う。自分の気持ちを言う時は使わないのが普通。<br><b>[EN]:</b> When a person\'s feelings or the like are expressed by his or her manner or speech.<br><img src=\"Abu_Dhabi_Tennis_Math.jpg\" />', '[動-たい形-○ / い形-○ / な形]＋がる', '[\"彼は試合に負けて悔し<b>がって<\\/b>いる。\",\"その人の気持ちなどが様子や言葉に表れている時に使う。自分の気持ちを言う時は使わないのが普通。\"]', 'N3', '2026-04-02 16:01:07'),
(641, '～ 出[だ]す', '<b></b><br><br><b>[JP]:</b> 何かが急に起きた時や、急に始まったと言う時に使われる。<br><b>[EN]:</b> When something happens or starts suddenly<br><img src=\"crying-baby-kids-harbor.jpg\" />', '[動-ます形]＋出す', '[\"さっきまで笑っていた赤ちゃんが急に泣き<b>出した。<\\/b>\",\"何かが急に起きた時や、急に始まったと言う時に使われる。\"]', 'N3', '2026-04-02 16:01:07'),
(642, '～ようとする', '<b></b><br><br><b>[JP]:</b> 今から～しようと思う、～しようと頑張っていると言いたい時に使う。<br><b>[EN]:</b> When you want to say that you are doing your best to do something or want to start doing so.<br><img src=\"child-crossing-street.jpg\" />', '[動-意向形]＋とする', '[\"小さい子供が道を渡ろう<b>として<\\/b>いるよ。一人でどこへ行くのかな。\",\"「～ようとしない」は相手が～しないことを批判する気持ちを表す。\",\"今から～しようと思う、～しようと頑張っていると言いたい時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(643, '～ことがある', '<b></b><br><br><b>[JP]:</b> 時々、またはたまに～すると言う時に使う。<br><b>[EN]:</b> When you say that you sometimes or occasionally do something.<br><img src=\"paste-21646635171841.jpg\" />', '[動-辞書形・ない形-ない]＋ことがある', '[\"この地方では4月でも雪が降る<b>ことがある<\\/b>。\",\"時々、またはたまに～すると言う時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(644, '～させておく', '<b></b><br><br><b>[JP]:</b> 相手に「～」の動作をずっと続けるよう指示することを表す。また、相手の行動を変えさせたりやめさせたりしないで、そのままにしておくことを表すこともある。<br><b>[EN]:</b> Indicates that someone has been instructed to keep performing some action. It can also say that you are not changing or interrupting someone\'s behavior, but instead, just leaving them as they are.<br><img src=\"kid-in-hot-car.jpg\" />', '[動-使役-て形]＋おく', '[\"夏に車の中で子供を<b>待たせておく<\\/b>のは危険ですよ。\",\"自分より下の人や動物に使うことが多い。\",\"相手に「～」の動作をずっと続けるよう指示することを表す。また、相手の行動を変えさせたりやめさせたりしないで、そのままにしておくことを表すこともある。\"]', 'N3', '2026-04-02 16:01:07'),
(645, '～られてしまう', '<b></b><br><br><b>[JP]:</b> 他の人がしたことを迷惑だ、残念だと思う時に使う。<br><b>[EN]:</b> When you think that an action by another person inconveniences you or is unfortunate.<br><img src=\"paste-32207959752705.jpg\" />', '[動-受身-て形]＋しまう', '[\"片思いの彼を映画に誘ったが、<b>断られてしまった<\\/b>。\",\"他の人がしたことを迷惑だ、残念だと思う時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(646, '～ため (に)、 為[ため]に', '<b></b><br><br><b>[JP]:</b> ～が原因、理由でと言うと時に使う。<br><b>[EN]:</b> When you say that 「～」 is the cause or reason.<br><img src=\"Raingear.jpg\" />', '[名詞修飾型]＋ため', '[\"雨の<b>ために<\\/b>ハイキングは中止になりました。\",\"文末に「～たい・～つもりだ」などは使わない。\",\"～が原因、理由でと言うと時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(647, '～につき', '<b></b><br><br><b>[JP]:</b> 「使用料は1時間につき1000円」のように「～」の数の単位（1時間）で「・・・」の数（1000円）と言う時などに使う。<br><b>[EN]:</b> As in the phrase&nbsp;「使用料は1時間につき1000円」, which means there is a charge of 1,000 yen per hour. In this case the rate is expressed as a number 「・・・」（1000円）, which accrues for every unit of 「～」 （1時間）.<br><img src=\"blog20170418.jpg\" />', '[名]＋につき', '[\"当スポーツクラブ会員以外の方でも、1回<b>につき<\\/b>2,000円で施設をご利用いただけます。\",\"「使用料は1時間につき1000円」のように「～」の数の単位（1時間）で「・・・」の数（1000円）と言う時などに使う。\"]', 'N3', '2026-04-02 16:01:07'),
(648, '～を 通[とお]して / ～を 通[とお]じて', '<b></b><br><br><b>[JP]:</b> 直接ではなく、人、手段、物事が間に入って何かをすることを表す。<br><b>[EN]:</b> Says that rather than doing something directly, an action was taken by way of another person, means or thing.<br><img src=\"news-YourStory.jpg\" />', '[名]＋を＋通して・通じて', '[\"現在はインターネット<b>を通して<\\/b>、すぐに世界にニュースが広まる。\",\"直接ではなく、人、手段、物事が間に入って何かをすることを表す。\"]', 'N3', '2026-04-02 16:01:07'),
(649, '~によって / ~によっては / ~により / ~による', '<b>By~ ; Depending on~ (show differences)<div>By~ ; Depending on~ (For a certain condition / occasion)</div></b><br><br><b>[JP]:</b> 人や場所、時間などに対応してそれぞれ違うと言う時に使う。<br><b>[EN]:</b> When you say that something differs depending on the person, place, time, or the like.<br><img src=\"03427BB194ED9559FCF95B6140FE9050141DE4F0C83806CB25pimgpsh_fullsize_distr-750x300.jpg\" />', '[名]＋によって<div>[名]＋による＋[名]</div>', '[\"習慣は国<b>によって<\\/b>違う。\",\"人や場所、時間などに対応してそれぞれ違うと言う時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(650, '～のような / ～のように', '<b></b><br><br><b>[JP]:</b> 代表的な例をあげる時に使う。<br><b>[EN]:</b> When you give a typical example.<br><img src=\"kazoku-inhuruenza.jpg\" />', '[名]＋のように<div>[名]＋のような＋[名]</div><div>[名]＋みたい</div>', '[\"インフルエンザ<b>のような<\\/b>他の人にうつる病気になったら、治るまで学校へ来てはいけないことになっています。\",\"友達の会話では「～みたい」も使う。\",\"代表的な例をあげる時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(651, '~っけ', '<b></b><br><br><b>[JP]:</b> はっきり分からないことや聞いたのに忘れてしまったことを確認する時にも使う。<br><b>[EN]:</b> When you confirm something you do not fully know about or something you heard but forget about.<br><img src=\"main (1).jpg\" />', '[普通形 / 丁寧形]＋っけ', '[\"クリーニング店、何時までだ<b>っけ<\\/b>。\",\"はっきり分からないことや聞いたのに忘れてしまったことを確認する時にも使う。\",\"過去に知ったことは、現在、未来のことでも過去形を使うことがある。\"]', 'N3', '2026-04-02 16:01:07'),
(652, '~たりして', '<b></b><br><br><b>[JP]:</b> 「～もしかしたら」という意味を表す。<br><b>[EN]:</b> Perhaps or maybe<br><img src=\"paste-145337398329345.jpg\" />', '[普通形の過去]＋りして', '[\"もしかして寝ていた<b>りして<\\/b>。\",\"「～もしかしたら」という意味を表す。\"]', 'N3', '2026-04-02 16:01:07'),
(653, '~たって', '<b></b><br><br><b>[JP]:</b> 「～でも」と同じ意味で使う。<br><b>[EN]:</b> It means the same as 「～でも」 (even if~)<br><img src=\"sad-rich-man.jpg\" />', '[動-た形・ない形-ない-○ / い形-○-くた・い形-○-くなくた / な形-だ・な形-じゃなくた / 名-だ・名-じゃなくた]＋って', '[\"お金持ち<b>だって<\\/b>、幸せじゃない人もいます。\",\"「～でも」と同じ意味で使う。\"]', 'N3', '2026-04-02 16:01:07'),
(654, '~に 決[き]まっている', '<b></b><br><br><b>[JP]:</b> 「絶対～だと思う」と強く言う時に使う。<br><b>[EN]:</b> When you want to stress that you are absolutely sure of something&nbsp;<br><img src=\"DSC03711.jpg\" />', '[普通形]-○＋に決まっている', '[\"あのチームは今年も最下位<b>に決まってる<\\/b>よ。\",\"Mostly used in speaking\",\"「絶対～だと思う」と強く言う時に使う。\",\"[な形・名] don\'t use [だ]\"]', 'N3', '2026-04-02 16:01:07'),
(655, '~じゃない', '<b></b><br><br><b>[JP]:</b> 聞き手も知っていると思うことや同じ意見だと思うことを確認する時に使う。避難や発見の意味表すこともある。否定の意味はない。<br><b>[EN]:</b> When you want to confirm that the listener also knows the same thing or has te same opinion as you. Also used to reproach or to talk about a discovery. Does not contain negative meaning.<br><img src=\"201212310853203a1.jpg\" />', '[普通形]＋じゃない', '[\"レストランABK、広くて、交通の便もいい<b>じゃない<\\/b>。\",\"「～じゃん」の形も同じように使われる。\",\"聞き手も知っていると思うことや同じ意見だと思うことを確認する時に使う。避難や発見の意味表すこともある。否定の意味はない。\"]', 'N3', '2026-04-02 16:01:07'),
(656, '~みたい', '<b></b><br><br><b>[JP]:</b> 話し手の推量を表す「～よう」の意味で使う。<br><b>[EN]:</b> To state the speaker\'s speculation, as in 「～よう」.<br><img src=\"6098-1.jpg\" />', '[普通形]-○＋みたい', '[\"なんか、疲れた<b>みたい<\\/b>だけど、仕事忙しいの？\",\"話し手の推量を表す「～よう」の意味で使う。\",\"[な形・名] don\'t use [だ]\"]', 'N3', '2026-04-02 16:01:07'),
(657, '~ばよかった', '<b></b><br><br><b>[JP]:</b> 自分が～しなかったから悪い結果になったことを後悔したり、他の人がしなかったことを残念に思った時に使う。<br><b>[EN]:</b> When you regret a bad result due to you not taking an action, or when another person\'s inaction is unfortunate.<br><img src=\"hqdefault (1).jpg\" />', '[普通形-ば]＋よかった', '[\"カメラを持ってくれ<b>ばよかった<\\/b>ね。\",\"自分が～しなかったから悪い結果になったことを後悔したり、他の人がしなかったことを残念に思った時に使う。\"]', 'N3', '2026-04-02 16:01:07'),
(658, '~ばかり', '<b></b><br><br><b>[JP]:</b> ～が多くて困る、～以外のことをしないから困ると批判的に言う時に使う。<br><b>[EN]:</b> to express criticism of only doing ~ or of doing it too much because it causes a problem<br><img src=\"paste-25396141621249.jpg\" />', '[動-て形 / 名]＋ばかり', '[\"最近雨<b>ばかり<\\/b>で、洗濯物が乾かなくて困っています。\",\"～一方\",\"～が多くて困る、～以外のことをしないから困ると批判的に言う時に使う。\",\"[動-て形]＋ばかりいると[動-て形・て形-いる]＋ばかりの形も使われる。\"]', 'N3', '2026-04-02 16:01:07'),
(660, '1611', '<b>okurigana</b><br><br><b>[JP]:</b> I invited my parents for a meal. / I invited my parents to a meal.<br><b>[EN]:</b> 招く<br>[sound:1169V.mp3]', 'まねく', '[\"invite, beckon, engage\",\"verb\",\"I invited my parents for a meal. \\/ I invited my parents to a meal.\",\"招[まね]きます\",\"両親[りょうしん]を 食事[しょくじ]に<b> 招[まね]いた<\\/b>。\"]', 'N3', '2026-04-02 16:01:07'),
(661, '~つつ / ~つつも', '<b>~Though</b><br><br><b>[JP]:</b> 「〜だけれども、実際はよくないことをしてしまう」という気持ちを表す。<br><b>[EN]:</b> As in \"タバコは体に悪いからやめようよと思いつつも、つい吸ってしまう\", it expresses the feeling that \"altougth ~ (I tought I should quit), something undesired actually happened (I smoked)\".<br><img src=\"does-chocolate-give-pimples.jpg\" />', '[動-ます形]＋つつも', '[\"チョコレートを食べたらにきびが増えると知り<b>つつも<\\/b>、つい手が伸びてしまうんです。\",\"Not used in conversations.\",\"「〜だけれども、実際はよくないことをしてしまう」という気持ちを表す。\"]', 'N2', '2026-04-02 16:01:07'),
(662, '~わけだ', '<b>It means that</b><br><br><b>[JP]:</b> 理由や事情を説明して「当然そうなる」と言いたいときに使う。<br><b>[EN]:</b> Use this when you want to explain a reason or circumstances about something and say that it is a matter of course.<br><img src=\"paste-20263655702529.jpg\" />', '[名詞修飾型]＋わけだ・というわけだ', '[\"食生活の改善と適度な運動によって免疫力が高まり、病気にかかりにくくなる<b>わけです。<\\/b>\",\"理由や事情を説明して「当然そうなる」と言いたいときに使う。\"]', 'N2', '2026-04-02 16:01:07');
INSERT INTO `questions` (`id`, `level`, `category`, `sub_tag`, `content`, `option_a`, `option_b`, `option_c`, `option_d`, `correct_answer`, `explanation`, `created_at`) VALUES
(1, 'N3', 'Từ vựng', 'Cách đọc Kanji', 'プレゼントはきれいな紙で包んであった。', 'つつんで', 'つづんで', 'つうつんで', 'つうづんで', 'A', 'Từ \'包む\' (Bao) có cách đọc là \'つつむ\'. Đáp án đúng là số 1.', '2026-04-02 15:41:30'),
(2, 'N3', 'Từ vựng', 'Cách đọc Kanji', '彼はダンスが得意だ。', 'どおくい', 'とおくい', 'どくい', 'とくい', 'D', '\'得意\' (Đắc Ý) đọc là \'とくい\'. Đáp án đúng là số 4.', '2026-04-02 15:41:30'),
(3, 'N3', 'Từ vựng', 'Cách đọc Kanji', '新しい星が発見された。', 'はっけん', 'はけん', 'はつけん', 'ぱつけん', 'A', '\'発見\' (Phát Kiến) đọc là \'はっけん\'. Đáp án đúng là số 1.', '2026-04-02 15:41:30'),
(4, 'N3', 'Từ vựng', 'Cách đọc Kanji', '通勤にとても時間がかかります。', 'つうがく', 'つうきん', 'つうやく', 'つうしん', 'B', '\'通勤\' (Thông Cần) đọc là \'つうきん\'. Đáp án đúng là số 2.', '2026-04-02 15:41:30'),
(5, 'N3', 'Từ vựng', 'Viết Kanji', '機械がせいじょうかどうかチェックした。', '盛情', '威常', '正情', '正常', 'D', '\'せいじょう\' (Bình thường) viết là \'正常\'. Đáp án đúng là số 4.', '2026-04-02 15:41:30'),
(6, 'N3', 'Từ vựng', 'Điền từ', '新しい車を買うために、店で（　）をもらってきた。', 'カタログ', 'オーダー', 'レシート', 'セール', 'A', 'Để mua xe mới cần lấy \'Catalog\'. Đáp án đúng là số 1.', '2026-04-02 15:41:30'),
(7, 'N3', 'Từ vựng', 'Điền từ', '田中さんの服装はとても上品な（　）がする。', '関心', '気分', '考え', '感じ', 'D', 'Cụm từ \'感じがする\' nghĩa là có cảm giác/cảm thấy. Đáp án đúng là số 4.', '2026-04-02 15:41:30'),
(8, 'N3', 'Từ vựng', 'Từ đồng nghĩa', '今回の仕事はとてもきつい。', '大変だ', '簡単だ', 'つまらない', 'おもしろい', 'A', '\'きつい\' đồng nghĩa với \'大変\' (vất vả). Đáp án đúng là số 1.', '2026-04-02 15:41:30'),
(9, 'N3', 'Từ vựng', 'Cách dùng từ', '火事のとき落ち着いて行動しよう。', '電車が駅に落ち着いたら', '棚にずっと落ち着いている', 'ポケットに落ち着いた', '落ち着いて行動しよう', 'D', '\'落ち着く\' dùng để chỉ sự bình tĩnh. Đáp án đúng là số 4.', '2026-04-02 15:41:30'),
(10, 'N3', 'Ngữ pháp', 'Trích dẫn って', 'B「今日はない（　）言っていましたよ。」', 'を', 'って', 'のを', 'だ', 'B', '\'って\' dùng để trích dẫn câu nói. Đáp án đúng là số 2.', '2026-04-02 15:41:30'),
(11, 'N3', 'Ngữ pháp', 'たびに', 'わたしは山田さんに会う（　）すてきな人だといつも思う。', 'うちに', 'はじめに', 'たびに', 'だけに', 'C', '\'V-ru + たびに\' (mỗi lần... lại). Đáp án đúng là số 3.', '2026-04-02 15:41:30'),
(12, 'N3', 'Ngữ pháp', 'Kính ngữ', '「かばん売り場はどこ?」「5階に（　）」', 'ございます', 'いらっしゃいます', 'いる', 'おります', 'A', '\'ございます\' là thể lịch sự của \'あります\'. Đáp án đúng là số 1.', '2026-04-02 15:41:30'),
(13, 'N3', 'Ngữ pháp', 'Giới hạn だけ', 'C「わたし、おなかすいてないから、コーヒー（　）する。」', 'だけ', 'だけで', 'だけを', 'だけに', 'A', '\'だけ\' nghĩa là chỉ. Đáp án đúng là số 1.', '2026-04-02 15:41:30'),
(14, 'N3', 'Ngữ pháp', 'Trạng thái (~てい)', '昨日、塩の量が間違えて味が（　）いました。', '濃くなりやすくなって', '濃くしやすくなって', '濃くなりすぎて', '濃くしすぎて', 'C', '\'過ぎる\' nghĩa là quá mức. Đáp án đúng là số 3.', '2026-04-02 15:41:30'),
(15, 'N3', 'Ngữ pháp', 'Dự đoán だろう', '父も私も、今日はかさがなくても（　）が...', 'だろう', 'と思って', '大丈夫', '出かけた', 'C', 'Câu hoàn chỉnh: \'かさがなくても大丈夫だろう\'. Đáp án đúng là số 3.', '2026-04-02 15:41:30');
